/**
 * Workplace English Data — PTE Study Planner
 * Target user: Chinese-speaking (Mandarin native) secondary teacher in Australia
 * Focus: professionally reliable English in high-value workplace contexts
 * Australian English spelling throughout
 * ES5 compatible — no arrow functions, no template literals, no const/let
 *
 * Total exercises: ~1050 across 6 modules, 25 sections
 */

var WORKPLACE_ENGLISH = {

// ============================================================
// MODULE 1: CLASSROOM INSTRUCTIONS & MANAGEMENT
// ============================================================
classroomInstructions: {
  title: "Classroom Instructions & Management",
  sections: [
    {
      id: "giving-instructions",
      title: "Giving Clear Instructions",
      theory: "Effective classroom instructions in Australian schools are clear, sequenced, and use imperative verbs. Avoid overly long sentences. Break complex tasks into numbered steps. Use 'please' to maintain a respectful tone without being too soft. Chinese speakers often struggle with imperative mood because Mandarin instructions frequently use softer constructions.",
      exercises: [        {id:"ci001",type:"fill",q:"Please ___ your textbooks to page 42 and read the first paragraph silently.",a:"open",exp:"'Open your textbooks' is the standard classroom instruction. Chinese speakers sometimes say 'turn on' (from 打开 dǎkāi) which is only for electronic devices."},
        {id:"ci002",type:"mc",q:"Which is the most appropriate way to get students' attention?",options:["Be quiet now!","Could everyone please settle down?","Shut up, class!","Stop all your noise!"],a:1,exp:"'Could everyone please settle down?' is firm but respectful. Australian classrooms expect polite, professional language even when managing behaviour."},
        {id:"ci003",type:"fill",q:"___ out your laptops and ___ to the Google Classroom page.",a:"Take ... navigate",exp:"'Take out' means remove from bag. 'Navigate to' is the professional way to say 'go to' for websites. Chinese speakers sometimes say 'open the page' which is acceptable but less precise."},
        {id:"ci004",type:"error",q:"Everyone listen me carefully and follow the step.",a:"Everyone listen to me carefully and follow the steps.",exp:"'Listen' requires 'to' before the object (listen to me). 'Steps' needs plural — Chinese doesn't mark plurals, so this is a common error."},
        {id:"ci005",type:"fill",q:"I'd like you to ___ into groups of four and ___ one person as the note-taker.",a:"get ... choose",exp:"'Get into groups' is the natural classroom phrase. 'Choose' is better than 'select' for Year 7-8 students as it is simpler."},
        {id:"ci006",type:"mc",q:"What does 'pack up' mean in a classroom context?",options:["Start a new activity","Put your things away and get ready to leave","Open your bags","Stand up and stretch"],a:1,exp:"'Pack up' is an extremely common Australian classroom instruction meaning 'put your things away'. It signals the end of an activity or the lesson."},
        {id:"ci007",type:"fill",q:"Before you start, make ___ you have a ruler, a pencil, and ___ A3 sheet of paper.",a:"sure ... an",exp:"'Make sure' = ensure/check. Use 'an' before 'A3' because we say 'an ay-three' — the sound starts with a vowel. Chinese speakers often forget articles entirely."},
        {id:"ci008",type:"error",q:"Put your hand up if you have question.",a:"Put your hand up if you have a question.",exp:"Missing article 'a' before 'question'. In Chinese, 你有问题吗 doesn't require an article, but English singular countable nouns always need one."},
        {id:"ci009",type:"fill",q:"When I say 'go', I want you to ___ to your workstations and ___ the experiment.",a:"move ... begin",exp:"Using two clear imperative verbs gives students a sequence. 'Begin' is slightly more formal than 'start' — both are fine in classrooms."},
        {id:"ci010",type:"mc",q:"Which instruction is clearest for a practical lesson?",options:["Do the thing with the materials","You should maybe try to use the equipment","Step 1: Measure 50ml of water. Step 2: Pour it into the beaker.","Try doing it properly this time"],a:2,exp:"Numbered steps with specific amounts are the clearest instructions. Vague language ('the thing') and sarcasm ('this time') are ineffective."},
        {id:"ci011",type:"fill",q:"Please ___ your screens and give me your full ___.",a:"close ... attention",exp:"'Close your screens' (laptop lids) and 'give me your attention' are standard instructions. Chinese speakers may say 'shut' which sounds too harsh."},
        {id:"ci012",type:"error",q:"I need everyone finish this before the bell ring.",a:"I need everyone to finish this before the bell rings.",exp:"'Need someone to do something' requires 'to'. 'The bell rings' — third person singular present tense needs 's'. Chinese verbs don't conjugate."},
        {id:"ci013",type:"fill",q:"You have ___ minutes to complete the task. I'll give you a two-minute ___ before time is up.",a:"fifteen ... warning",exp:"Giving a specific time frame and a warning helps students manage their time. 'Two-minute warning' is standard classroom language."},
        {id:"ci014",type:"mc",q:"A student asks 'What do we do?' after you gave instructions. What is the best response?",options:["I already told you. Weren't you listening?","Let me go through the steps one more time.","You should have been paying attention.","Ask your neighbour."],a:1,exp:"Repeating instructions without shaming is best practice. Option 0 and 2 are dismissive. Option 3 is sometimes okay but not the best first response."},
        {id:"ci015",type:"fill",q:"___ the heading '___ Design Challenge' at the top of your page.",a:"Write ... The",exp:"Clear, specific instruction. 'The Design Challenge' uses the definite article because it refers to a specific, known task."},
        {id:"ci016",type:"error",q:"You can to start working now if you already understand.",a:"You can start working now if you already understand.",exp:"Modal verbs (can, should, must, will) are NEVER followed by 'to'. This is a very common Chinese speaker error because 可以 (kěyǐ) often translates as 'can to'."},
        {id:"ci017",type:"open",q:"Write a three-step instruction for students to submit their work digitally at the end of class.",a:"Step 1: Save your document with your name and class — for example, 'Ahmed_7B_Design.docx'. Step 2: Upload your file to the Google Classroom assignment before the bell. Step 3: Check that you can see your submission in the 'Turned in' section.",exp:"Good instructions are numbered, specific, and include an example. They tell students what success looks like (checking the submission)."},
        {id:"ci018",type:"fill",q:"Eyes on me, please. I need your ___ attention for the next two minutes.",a:"undivided",exp:"'Undivided attention' is a common classroom collocation meaning 'complete, full attention'. It signals to students that something important is coming."},
        {id:"ci019",type:"mc",q:"Which phrase is best for transitioning between activities?",options:["OK stop everything right now","Alright, let's wrap up this activity and move on to the next one.","New thing now","Hurry up and finish"],a:1,exp:"'Wrap up' (finish) and 'move on to' (transition) are natural, professional phrases for managing activity changes."},
        {id:"ci020",type:"error",q:"Please to remember bring your USB tomorrow.",a:"Please remember to bring your USB tomorrow.",exp:"'Please remember to...' — 'please' doesn't take 'to' after it, and 'remember to bring' is the correct verb pattern. Word order differs from Chinese 请记得明天带."},
        {id:"ci021",type:"fill",q:"___ your hand up if you need help. Don't ___ out — wait for me to come to you.",a:"Put ... call",exp:"'Put your hand up' and 'don't call out' are essential behaviour instructions. 'Call out' means shouting answers without being asked."},
        {id:"ci022",type:"mc",q:"What does 'have a go' mean in Australian English?",options:["Leave the classroom","Try/attempt something","Have a turn at a game","Start an argument"],a:1,exp:"'Have a go' is very Australian and means 'try it' or 'give it a try'. Teachers often say 'Just have a go — it doesn't have to be perfect.' It encourages risk-taking."},
        {id:"ci023",type:"fill",q:"I'm going to ___ the task on the board. Please don't ___ until I've finished explaining.",a:"demonstrate ... start",exp:"'Demonstrate' is more professional than 'show'. Clear boundary-setting: 'don't start until I've finished'."},
        {id:"ci024",type:"error",q:"Can someone to help me give out the worksheet?",a:"Can someone help me give out the worksheets?",exp:"No 'to' after 'can' (modal verb rule). 'Worksheets' needs plural because there are multiple copies. 'Give out' = distribute."},
        {id:"ci025",type:"fill",q:"Please ___ sure your name is on your work ___ you hand it in.",a:"make ... before",exp:"'Make sure' + condition 'before you hand it in'. 'Hand in' = submit physical work. Chinese speakers sometimes confuse 'hand in' and 'hand out' (distribute)."},
        {id:"ci026",type:"mc",q:"How would you instruct students to work quietly?",options:["Silence! No talking!","I'd like you to work independently and keep the noise to a minimum, please.","Be quiet or else.","No speaking allowed."],a:1,exp:"'Work independently' and 'keep the noise to a minimum' are professional, respectful, and clear. The other options are either threatening or too blunt."},
        {id:"ci027",type:"fill",q:"___ to me for a moment. I need to ___ something before we continue.",a:"Listen ... clarify",exp:"'Listen to me' and 'clarify' (make something clearer) are professional instruction language. 'Clarify' is a useful formal alternative to 'explain again'."},
        {id:"ci028",type:"error",q:"Everyone should to finish their work and then can leave.",a:"Everyone should finish their work and then can leave.",exp:"No 'to' after 'should' — same modal verb rule. Two modals in one sentence (should, can) are fine as they apply to different actions."},
        {id:"ci029",type:"open",q:"Write instructions for a Think-Pair-Share activity about sustainability.",a:"First, think about this question on your own for two minutes: 'What is one thing our school could do to be more sustainable?' Then, turn to your partner and share your ideas. You have three minutes to discuss. Finally, be ready to share your best idea with the whole class.",exp:"Think-Pair-Share has three clear stages. Good instructions specify time limits and what students need to be ready for at the end."},
        {id:"ci030",type:"fill",q:"Right, Year 8. I need you to ___ down and ___ your attention to the front.",a:"settle ... direct",exp:"'Settle down' means calm down and be ready. 'Direct your attention to the front' is formal but clear. These are standard lesson-start instructions."},
        {id:"ci031",type:"mc",q:"What is the best way to give instructions to EAL/D students?",options:["Speak faster so they get used to natural speed","Use short sentences, gestures, and visual supports","Only write instructions — never speak them","Translate everything into their first language"],a:1,exp:"Short sentences, gestures, and visual supports help EAL/D students access instructions. This also benefits all learners. Speaking faster is counterproductive."},
        {id:"ci032",type:"fill",q:"When you've ___ the reading, ___ the questions on the back of the handout.",a:"finished ... answer",exp:"Sequenced instructions: finish one task, then do the next. 'When you've finished' uses present perfect to mark task completion."},
        {id:"ci033",type:"error",q:"You need complete all the question by the end of the period.",a:"You need to complete all the questions by the end of the period.",exp:"'Need to complete' (need + to + infinitive). 'Questions' needs plural. 'Period' is the Australian/American term for a lesson block."},
        {id:"ci034",type:"fill",q:"I'm going to ___ you a worksheet. Please don't write on it ___ I tell you to start.",a:"hand ... until",exp:"'Hand you a worksheet' = give/distribute. 'Until I tell you' sets a clear boundary. Chinese speakers sometimes use 'when' instead of 'until' here."},
        {id:"ci035",type:"mc",q:"A student says 'I don't get it.' What is the most helpful teacher response?",options:["That's because you weren't listening.","Which part is confusing? Let me help you break it down.","Just try harder.","Ask someone else."],a:1,exp:"Identifying the specific confusion point is the most effective response. It shows willingness to help and teaches the student to articulate their difficulty."},
        {id:"ci036",type:"open",q:"Write a set of instructions for students beginning a research task on Australian Indigenous history.",a:"Today we are starting our research on Australian Indigenous history. Step 1: Open your laptop and go to the school library database. Step 2: Search for your chosen topic using at least two different keywords. Step 3: Find three reliable sources and record the title, author, and URL in your research log. Remember — Wikipedia is a starting point, not a source you can cite. If you need help evaluating sources, put your hand up.",exp:"Good research instructions include where to search, how many sources, what to record, and a note about source reliability."},
        {id:"ci037",type:"fill",q:"For homework tonight, I'd like you to ___ the chapter we discussed and ___ three key points.",a:"review ... note",exp:"'Review' is more academic than 'look at again'. 'Note' as a verb means 'write down'. Clear, achievable homework instructions."},
        {id:"ci038",type:"error",q:"Don't forget bring your permission slip for the excursion.",a:"Don't forget to bring your permission slip for the excursion.",exp:"'Forget to bring' — the infinitive 'to' is required after 'forget'. In Mandarin, 别忘了带 doesn't have an equivalent of 'to'. Note: 'excursion' is the Australian term for school trips."},
        {id:"ci039",type:"mc",q:"What does 'line up' mean in an Australian school?",options:["Draw a straight line on paper","Form a queue/row outside the classroom","Connect to the internet","Organise your desk"],a:1,exp:"'Line up' means form an orderly queue. Students typically line up before entering classrooms or moving to other areas. This is standard Australian school language."},
        {id:"ci040",type:"fill",q:"Before we ___, does anyone have any ___ about what we just covered?",a:"move on ... questions",exp:"'Move on' = proceed to the next topic. Checking for questions before transitioning is good teaching practice."},
        {id:"ci041",type:"error",q:"Let's we start the lesson now. Everyone should sit down.",a:"Let's start the lesson now. Everyone should sit down.",exp:"'Let's' already includes the subject (let us). Adding 'we' is redundant and incorrect. This is a common Chinese speaker error from 让我们 (ràng wǒmen)."},
        {id:"ci042",type:"fill",q:"I need a ___ from each group to come up and ___ your poster.",a:"volunteer ... present",exp:"'A volunteer' — someone who offers willingly. 'Present your poster' is more formal than 'show'. Group work language is important in Australian schools."}
      ]
    },
    {
      id: "behaviour-management",
      title: "Behaviour Management Language",
      theory: "Australian schools use positive behaviour management. This means redirecting rather than punishing, using 'I' statements, offering choices, and maintaining a calm, firm tone. Avoid sarcasm and public shaming. The language should be professional — even when frustrated.",
      exercises: [
        {id:"bm001",type:"fill",q:"I've noticed you're having a hard time staying on task. Would you like to ___ somewhere quieter, or would you prefer to stay here and ___?",a:"move ... refocus",exp:"Offering a choice gives students agency and avoids confrontation. 'Refocus' means get back on task. This is a key positive behaviour strategy."},
        {id:"bm002",type:"mc",q:"A student is talking while you're explaining. What is the best first response?",options:["Stop talking immediately!","I'll wait... [pause and make eye contact]","If you don't stop, I'll send you out.","Can you just be quiet?"],a:1,exp:"A pause with eye contact is the least intrusive intervention. It gives the student a chance to self-correct without public confrontation."},
        {id:"bm003",type:"error",q:"You are always late to my class. You need change your behaviour.",a:"You've been arriving late to class recently. You need to change this behaviour.",exp:"'Always' is an absolute — use 'recently' for fairer feedback. 'Need to change' requires 'to'. 'This behaviour' is more specific and less personal than 'your behaviour'."},
        {id:"bm004",type:"fill",q:"I can see that you're frustrated. Let's take a ___ and come back to this when you're ___.",a:"break ... calmer",exp:"Acknowledging the emotion ('I can see') validates the student. Offering a break is de-escalation. 'Calmer' is comparative — they don't need to be fully calm, just calmer."},
        {id:"bm005",type:"mc",q:"Which phrase uses an effective 'I' statement for behaviour management?",options:["You're being really annoying right now.","I feel disrespected when people talk over me.","Everyone thinks you're being rude.","Stop it or I'll call your parents."],a:1,exp:"'I feel disrespected when...' names the teacher's feeling and the specific behaviour without attacking the student's character. This is the 'I' statement model."},
        {id:"bm006",type:"fill",q:"That language is ___ in this classroom. I expect you to speak ___.",a:"inappropriate ... respectfully",exp:"'Inappropriate' is the professional term — never say 'bad' language. 'Respectfully' sets a clear expectation without over-reacting."},
        {id:"bm007",type:"error",q:"If you will not stop, I will give you detention.",a:"If you do not stop, I will give you a detention.",exp:"Conditional: 'If you do not stop' (present simple in the if-clause, not 'will'). 'A detention' needs the article. Chinese speakers often drop articles and use 'will' in both clauses."},
        {id:"bm008",type:"fill",q:"I'm going to give you a ___ to make the right choice. I'd like to see you back on task in ___ minutes.",a:"chance ... two",exp:"'Give you a chance' is positive framing. Setting a specific time ('two minutes') is clear and measurable."},
        {id:"bm009",type:"mc",q:"What does 'on task' mean in a school context?",options:["Standing on the desk","Doing the assigned work","Writing a task list","Checking homework"],a:1,exp:"'On task' means doing what they are supposed to be doing. 'Off task' means doing something else. These are very common Australian school phrases."},
        {id:"bm010",type:"fill",q:"I need you to ___ your phone away. If I see it again, I'll need to ___ it until the end of the day.",a:"put ... confiscate",exp:"'Put away' = store out of sight. 'Confiscate' = take temporarily as a consequence. NSW schools have clear phone policies."},
        {id:"bm011",type:"error",q:"You must to sit down right now. I'm very angry with you.",a:"You must sit down right now. I'm very disappointed in this behaviour.",exp:"No 'to' after 'must' (modal verb rule). Teachers should express 'disappointment' not 'anger' — it focuses on the behaviour, not the teacher's emotion."},
        {id:"bm012",type:"open",q:"A student refuses to work and says 'This is boring.' Write a professional response.",a:"I understand this might not be your favourite activity, but it's an important skill. Let me help you find a way to make it more interesting. Would you like to work with a partner, or would you prefer to try the extension challenge instead?",exp:"Validate the feeling, redirect to the learning purpose, and offer a choice. Never argue about whether something is boring."},
        {id:"bm013",type:"fill",q:"I've spoken to you about this ___ today. This is your final ___.",a:"twice ... warning",exp:"Documenting the number of reminders is important. 'Final warning' signals that the next step will be a consequence. This follows the warning system used in many NSW schools."},
        {id:"bm014",type:"mc",q:"Which consequence language is most professional?",options:["Because you chose to continue talking, you'll need to stay back at lunch for five minutes.","You're staying in at lunch because you can't behave.","Lunch detention. No arguments.","I told you three times. Now you're in trouble."],a:0,exp:"'Because you chose to...' links the consequence directly to the student's choice. This is the 'choice-consequence' model used in Australian schools."},
        {id:"bm015",type:"fill",q:"I appreciate that you're ___ to follow instructions today. Thank you for making a good ___.",a:"trying ... effort",exp:"Positive reinforcement: acknowledging effort, not just success. 'Making a good effort' is more encouraging than 'doing well' for struggling students."},
        {id:"bm016",type:"error",q:"Don't make me to repeat myself again. You should already know the rule.",a:"Don't make me repeat myself. You already know the rule.",exp:"'Make me repeat' — no 'to' after 'make + object' in active voice. Remove 'again' (redundant with 'repeat'). 'Should already know' sounds judgemental — 'already know' is neutral."},
        {id:"bm017",type:"fill",q:"I can see some people are not ___ the expectations we set at the ___ of the year.",a:"meeting ... beginning",exp:"'Meeting expectations' is the professional phrase. Referring to agreed expectations ('we set') gives shared ownership."},
        {id:"bm018",type:"mc",q:"A student slams their book on the desk in frustration. What is the best first response?",options:["Pick that up right now!","I can see you're feeling frustrated. Let's talk about it.","That's it — you're out!","Don't you dare do that in my classroom."],a:1,exp:"Acknowledging the emotion first de-escalates the situation. Then redirect. Reacting with anger or immediate consequences escalates conflict."},
        {id:"bm019",type:"fill",q:"Please ___ to me after class. I'd like to have a quick ___ about what happened today.",a:"come ... chat",exp:"'Come to me' is less formal than 'report to me'. 'A quick chat' is warm and non-threatening. It signals a conversation, not a lecture."},
        {id:"bm020",type:"error",q:"I don't want see anyone use their phone during class time.",a:"I don't want to see anyone using their phone during class time.",exp:"'Want to see' requires 'to'. 'Using' (present participle after perception verb 'see') is more natural than 'use'. Chinese speakers often omit 'to' after 'want'."},
        {id:"bm021",type:"open",q:"Write what you would say to a student who has been consistently disruptive over three lessons.",a:"I've noticed a pattern over the last few lessons where you've been finding it hard to stay on task and follow our class expectations. I want to help you get back on track. Can we talk about what's going on? Is there something happening that I should know about? Let's work out a plan together.",exp:"A private conversation that shows concern rather than punishment. Asking 'what's going on' addresses root causes. Collaborative problem-solving is most effective."},
        {id:"bm022",type:"fill",q:"Hands and feet to ___. We keep our ___ space safe for everyone.",a:"yourself ... learning",exp:"'Hands and feet to yourself' is a common primary/junior school rule. 'Learning space' frames the classroom as shared and purposeful."},
        {id:"bm023",type:"mc",q:"What does 'move to the buddy room' typically mean in an Australian school?",options:["Go to a friend's classroom to chat","Go to a designated classroom as a consequence for repeated disruption","Move to the library","Switch seats with a buddy"],a:1,exp:"The 'buddy room' or 'buddy class' is another classroom where a disruptive student is sent temporarily. It removes them from the situation while keeping them supervised."},
        {id:"bm024",type:"fill",q:"I expect everyone to show ___ when others are speaking. That means eyes on the ___ and no side conversations.",a:"respect ... speaker",exp:"Explicitly defining what 'respect' looks like (eyes on speaker, no side conversations) makes the expectation concrete and measurable."},
        {id:"bm025",type:"error",q:"You are not allow to leave the classroom without my permit.",a:"You are not allowed to leave the classroom without my permission.",exp:"'Not allowed' (past participle as adjective). 'Permission' not 'permit' — a permit is a physical document. Chinese speakers sometimes confuse 许可 (xǔkě) which covers both meanings."},
        {id:"bm026",type:"fill",q:"I'm going to have to ___ a phone call home if this behaviour ___.",a:"make ... continues",exp:"'Make a phone call home' is the standard phrase for contacting parents. 'If this continues' — present simple in conditional clause."},
        {id:"bm027",type:"mc",q:"Which is the most effective way to praise positive behaviour?",options:["Good boy!","I notice you've been working really quietly — well done.","You're the only one behaving today.","At least someone knows how to listen."],a:1,exp:"Specific praise ('working really quietly') is most effective. 'Good boy' is patronising for secondary students. Comparing students creates resentment."},
        {id:"bm028",type:"fill",q:"I understand you're upset, but ___ language is not ___ in this school.",a:"offensive ... tolerated",exp:"'Offensive language' (swearing/verbal abuse). 'Not tolerated' is the formal phrasing used in school behaviour policies."},
        {id:"bm029",type:"error",q:"If you don't stop to disturb other students, I will need contact your parents.",a:"If you don't stop disturbing other students, I will need to contact your parents.",exp:"'Stop disturbing' (stop + gerund = cease an action). 'Stop to disturb' would mean 'pause in order to disturb'. 'Need to contact' requires 'to'."},
        {id:"bm030",type:"open",q:"A Year 9 student rolls their eyes when you give them an instruction. Write your response.",a:"I noticed that reaction. I understand you might not feel like doing this right now, but the expectation is that you complete the task. I'll check in with you in five minutes to see how you're going. If something is bothering you, we can talk about it after class.",exp:"Address the behaviour without escalating. Acknowledge the emotion, restate the expectation, and offer to follow up privately."},
        {id:"bm031",type:"fill",q:"Let's ___ it down, everyone. I can hear too many ___ at once.",a:"keep ... voices",exp:"'Keep it down' = reduce noise level. 'Too many voices at once' is descriptive and specific rather than just 'be quiet'."},
        {id:"bm032",type:"mc",q:"What is 'restorative practice' in Australian schools?",options:["Giving detention","Having the student repair the relationship through discussion and accountability","Sending students to the principal","Making students write lines"],a:1,exp:"Restorative practice focuses on repairing harm and rebuilding relationships rather than just punishment. It is widely used in NSW schools."},
        {id:"bm033",type:"fill",q:"You've earned a merit ___ today for your excellent contribution to the class ___.",a:"award ... discussion",exp:"'Merit award' is the positive recognition system in many NSW schools. Praising 'contribution to the discussion' reinforces participation."},
        {id:"bm034",type:"error",q:"Please don't running in the corridor. Walk safe to your next class.",a:"Please don't run in the corridor. Walk safely to your next class.",exp:"'Don't run' — base form after 'don't', not gerund. 'Safely' needs the adverb form to modify the verb 'walk'. Chinese doesn't distinguish adjective/adverb forms."},
        {id:"bm035",type:"fill",q:"I've placed a ___ on your desk. It shows the three expectations for today's ___.",a:"reminder ... lesson",exp:"Visual reminders (cards, charts) support behaviour management. Non-verbal strategies are less disruptive than verbal corrections."},
        {id:"bm036",type:"mc",q:"A student says 'You can't make me do this.' What is the best response?",options:["Yes I can — I'm the teacher.","You're right, I can't force you. But there will be consequences for choosing not to participate.","Fine, don't do it then.","I'll call the deputy right now."],a:1,exp:"Acknowledging the truth ('I can't force you') while naming consequences ('choosing not to participate') avoids a power struggle and keeps the focus on the student's agency."},
        {id:"bm037",type:"fill",q:"I'd like you to ___ about the impact your words had on ___. We'll discuss it during ___.",a:"think ... others ... recess",exp:"Restorative practice: reflect on impact, then discuss. 'Recess' and 'lunch' are the Australian terms for break times."},
        {id:"bm038",type:"error",q:"He has very bad attitude today. I think he is just try to get attention.",a:"He has a very bad attitude today. I think he is just trying to get attention.",exp:"Missing article 'a' before 'very bad attitude'. 'Is trying' needs the -ing form for present continuous. Chinese speakers often forget both articles and continuous tense markers."},
        {id:"bm039",type:"fill",q:"You and I both know you can do ___ than this. I've seen your ___ work — it was excellent.",a:"better ... previous",exp:"Referencing past success is a powerful motivator. 'Better than this' challenges without being negative. 'Previous work' provides evidence."},
        {id:"bm040",type:"open",q:"Write a brief note to send home about a student's positive behaviour change this week.",a:"Dear Mr and Mrs Chen, I wanted to let you know that Jiawei has shown a wonderful improvement in his behaviour this week. He has been focused, respectful, and actively contributing to class discussions. I am very pleased with his progress and wanted to make sure you knew about it. Kind regards, Ms Gao",exp:"Positive communication home builds relationships. Be specific about what improved. Australian schools value the home-school connection."},
        {id:"bm041",type:"fill",q:"I'm going to ___ the seating arrangement today because the current one isn't ___ for everyone.",a:"change ... working",exp:"'Change the seating arrangement' is a proactive strategy. 'Not working for everyone' is diplomatic and avoids blame."},
        {id:"bm042",type:"mc",q:"What should a teacher do FIRST when two students are in conflict?",options:["Separate them immediately and give both detention","Yell at them to stop","Calmly separate them and speak to each one individually","Tell the class to watch and learn"],a:2,exp:"Calm separation followed by individual conversations. This prevents escalation and allows each student to share their perspective safely."}
      ]
    },
    {
      id: "explaining-tasks",
      title: "Explaining Tasks & Activities",
      theory: "Explaining tasks clearly involves three elements: what students need to do, how they should do it, and what success looks like. Use simple sentence structures, visual examples, and check for understanding before releasing students to work.",
      exercises: [
        {id:"et001",type:"fill",q:"For today's activity, you will be ___ a poster that ___ three sustainable design principles.",a:"creating ... illustrates",exp:"'Creating' (present continuous for planned activity). 'Illustrates' (shows/demonstrates) is a good academic verb."},
        {id:"et002",type:"mc",q:"Which explanation best sets up a collaborative task?",options:["Work in groups.","In your groups of three, you need to research one renewable energy source, create a summary poster, and prepare a two-minute presentation.","Do the group work thing we talked about.","Help each other with the work."],a:1,exp:"The best explanation specifies group size, the task, the output, and the time/format. Vague instructions lead to confusion and off-task behaviour."},
        {id:"et003",type:"error",q:"The task is write a paragraph about your weekend. You have ten minute.",a:"The task is to write a paragraph about your weekend. You have ten minutes.",exp:"'The task is to write' requires 'to' (infinitive of purpose). 'Ten minutes' needs plural. Both are common Chinese speaker errors."},
        {id:"et004",type:"fill",q:"I'd like you to ___ the information in the table into a ___ graph.",a:"convert ... bar",exp:"'Convert' (change format) is a key instruction verb. 'Bar graph' — specific data representation term. Clear, specific output expectations."},
        {id:"et005",type:"mc",q:"What does 'draft' mean when explaining a writing task?",options:["The final perfect version","A first attempt that will be revised later","A quick copy of someone else's work","Drawing a picture"],a:1,exp:"'Draft' means a preliminary version that will be improved. Understanding process writing terms (draft, revise, edit, publish) is essential for teaching in Australia."},
        {id:"et006",type:"fill",q:"Your task is to ___ and ___ the data from the experiment. Present your findings in a table.",a:"collect ... analyse",exp:"'Collect and analyse' — two-step process instruction. Note Australian spelling: 'analyse' not 'analyze'. 'Findings' is more academic than 'results' in some contexts."},
        {id:"et007",type:"error",q:"I will explain the homework for tonight. You should do pages 12 to 15 and answer all question.",a:"I will explain tonight's homework. You should do pages 12 to 15 and answer all questions.",exp:"'Tonight's homework' is more natural than 'the homework for tonight'. 'All questions' needs plural. Direct and specific instructions are best."},
        {id:"et008",type:"fill",q:"This is a ___ activity, so you can work at your ___ pace. There's no rush.",a:"self-paced ... own",exp:"'Self-paced activity' means students can work at their own speed. 'At your own pace' is a common reassuring phrase in differentiated learning."},
        {id:"et009",type:"open",q:"Explain a jigsaw reading activity to a Year 8 class.",a:"OK everyone, we are going to do a jigsaw reading activity. Each person in your group will receive a different section of the article. Your job is to read your section carefully and summarise the key points. Then, take turns sharing what you learned with your group. By the end, everyone should understand the whole article even though you only read one part. You have fifteen minutes.",exp:"Jigsaw explanations should clarify the structure: individual task first, then sharing. Specify the purpose (everyone understands the whole text) and time limit."},
        {id:"et010",type:"fill",q:"Before you begin, let me show you an ___ of what a finished product should look ___.",a:"example ... like",exp:"Showing an exemplar (model) is best practice. 'What it should look like' sets visual expectations. Chinese speakers sometimes say 'look as' instead of 'look like'."},
        {id:"et011",type:"mc",q:"Which is the best way to check understanding after giving instructions?",options:["Everyone got it? Good, start.","Can someone explain back to me what you need to do?","You all understand, right?","I hope that was clear enough."],a:1,exp:"Having a student explain back tests actual comprehension. Yes/no questions ('got it?') rarely reveal genuine understanding."},
        {id:"et012",type:"fill",q:"The success ___ for this task are on the board. Make sure your work ___ all three criteria.",a:"criteria ... meets",exp:"'Success criteria' (plural of criterion) are the standards for quality. 'Meets all criteria' = fulfils all requirements."},
        {id:"et013",type:"error",q:"This activity is for practise your presentation skill.",a:"This activity is for practising your presentation skills.",exp:"'For practising' (gerund after preposition 'for'). Note: 'practise' is the verb, 'practice' is the noun in Australian English. 'Skills' needs plural."},
        {id:"et014",type:"fill",q:"You'll need to ___ your results with the rest of the class. Each group has ___ minutes to present.",a:"share ... three",exp:"'Share your results' — collaborative learning. Specifying presentation time per group manages expectations and ensures fairness."},
        {id:"et015",type:"mc",q:"What does 'scaffolding' mean in an educational context?",options:["Building a metal structure outside a building","Providing temporary support to help students learn","Copying answers from the teacher","Working without any help"],a:1,exp:"Scaffolding means providing structured support (templates, sentence starters, examples) that is gradually removed as students gain confidence. It is a key educational term in Australia."},
        {id:"et016",type:"fill",q:"If you finish early, there's an ___ task on the back of the worksheet that goes into more ___.",a:"extension ... depth",exp:"'Extension task' provides challenge for fast finishers. 'Goes into more depth' means more detailed/complex. Differentiation is required in Australian schools."},
        {id:"et017",type:"error",q:"Please working in pair and discuss the question together.",a:"Please work in pairs and discuss the questions together.",exp:"'Please work' (base form after 'please'). 'In pairs' (plural). 'Questions' (plural for multiple items). Three common Chinese speaker errors in one sentence."},
        {id:"et018",type:"fill",q:"The worksheet has three ___: a support version, a ___ version, and an extension version.",a:"levels ... core",exp:"Three-tier differentiation is standard in NSW: support, core, extension. Knowing this terminology is essential for Australian teachers."},
        {id:"et019",type:"open",q:"Explain the expectations for a science practical on electrical circuits.",a:"Today we are building simple electrical circuits. Before you touch any equipment, listen to the safety briefing. You must wear safety goggles at all times. Work in pairs. Follow the instruction sheet step by step — do not skip ahead. If a component is not working, raise your hand and I will check it. By the end of the lesson, you should have a working circuit and a completed diagram in your books. All equipment must be returned to the tray before you leave.",exp:"Practical instructions must include safety, process, expected output, and clean-up expectations. Clear sequencing prevents safety issues."},
        {id:"et020",type:"fill",q:"I've ___ a template on Google Classroom to help you get ___.",a:"uploaded ... started",exp:"'Uploaded a template' — digital resource sharing. 'Get started' = begin (common colloquial phrase). Templates scaffold the task."},
        {id:"et021",type:"mc",q:"What is a 'rubric' in an Australian school context?",options:["A type of red pen","A scoring guide that describes what different levels of quality look like","A rubber eraser","A rule book for the classroom"],a:1,exp:"A rubric is a marking guide with criteria and descriptors for each achievement level. In NSW, these often use A-E bands aligned to NESA standards."},
        {id:"et022",type:"fill",q:"Make sure to ___ your sources using the ___ referencing style we discussed last week.",a:"cite ... Harvard",exp:"'Cite your sources' = reference where information came from. Harvard referencing is commonly taught in Australian schools alongside APA."},
        {id:"et023",type:"error",q:"You must to finished this by the Friday. Late work will not be accept.",a:"You must finish this by Friday. Late work will not be accepted.",exp:"No 'to' after 'must'. 'Finish' (base form). 'By Friday' (no 'the' before days). 'Accepted' (past participle in passive voice). Multiple common errors."},
        {id:"et024",type:"fill",q:"This is a formative task, which means it's for ___ — it won't count towards your final ___.",a:"learning ... grade",exp:"'Formative' = for learning (not graded). 'Summative' = for assessment. Understanding this distinction and explaining it to students is important."},
        {id:"et025",type:"mc",q:"How should you explain a complex multi-step task?",options:["Give all instructions at once and hope for the best","Write steps on the board, explain each one, then check for understanding","Just let them figure it out — that's inquiry learning","Tell them to read the worksheet"],a:1,exp:"Writing steps on the board provides a visual reference. Explaining each step prevents cognitive overload. Checking understanding ensures readiness."},
        {id:"et026",type:"fill",q:"For the ___ task, you'll be designing a solution to a real-world problem. You can choose ___ topic that interests you.",a:"assessment ... any",exp:"'Assessment task' is the NSW term for a formal piece of graded work. 'Any topic' gives student choice, which increases engagement."},
        {id:"et027",type:"error",q:"Today we will learning about the water cycle. Please open your book on page 34.",a:"Today we will be learning about the water cycle. Please open your books to page 34.",exp:"'Will be learning' (future continuous for planned lessons). 'Open your books' (plural — each student has one). 'To page 34' (direction preposition)."},
        {id:"et028",type:"fill",q:"The ___ will be due next Friday. Please submit it through ___ Classroom by 11:59 p.m.",a:"assignment ... Google",exp:"'Due next Friday' = deadline. Specifying the exact submission method and time prevents confusion. Google Classroom is widely used in NSW schools."},
        {id:"et029",type:"open",q:"Write instructions for a debate activity in a Year 10 class.",a:"We are holding a class debate on the topic: 'Social media does more harm than good.' You will work in teams of four. One team will argue for the topic, the other against. You have twenty minutes to prepare your arguments using the research from last lesson. Each speaker has two minutes. Remember to use evidence, not just opinions. The audience will vote on the most persuasive team at the end.",exp:"Debate instructions need: topic, team structure, preparation time, speaking time, expectations for evidence, and how the debate will be judged."},
        {id:"et030",type:"fill",q:"I'll ___ a demonstration first, and then you can have a ___ on your own.",a:"do ... go",exp:"'Do a demonstration' = model the task. 'Have a go' is a very Australian phrase meaning 'try it yourself'. Modelling before practice is effective pedagogy."},
        {id:"et031",type:"mc",q:"What is the purpose of 'learning intentions' displayed at the start of a lesson?",options:["To fill up the board","To tell students what they are expected to learn in this lesson","To remind the teacher what to teach","To impress the principal"],a:1,exp:"Learning intentions (or objectives) make the lesson's purpose transparent. Students should be able to explain what they are learning and why. This is standard practice in NSW."},
        {id:"et032",type:"error",q:"The first step is brainstorm some ideas. After that, you can start to write first draft.",a:"The first step is to brainstorm some ideas. After that, you can start to write your first draft.",exp:"'Is to brainstorm' (infinitive after 'the step is'). 'Your first draft' needs possessive 'your' and article context. Chinese doesn't use possessive adjectives as frequently."},
        {id:"et033",type:"fill",q:"I want you to ___ the text carefully and ___ the key vocabulary words.",a:"read ... highlight",exp:"'Read carefully' (instruction to focus). 'Highlight' (mark with colour) is a key reading strategy verb used across all subjects."},
        {id:"et034",type:"mc",q:"What does 'peer assessment' mean?",options:["The teacher marks the work","Students mark each other's work using criteria","Parents review the work","The principal observes the lesson"],a:1,exp:"Peer assessment is when students evaluate each other's work against set criteria. It builds critical thinking and helps students understand success criteria."},
        {id:"et035",type:"fill",q:"Remember, this is a ___ task — you must complete it entirely on your ___.",a:"individual ... own",exp:"'Individual task' = solo work. 'On your own' = independently, without help. Clear expectations prevent plagiarism issues."},
        {id:"et036",type:"error",q:"Each groups need to select a leader who will present the group finding.",a:"Each group needs to select a leader who will present the group's findings.",exp:"'Each group' (singular). 'Needs' (third person singular). 'Group's findings' (possessive + plural)."},
        {id:"et037",type:"fill",q:"Use the ___ starters on the board to help ___ your responses in full sentences.",a:"sentence ... structure",exp:"Sentence starters are a common scaffold in Australian classrooms. They help students write academic English rather than informal responses."},
        {id:"et038",type:"open",q:"Explain how to use a graphic organiser for a compare-and-contrast essay.",a:"I have given you a Venn diagram. In the left circle, write the features that are unique to renewable energy. In the right circle, write the features unique to non-renewable energy. In the overlapping section in the middle, write what they have in common. Once your diagram is complete, use it to plan your essay. Each section of the diagram becomes a paragraph.",exp:"Clear explanation linking the visual tool to the writing output. Step-by-step process with a clear connection between the graphic organiser and the essay structure."},
        {id:"et039",type:"fill",q:"Your ___ goal for this term is to improve your ability to ___ and interpret data.",a:"learning ... collect",exp:"'Learning goal' frames the target. 'Collect and interpret data' are key skill verbs across the Australian Curriculum."},
        {id:"et040",type:"mc",q:"What does 'differentiated instruction' mean?",options:["Teaching the same thing to everyone in the same way","Adjusting teaching to meet students at different levels","Only helping the smart students","Giving the struggling students easier work and ignoring everyone else"],a:1,exp:"Differentiation means adjusting content, process, or product so all students can access learning at their level. It includes support AND extension. Required in Australian schools."},
        {id:"et041",type:"fill",q:"I've ___ the task into three parts so it's easier to ___. Start with Part A.",a:"broken ... manage",exp:"'Broken the task into parts' = chunking. This scaffolding technique helps students who struggle with complex tasks. 'Easier to manage' reassures them."},
        {id:"et042",type:"error",q:"This task require you to use internet for research. Please do not copy paste from website.",a:"This task requires you to use the internet for research. Please do not copy and paste from websites.",exp:"'Requires' (third person singular). 'The internet' (specific — always 'the'). 'Copy and paste' (two verbs joined by 'and'). 'Websites' (plural)."}
      ]
    },
    {
      id: "feedback-to-students",
      title: "Giving Feedback to Students",
      theory: "Effective feedback in Australian schools follows the 'two stars and a wish' or 'glow and grow' model — positive comments paired with actionable suggestions for improvement. Feedback should be specific, timely, and focused on the work rather than the student's character.",
      exercises: [
        {id:"fs001",type:"fill",q:"You've made ___ progress on this essay. One area to ___ on is your use of evidence.",a:"great ... improve",exp:"'Great progress' is encouraging. 'Area to improve on' is the standard feedback phrase for suggesting growth."},
        {id:"fs002",type:"mc",q:"Which is the most effective written feedback comment?",options:["Good.","Well done!","Your introduction clearly states your argument, but your conclusion needs to connect back to your thesis. Try restating your main point in different words.","Try harder next time."],a:2,exp:"Effective feedback is specific (names what was done well), diagnostic (identifies the issue), and actionable (tells the student HOW to improve)."},
        {id:"fs003",type:"error",q:"Your work is very good but you need to more carefully with spelling.",a:"Your work is very good, but you need to be more careful with your spelling.",exp:"'Need to be more careful' (need + to be + comparative adjective). 'Your spelling' needs possessive. Chinese speakers often omit 'be' in these constructions."},
        {id:"fs004",type:"fill",q:"I really liked how you ___ the different perspectives in your analysis. ___ time, try to include more specific examples.",a:"compared ... Next",exp:"Specific praise + forward-looking improvement. 'Compared the different perspectives' names the skill demonstrated."},
        {id:"fs005",type:"mc",q:"What is 'feedforward' in educational practice?",options:["Feedback given too early","Suggestions focused on what to do differently NEXT time, rather than what went wrong","Positive feedback only","Feedback given by email"],a:1,exp:"Feedforward focuses on future actions rather than past mistakes. It is more motivating and actionable. For example, 'Next time, try to...' rather than 'You failed to...'."},
        {id:"fs006",type:"fill",q:"This is a solid ___ draft. I can see you've put in real ___. Let's work on tightening up your paragraphs.",a:"first ... effort",exp:"'Solid first draft' validates the work without implying it is finished. 'Put in real effort' acknowledges the process, not just the product."},
        {id:"fs007",type:"error",q:"You are improve a lot since the beginning of the term. Keep up the good work.",a:"You have improved a lot since the beginning of the term. Keep up the good work.",exp:"'Have improved' — present perfect for change over time (since...). Chinese speakers often use present tense for completed changes because Mandarin doesn't conjugate verbs."},
        {id:"fs008",type:"fill",q:"Your diagram is clearly ___ and well ___. To move to the next level, add labels with technical vocabulary.",a:"drawn ... labelled",exp:"Specific praise for both accuracy and presentation. 'To move to the next level' is the standard 'how to improve' phrasing aligned to NSW achievement levels."},
        {id:"fs009",type:"open",q:"Write feedback for a student whose creative writing has good ideas but many grammar errors.",a:"You have some really creative ideas in this story — I especially liked the twist at the end. Your dialogue feels natural and your characters are developing well. To strengthen your writing further, focus on two things: first, check that each sentence has a subject and a verb; second, read your work aloud to catch missing words. I have circled three examples for you to revise. Keep writing — you have a real talent for storytelling.",exp:"Balance praise for creativity with specific, manageable grammar goals. Limit the number of corrections to avoid overwhelming the student. End positively."},
        {id:"fs010",type:"fill",q:"I've ___ some comments in the margin of your essay. Please read them carefully and ___ the changes before resubmitting.",a:"written ... make",exp:"'Written comments in the margin' describes annotation feedback. 'Make the changes' = implement the suggested revisions."},
        {id:"fs011",type:"mc",q:"Which feedback approach is best for a student who is already high-achieving?",options:["Just write 'Excellent!' and move on","Challenge them with extension questions that push their thinking further","Tell them they don't need to improve anything","Give them the same feedback as everyone else"],a:1,exp:"High-achieving students still need feedback that stretches them. Extension questions and higher-order thinking challenges maintain engagement and growth."},
        {id:"fs012",type:"fill",q:"You've ___ all the success criteria for this task. Well ___!",a:"met ... done",exp:"'Met all the success criteria' links back to the assessment standards. 'Well done' is simple, genuine praise."},
        {id:"fs013",type:"error",q:"I suggest you to rewrite the conclusion. It is not enough strong.",a:"I suggest you rewrite the conclusion. It is not strong enough.",exp:"'Suggest' + base verb (no 'to' in this pattern). 'Strong enough' — adjective before 'enough', not after. Both are common Chinese speaker errors."},
        {id:"fs014",type:"fill",q:"Your ___ skills have really improved this term. I've noticed you're much more confident when ___ in front of the class.",a:"presentation ... speaking",exp:"Tracking growth over time shows students you notice their progress. 'Presentation skills' and 'speaking in front of the class' are specific observable behaviours."},
        {id:"fs015",type:"mc",q:"When should verbal feedback be given?",options:["Only at the end of the term","During the task, while students can still make changes","Only on report cards","Never — all feedback should be written"],a:1,exp:"Verbal feedback during a task is most timely and actionable — students can apply it immediately. Written feedback is important too, but in-the-moment feedback is powerful."},
        {id:"fs016",type:"fill",q:"I can see you've ___ hard on this, and it ___. Your research is thorough and well-organised.",a:"worked ... shows",exp:"'Worked hard' acknowledges effort. 'It shows' connects effort to visible quality. 'Thorough and well-organised' names specific qualities."},
        {id:"fs017",type:"error",q:"Your work have many good point but also have some mistake. Please to fix them.",a:"Your work has many good points but also has some mistakes. Please fix them.",exp:"'Work has' (uncountable noun, singular verb). 'Points', 'mistakes' (plurals). 'Please fix' (no 'to' after 'please' + imperative). Multiple common Chinese speaker errors."},
        {id:"fs018",type:"fill",q:"One ___ I'd like you to focus on is ___ your ideas more clearly. Use linking words like 'however' and 'therefore'.",a:"thing ... connecting",exp:"'One thing to focus on' keeps the improvement manageable. Naming specific strategies (linking words) makes the feedback actionable."},
        {id:"fs019",type:"open",q:"Write verbal feedback for a student who has improved their behaviour but still struggles academically.",a:"I just want to say, I have really noticed the effort you have been putting into your behaviour this term, and I am proud of you. You are being respectful, staying on task, and that takes real maturity. Now, let us work together on building up your academic skills. I know you can do it because you have already shown you can make big changes. Let us set a small goal for this week — how about completing one paragraph of your essay by Thursday? I will help you get started.",exp:"Lead with genuine praise for behaviour improvement. Then transition to academics with a supportive, non-judgemental tone. Set a small, achievable goal."},
        {id:"fs020",type:"fill",q:"Your teamwork during the group activity was ___. You listened to your ___ and contributed your own ideas as well.",a:"excellent ... peers",exp:"'Peers' is the professional term for fellow students. Naming specific teamwork behaviours (listening, contributing) makes the praise meaningful."},
        {id:"fs021",type:"mc",q:"What does the 'glow and grow' feedback model involve?",options:["Writing in glowing ink","One positive comment (glow) and one improvement suggestion (grow)","Only giving positive feedback","Grading on a curve"],a:1,exp:"'Glow and grow' is widely used in Australian schools. 'Glow' = what was done well. 'Grow' = what to improve next. Simple, balanced, effective."},
        {id:"fs022",type:"fill",q:"I appreciate the ___ you put into this design. To take it further, ___ adding colour coding to distinguish the different sections.",a:"thought ... consider",exp:"'The thought you put into' values the thinking process. 'Consider adding' is a softer suggestion that empowers the student to decide."},
        {id:"fs023",type:"error",q:"You should to spent more time on proof reading your work before to hand it in.",a:"You should spend more time on proofreading your work before handing it in.",exp:"No 'to' after 'should'. 'Spend' (base form). 'Proofreading' (one word). 'Before handing' (gerund after 'before'). 'Hand it in' (phrasal verb for submission)."},
        {id:"fs024",type:"fill",q:"Your understanding of the topic is ___. The next step is to ___ that understanding into your written responses.",a:"strong ... translate",exp:"'Translate understanding into written responses' — bridging the gap between knowing and demonstrating. A common challenge for EAL/D students."},
        {id:"fs025",type:"mc",q:"What is the best way to give feedback on late work?",options:["Don't accept it at all","Mark it as normal but note the lateness separately","Write 'LATE' in red across the top","Give it a zero"],a:1,exp:"Marking the quality of work separately from the submission issue is fairest. Address lateness through school processes (not through academic penalties on the work itself)."},
        {id:"fs026",type:"fill",q:"Your hypothesis was clearly ___ and your method was well ___. However, your analysis could go deeper.",a:"stated ... structured",exp:"Science feedback: hypothesis (clearly stated), method (well structured), analysis (needs depth). Specific subject feedback helps students improve."},
        {id:"fs027",type:"error",q:"This essay have a strong thesis but the body paragraphs doesn't support it enough.",a:"This essay has a strong thesis, but the body paragraphs don't support it enough.",exp:"'Essay has' (singular). 'Paragraphs don't' (plural). Subject-verb agreement is a common challenge when Chinese speakers translate directly."},
        {id:"fs028",type:"fill",q:"I'd like to ___ on the progress you've made. You went from a C to a ___ on this task — that's a fantastic achievement.",a:"comment ... B",exp:"Naming grade improvement is motivating. 'Comment on the progress' is a professional feedback opener."},
        {id:"fs029",type:"open",q:"Write a brief comment for a report card about a student who is average in ability but has excellent attitude.",a:"Jasmine is a conscientious student who consistently demonstrates a positive attitude towards her learning. She participates actively in class discussions and always completes her work to a high standard of effort. To continue improving, Jasmine should focus on developing her analytical skills by practising how to explain her reasoning in more depth. With her strong work ethic, I am confident she will make excellent progress.",exp:"Report card comments should be professional, balanced, and forward-looking. Name specific strengths and one growth area. End positively."},
        {id:"fs030",type:"fill",q:"Thank you for ___ this in on time. I know it's been a busy week, and I ___ the effort.",a:"handing ... appreciate",exp:"Acknowledging timely submission is a positive reinforcement strategy. 'Appreciate the effort' validates the student's time management."},
        {id:"fs031",type:"mc",q:"Which phrase is most appropriate for a student who needs significant improvement?",options:["This is terrible work.","There is significant room for growth in this area. Let's discuss a plan to help you improve.","You obviously didn't try.","This is below standard."],a:1,exp:"'Room for growth' is diplomatic and focuses on potential, not failure. Offering a plan shows support. Avoid language that shames or demotivates."},
        {id:"fs032",type:"error",q:"You are progressed well but still need to working on your spelling and grammar.",a:"You have progressed well but still need to work on your spelling and grammar.",exp:"'Have progressed' (present perfect for progress over time). 'Need to work' (infinitive, not gerund). These tense errors are extremely common for Chinese speakers."},
        {id:"fs033",type:"fill",q:"I've noticed you tend to ___ through tasks quickly. Try to ___ down and check your work before submitting.",a:"rush ... slow",exp:"'Rush through' = do too quickly without care. 'Slow down' is a common collocation. Specific observation + specific action = good feedback."},
        {id:"fs034",type:"fill",q:"Your ___ of primary sources in this history essay is ___. You've clearly done thorough research.",a:"use ... impressive",exp:"'Use of primary sources' is specific to the task. 'Impressive' is a strong positive word that still sounds professional."},
        {id:"fs035",type:"mc",q:"What is 'assessment for learning' (formative assessment)?",options:["A final exam","Ongoing assessment used to identify what students know and need to learn next","A standardised test","Report card grades"],a:1,exp:"Assessment FOR learning (formative) informs teaching and learning decisions. Assessment OF learning (summative) measures achievement. This distinction is key in Australian education."},
        {id:"fs036",type:"error",q:"I recommend that you will practise writing every day to improve your fluency.",a:"I recommend that you practise writing every day to improve your fluency.",exp:"'Recommend that + subject + base verb' (subjunctive). No 'will'. In Australian English, 'practise' is the verb spelling."},
        {id:"fs037",type:"fill",q:"Your code ___ correctly, but I'd suggest adding ___ to explain what each function does.",a:"runs ... comments",exp:"Programming feedback: functionality (runs correctly) + readability (add comments). Code comments are a good practice to teach."},
        {id:"fs038",type:"open",q:"Write feedback for a group project where one student did most of the work.",a:"The final product is well-researched and presented. However, I noticed that the contribution was not evenly distributed among group members. For future group work, I want each person to clearly define their role at the start and record their individual contributions in a log. Strong collaboration means everyone carries their share. Let us talk about how we can make group work fairer next time.",exp:"Address uneven contribution without naming individuals in written feedback. Set expectations for future collaboration. Create systems (role cards, contribution logs) to prevent it."},
        {id:"fs039",type:"fill",q:"Your ___ has improved markedly since the start of the year. Keep up the ___ work.",a:"handwriting ... fantastic",exp:"Noticing improvement over time motivates students. 'Markedly' means noticeably/significantly. 'Fantastic' is warm and genuine."},
        {id:"fs040",type:"mc",q:"When giving feedback on a student's oral presentation, which is most helpful?",options:["Your presentation was OK I guess.","You spoke clearly and maintained eye contact. One area to improve is your pacing — try to slow down during your key arguments so the audience can follow.","Too many ums and ahs.","You need to be louder."],a:1,exp:"Specific positive + specific improvement + actionable strategy (slow down during key arguments). Vague feedback ('OK I guess') or criticism without strategy ('too many ums') is not helpful."},
        {id:"fs041",type:"fill",q:"I've ___ you an A for this task because your analysis is ___ and well-supported by evidence.",a:"given ... thorough",exp:"'Given you an A' links the grade to specific qualities. 'Thorough and well-supported' names what earned the grade."},
        {id:"fs042",type:"error",q:"Keep try your best. I am sure you will success in the exam.",a:"Keep trying your best. I am sure you will succeed in the exam.",exp:"'Keep trying' (keep + gerund). 'Will succeed' (succeed is the verb, success is the noun). Common Chinese speaker confusion because 成功 (chénggōng) can be both."}
      ]
    }
  ]
},
// ============================================================
// MODULE 2: PROFESSIONAL EMAILS & WRITTEN COMMUNICATION
// ============================================================
professionalEmails: {
  title: "Professional Emails & Written Communication",
  sections: [
    {
      id: "email-openings-closings",
      title: "Email Openings & Closings",
      theory: "Australian professional emails are more informal than many other cultures, but there are still conventions. 'Hi [Name]' is standard for colleagues. 'Dear [Name]' is for formal/external. Always include a clear subject line. Closings: 'Kind regards' (standard), 'Best wishes' (warm), 'Cheers' (informal colleague). Chinese speakers often over-formalise or under-formalise because 你好 covers all registers.",
      exercises: [
        {id:"eo001",type:"fill",q:"___ Sarah,\n\nI hope this email ___ you well.",a:"Hi ... finds",exp:"'Hi Sarah' is the standard opening for a colleague you know. 'I hope this email finds you well' is a common warm opener. 'Dear' would be too formal for a fellow teacher."},
        {id:"eo002",type:"mc",q:"Which closing is most appropriate for an email to your Head of Department?",options:["Love, [Your name]","Cheers, [Your name]","Kind regards, [Your name]","Bye bye, [Your name]"],a:2,exp:"'Kind regards' is professional and appropriate for your Head of Department. 'Cheers' is fine for close colleagues. 'Love' and 'Bye bye' are never appropriate in professional emails."},
        {id:"eo003",type:"error",q:"Dear Mr. Smith, I am writing this email for telling you about the upcoming event.",a:"Dear Mr Smith, I am writing to let you know about the upcoming event.",exp:"In Australian English, no full stop after Mr/Mrs/Ms. 'Writing to let you know' is more natural than 'writing for telling'. Simpler and more direct."},
        {id:"eo004",type:"fill",q:"Thank you for your ___ reply. I appreciate you getting ___ to me so quickly.",a:"prompt ... back",exp:"'Prompt reply' = fast response. 'Getting back to me' = replying. Both are standard professional email phrases."},
        {id:"eo005",type:"mc",q:"What is the best subject line for an email about a Year 8 excursion?",options:["Hi!","URGENT - READ NOW!!!","Year 8 Science Excursion — Friday 14 March","Something about the excursion"],a:2,exp:"Good subject lines are specific: year group, topic, date. They help recipients prioritise and find the email later. Vague or all-caps subjects are unprofessional."},
        {id:"eo006",type:"fill",q:"I'm writing to ___ you that the staff meeting has been ___ to Thursday.",a:"inform ... rescheduled",exp:"'Inform you that' is formal. 'Rescheduled to Thursday' = moved to a new time. Clear, direct purpose statement."},
        {id:"eo007",type:"error",q:"I want to know can you attend the meeting tomorrow? Please reply me as soon as possible.",a:"I was wondering if you could attend the meeting tomorrow? Please reply as soon as possible.",exp:"'I was wondering if' is more polite than 'I want to know can you'. 'Reply' is intransitive in this context (no 'me'). Chinese 回复我 translates directly but is wrong in English."},
        {id:"eo008",type:"fill",q:"Please find ___ the documents I mentioned in our conversation ___.",a:"attached ... earlier",exp:"'Please find attached' is the standard phrase for email attachments. 'Mentioned earlier' (not 'before time' or 'last time'). Formal but natural."},
        {id:"eo009",type:"mc",q:"When is 'Dear Sir/Madam' appropriate?",options:["In every email","When you don't know the recipient's name","When emailing a friend","When replying to a colleague"],a:1,exp:"'Dear Sir/Madam' is only for formal emails where you do not know the person's name. It is becoming less common — many people prefer 'To whom it may concern' or finding the person's name."},
        {id:"eo010",type:"fill",q:"Just a quick ___ to let you know that I've ___ the permission slips for the Year 9 excursion.",a:"note ... collected",exp:"'Just a quick note' signals a brief, informal email to a colleague. 'Collected' is past tense — the action is complete."},
        {id:"eo011",type:"error",q:"I look forward to hear from you soon. Thank you for your patient.",a:"I look forward to hearing from you soon. Thank you for your patience.",exp:"'Look forward to hearing' (to + gerund, because 'to' is a preposition here). 'Patience' is the noun, 'patient' is the adjective. Chinese speakers often confuse these."},
        {id:"eo012",type:"open",q:"Write an opening paragraph for an email introducing yourself to a new colleague.",a:"Hi James, My name is Yunshu Gao, and I am one of the Technology teachers here at the school. I wanted to reach out and welcome you to the team. Please do not hesitate to ask if you need anything — I remember how overwhelming the first few weeks can be! I would be happy to show you around or answer any questions.",exp:"Professional, warm, and helpful. Australian workplace culture values welcoming new colleagues. 'Don't hesitate to ask' is a key offer phrase."},
        {id:"eo013",type:"fill",q:"I hope you had a lovely ___. I'm getting in ___ about the upcoming parent-teacher evening.",a:"weekend ... touch",exp:"'Hope you had a lovely weekend' is a common Monday email opener in Australia. 'Getting in touch' = contacting. Warm but professional."},
        {id:"eo014",type:"mc",q:"Which is the most professional way to end an email when you need a reply?",options:["Reply ASAP!!!","I'd appreciate your response by Friday if possible.","Write back quickly.","Don't forget to answer me."],a:1,exp:"'I'd appreciate your response by Friday if possible' is polite, clear about the deadline, and uses 'if possible' to soften the request."},
        {id:"eo015",type:"fill",q:"Thanks for ___ me know. I'll ___ sure to pass this information on to my class.",a:"letting ... make",exp:"'Thanks for letting me know' is the standard informal acknowledgement. 'Make sure to' = ensure."},
        {id:"eo016",type:"error",q:"Kindly please revert back to me at your earliest convenience.",a:"Please get back to me at your earliest convenience.",exp:"Overly formal. 'Revert' does not mean 'reply' in Australian English. 'Kindly please' is a double softener (remove one). 'Get back to me' is the natural Australian phrase."},
        {id:"eo017",type:"fill",q:"I wanted to ___ up on our conversation about the new ___.",a:"follow ... timetable",exp:"'Follow up on' = continue discussing. 'Timetable' is the Australian term for a school schedule."},
        {id:"eo018",type:"mc",q:"Which email sign-off is appropriate for a parent you haven't met?",options:["Cheers","Kind regards","See ya","Thanks heaps"],a:1,exp:"'Kind regards' is the safest professional sign-off for parents, especially ones you haven't met. 'Cheers' and 'Thanks heaps' are too casual for initial parent contact."},
        {id:"eo019",type:"fill",q:"Please don't ___ to reach out if you have any further ___.",a:"hesitate ... questions",exp:"'Don't hesitate to reach out' is a standard warm closing. 'Further questions' = additional queries. This phrase is very common in Australian professional emails."},
        {id:"eo020",type:"error",q:"I am appreciate your help very much. Thanks you for the support.",a:"I really appreciate your help. Thank you for your support.",exp:"'Appreciate' is already a verb — no 'am' before it. 'Thank you' (not 'Thanks you'). 'Your support' needs possessive."},
        {id:"eo021",type:"fill",q:"With ___ regards,\nYunshu Gao\nTechnology Teacher\nArthur Phillip ___",a:"warm ... High School",exp:"'Warm regards' is slightly more personal than 'Kind regards'. Email signatures should include your role and school name."},
        {id:"eo022",type:"open",q:"Write a short email to a colleague thanking them for covering your class while you were at a PD day.",a:"Hi Rachel, Just a quick note to say thank you so much for covering my Year 8 class on Tuesday while I was at the professional development session. I really appreciate it — I know it is a big ask on top of your own teaching load. I owe you one! Let me know if you ever need me to return the favour. Kind regards, Yunshu",exp:"Brief, genuine, acknowledges the inconvenience, offers reciprocation. 'I owe you one' is informal but appropriate for colleagues. 'Return the favour' is a natural Australian English expression."},
        {id:"eo023",type:"fill",q:"I'm copying in ___ so she's across the latest ___.",a:"Lisa ... updates",exp:"'Copying in' (CC'ing) someone. 'Across the latest updates' = informed about recent developments. Very Australian workplace phrasing."},
        {id:"eo024",type:"mc",q:"What does 'FYI' mean in an email?",options:["Fix Your Issues","For Your Information","Final Year Inspection","File Your Invoice"],a:1,exp:"FYI = For Your Information. Used when sharing information that doesn't require a response. Common in informal workplace emails."},
        {id:"eo025",type:"error",q:"I have send you the file yesterday. Please check it and give me your feedback.",a:"I sent you the file yesterday. Please check it and give me your feedback.",exp:"'Sent' (past simple with 'yesterday', not present perfect). 'Have sent' would only work without 'yesterday'. Time markers require matching tenses."},
        {id:"eo026",type:"fill",q:"___ you in advance for your ___.",a:"Thank ... assistance",exp:"'Thank you in advance' is used when you expect someone will help. 'Assistance' is more formal than 'help' — appropriate for external emails."},
        {id:"eo027",type:"fill",q:"I'll keep you ___ on any developments. In the ___, please let me know if you have questions.",a:"posted ... meantime",exp:"'Keep you posted' = keep you informed. 'In the meantime' = in the period between now and then. Both are very common email phrases."},
        {id:"eo028",type:"mc",q:"When should you use 'Reply All' on an email?",options:["Always — so everyone is informed","Only when everyone on the thread needs to see your response","Whenever you want to make a point publicly","Never — it's rude"],a:1,exp:"Reply All should only be used when all recipients genuinely need the information. Unnecessary Reply Alls are a common source of frustration in schools."},
        {id:"eo029",type:"error",q:"Dear Teacher, I want to discuss about the homework policy with you.",a:"Dear Ms Gao, I would like to discuss the homework policy with you.",exp:"'Dear Teacher' is too generic — use the person's name. 'Would like' is more polite than 'want'. 'Discuss' doesn't take 'about' (discuss the policy, not discuss about). Chinese 讨论关于 leads to this error."},
        {id:"eo030",type:"fill",q:"Sorry for the ___ reply — it's been a hectic ___.",a:"late ... week",exp:"'Sorry for the late reply' is the standard apology for delayed responses. 'Hectic week' = very busy week. Honest and brief."},
        {id:"eo031",type:"open",q:"Write a professional out-of-office reply for the school holidays.",a:"Thank you for your email. I am currently on school holidays and will not be checking emails regularly until Monday 28 January. If your matter is urgent, please contact the school office on (02) 9630 XXXX. I will respond to your email when I return. Kind regards, Yunshu Gao",exp:"Out-of-office replies should include: return date, alternative contact for urgent matters, and a professional tone."},
        {id:"eo032",type:"fill",q:"As ___ in the meeting, I've attached the ___ assessment schedule.",a:"discussed ... updated",exp:"'As discussed' references a prior conversation. 'Updated assessment schedule' signals it has been revised."},
        {id:"eo033",type:"mc",q:"What time is appropriate to send work emails in Australia?",options:["Any time — 3am is fine","Between 7am and 7pm on workdays","Only during exact work hours (9-5)","Never on Fridays"],a:1,exp:"While there is no strict rule, sending between 7am-7pm on workdays is considerate. Use 'Schedule Send' for emails written outside these hours. Work-life balance is valued in Australian culture."},
        {id:"eo034",type:"fill",q:"I ___ forward to working with you on this ___.",a:"look ... project",exp:"'Look forward to working with you' is a warm, professional closing phrase. 'On this project' specifies the collaboration."},
        {id:"eo035",type:"error",q:"I am sorry to disturb you. Could you please kindly help me to check the report?",a:"Sorry to bother you. Could you please check the report for me?",exp:"'Disturb' is too strong — 'bother' is appropriate. Too many softeners: remove 'kindly' or 'please' (one is enough). 'Check the report for me' is more natural. Chinese speakers tend to over-apologise in English."},
        {id:"eo036",type:"fill",q:"I wanted to ___ base with you about the upcoming parent-teacher ___.",a:"touch ... evening",exp:"'Touch base' = check in briefly. 'Parent-teacher evening' is the Australian term. This is a casual but professional opener."},
        {id:"eo037",type:"error",q:"Dear All Staffs, I would like to inform that the excursion has been postponed.",a:"Dear All, I would like to inform you that the excursion has been postponed.",exp:"'All' (not 'All Staffs' — staff is collective/uncountable). 'Inform you' needs the object pronoun. Two common errors in professional emails."},
        {id:"eo038",type:"fill",q:"Many thanks for your ___ assistance with this matter. I really ___ your support.",a:"continued ... value",exp:"'Continued assistance' implies ongoing help. 'Value your support' is warmer than 'appreciate'. Formal but warm closing."},
        {id:"eo039",type:"mc",q:"Which subject line is most professional?",options:["Hey","Question about something","Request for Leave — 21 March 2026","Please read this urgently!!!"],a:2,exp:"Good subject lines: specific topic + relevant date/detail. They help the recipient prioritise and file the email. Exclamation marks and vague subjects are unprofessional."},
        {id:"eo040",type:"fill",q:"I'll be working from ___ tomorrow, so the best way to reach me is by ___ or Teams message.",a:"home ... email",exp:"Working from home is common in Australian schools for planning days. 'Best way to reach me' manages communication expectations."},
        {id:"eo041",type:"error",q:"Regarding to your email, I have already complete the task. Please see the attachment.",a:"Regarding your email, I have already completed the task. Please see the attachment.",exp:"'Regarding' (no 'to' after it). 'Have completed' (past participle). 'Please see the attachment' is the standard phrase (not 'please see the attached' without a noun)."},
        {id:"eo042",type:"fill",q:"I'm writing to ___ receipt of your email dated 15 March. I will ___ to the matters raised as soon as possible.",a:"acknowledge ... respond",exp:"'Acknowledge receipt' is formal email language for confirming you got the email. 'Respond to matters raised' = address the issues mentioned."},
        {id:"eo043",type:"fill",q:"As per our ___ conversation, I've gone ahead and booked the computer lab for ___.",a:"earlier ... Thursday",exp:"'As per our earlier conversation' references a prior agreement. 'Gone ahead and booked' shows you took action. Professional follow-through."},
        {id:"eo044",type:"mc",q:"When CC'ing someone, should you mention it in the email body?",options:["No, never","Yes, always explain why they are CC'd","Only if it's your boss","Only for external emails"],a:1,exp:"Best practice: briefly explain why someone is CC'd. For example, 'I've CC'd Lisa so she's across this.' It helps everyone understand the communication chain."},
        {id:"eo045",type:"fill",q:"I'll ___ this to the relevant team and circle ___ with you once I have an update.",a:"escalate ... back",exp:"'Escalate' = refer to a higher level/specialist. 'Circle back' = return to discuss later. Professional workflow language."}
      ]
    },
    {
      id: "requesting",
      title: "Making Requests & Asking for Help",
      theory: "Australian workplace culture values directness softened by politeness. Requests should be clear about what you need and when you need it, but wrapped in polite language. 'Could you...', 'Would you mind...', and 'I was wondering if...' are the main request forms. Avoid being too indirect (the Chinese tendency to hint rather than ask directly) or too direct (which can sound demanding).",
      exercises: [
        {id:"rq001",type:"fill",q:"___ you mind sharing your lesson resources for the ___ unit?",a:"Would ... sustainability",exp:"'Would you mind + gerund' is a very polite request form. It literally asks 'Would it bother you to...?' The expected answer is 'Not at all' (= yes, I'll share)."},
        {id:"rq002",type:"mc",q:"Which request is most appropriate when asking your head teacher for time off?",options:["I'm taking next Friday off.","I need next Friday off. Can you arrange it?","I was wondering if it would be possible to take next Friday off for a personal appointment?","Give me Friday off please."],a:2,exp:"'I was wondering if it would be possible...' is the most respectful form. It acknowledges the request is negotiable. Giving a brief reason ('personal appointment') is expected."},
        {id:"rq003",type:"fill",q:"Could I ___ borrow your science equipment for my Year 7 class on ___?",a:"please ... Wednesday",exp:"'Could I please...' is polite and direct. Specifying the day helps the colleague plan. Being specific makes it easier for people to say yes."},
        {id:"rq004",type:"error",q:"I want you help me with the report card. Can you do it now?",a:"I was wondering if you could help me with the report cards. When would suit you?",exp:"'I want you help' is a direct translation from Chinese (我想你帮我). English needs 'I was wondering if you could help me'. 'When would suit you?' respects their time."},
        {id:"rq005",type:"fill",q:"I'd really ___ it if you could ___ over my lesson plan when you get a chance.",a:"appreciate ... look",exp:"'I'd appreciate it if you could...' is a warm, professional request. 'Look over' = review casually. 'When you get a chance' removes urgency pressure."},
        {id:"rq006",type:"mc",q:"A colleague asks you to do something you cannot do right now. What is the best response?",options:["No.","I'm afraid I can't right now, but I could help you after lunch. Would that work?","That's not my job.","Maybe later."],a:1,exp:"Declining with an alternative is the gold standard. 'I'm afraid' softens the no. Offering a specific alternative time shows willingness. 'Would that work?' checks it's acceptable."},
        {id:"rq007",type:"fill",q:"Sorry to ___ you, but could I ask a quick ___?",a:"bother ... favour",exp:"'Sorry to bother you' acknowledges the interruption. 'Ask a favour' is the natural phrase for a request. Brief and polite."},
        {id:"rq008",type:"error",q:"Could you please to help me translate this document? I need it until Friday.",a:"Could you please help me translate this document? I need it by Friday.",exp:"No 'to' after 'please' in a request (it's 'Could you please help', not 'Could you please to help'). 'By Friday' (deadline), not 'until Friday' (duration). Chinese 到 covers both meanings."},
        {id:"rq009",type:"fill",q:"Would it be ___ if I used the computer lab for my Year 9 class ___ Tuesday?",a:"possible ... next",exp:"'Would it be possible if...' is very polite and professional. Specifying the date helps logistics."},
        {id:"rq010",type:"mc",q:"What does 'I'll owe you one' mean when someone helps you?",options:["You need to pay them money","You will return the favour in the future","You are in debt to them officially","You need to write them a thank you card"],a:1,exp:"'I'll owe you one' is an informal way of saying 'I'll return the favour'. Very common in Australian English and shows appreciation."},
        {id:"rq011",type:"fill",q:"I don't suppose you'd be ___ to cover my class for ten minutes while I deal with this ___?",a:"able ... situation",exp:"'I don't suppose you'd be able to...' is an extremely polite request — it almost expects a 'no', making it easy for the person to say yes or no."},
        {id:"rq012",type:"error",q:"Please give me the data before the end of today. I am waiting for it.",a:"Would it be possible to get the data by the end of today? I need it to complete the report.",exp:"Too direct and sounds demanding. Adding 'Would it be possible' softens it. Explaining why you need it (to complete the report) makes the request reasonable."},
        {id:"rq013",type:"fill",q:"Do you happen to have a ___ copy of the Year 8 scope and ___? Mine seems to be outdated.",a:"spare ... sequence",exp:"'Do you happen to have...' is a casual, polite way to ask. 'Spare copy' = extra/additional copy. 'Scope and sequence' is an Australian curriculum planning document."},
        {id:"rq014",type:"open",q:"Write an email requesting professional development time from your principal.",a:"Dear Ms Thompson, I am writing to request approval to attend a two-day workshop on integrating technology into the classroom, being held at UTS on 15-16 May. The workshop covers project-based learning with digital tools, which aligns directly with our school's strategic plan for technology integration. I believe it would benefit both my teaching practice and our department's goals. A casual teacher would be needed for my classes on those two days. I am happy to share what I learn with the faculty when I return. Would you be open to supporting this request? Kind regards, Yunshu Gao",exp:"Professional request: specific details, alignment with school goals, practical logistics, and an offer to share learning. 'Would you be open to...' is a polite, non-presumptuous closing."},
        {id:"rq015",type:"fill",q:"I was ___ if you had any advice on how to ___ with a student who is consistently disruptive.",a:"wondering ... deal",exp:"'I was wondering if...' is the standard polite request opener. 'Deal with' = manage/handle. Seeking advice from colleagues is valued in Australian school culture."},
        {id:"rq016",type:"mc",q:"What is the polite way to remind someone who hasn't replied to your email?",options:["You still haven't replied. I'm waiting.","Just a gentle reminder about my email last week regarding the book order.","Did you forget about my email?","SECOND REQUEST — PLEASE REPLY"],a:1,exp:"'Just a gentle reminder' is the standard follow-up phrase. It's professional and non-accusatory. Reference the original topic so they can find it quickly."},
        {id:"rq017",type:"fill",q:"Could you ___ me the details when you get a ___? No rush at all.",a:"send ... chance",exp:"'Send me the details' is direct. 'When you get a chance' and 'No rush at all' remove time pressure and show respect for their workload."},
        {id:"rq018",type:"error",q:"I hope you can give me some advices about how to improve my teaching.",a:"I hope you can give me some advice on how to improve my teaching.",exp:"'Advice' is uncountable (never 'advices'). 'Advice on' (not 'about' in this context). Chinese 建议 can be counted, leading to this common error."},
        {id:"rq019",type:"fill",q:"I hate to ask, but would you ___ swapping playground duty with me on ___?",a:"mind ... Friday",exp:"'I hate to ask' acknowledges the inconvenience. 'Would you mind swapping' is a polite request for a favour. Playground duty swaps are common in Australian schools."},
        {id:"rq020",type:"mc",q:"How should you ask a colleague you don't know well for their resources?",options:["Send me your worksheets.","Hi, I've heard great things about your Year 9 unit. Would you be willing to share some of your resources? I'd be happy to share mine in return.","I need your lesson plans by tomorrow.","Can I just have all your stuff?"],a:1,exp:"Compliment + specific request + offer of reciprocity. This builds professional relationships and shows respect for their intellectual property."},
        {id:"rq021",type:"fill",q:"Would you be ___ to give me some ___ on my assessment task before I submit it to the head teacher?",a:"willing ... feedback",exp:"'Willing to give feedback' is respectful of their time. 'Before I submit it' explains the timeline and purpose."},
        {id:"rq022",type:"error",q:"May I to ask you a question? I don't understand what means 'differentiation'.",a:"May I ask you a question? I don't understand what 'differentiation' means.",exp:"No 'to' after 'May I' (modal). 'What differentiation means' — embedded question uses statement word order (subject before verb). Chinese question structure leads to inversion errors."},
        {id:"rq023",type:"fill",q:"I'd be ___ if you could point me in the right ___ regarding the new reporting software.",a:"grateful ... direction",exp:"'I'd be grateful' is very polite. 'Point me in the right direction' = help me get started. Very natural Australian phrase."},
        {id:"rq024",type:"open",q:"Write a message asking the IT department to set up student accounts for your new class.",a:"Hi IT Team, I hope you are well. I have a new group of Year 7 students starting the Technology elective next week, and they will need access to the school's Google Workspace accounts. There are 28 students in total. I have attached the class list with their student numbers. Would it be possible to have the accounts set up by Monday 3 March? Please let me know if you need any additional information. Thanks very much for your help. Kind regards, Yunshu Gao",exp:"Clear purpose, specific details (number of students, deadline), attached information, and a polite closing. Professional but not overly formal for an internal request."},
        {id:"rq025",type:"fill",q:"Any ___ you could send me the updated assessment ___ by the end of the week?",a:"chance ... calendar",exp:"'Any chance you could...' is a casual, friendly request. Very Australian. 'Assessment calendar' is a school planning document."},
        {id:"rq026",type:"mc",q:"A parent asks you a question you cannot answer. What is the best response?",options:["I don't know.","That's not my area.","That's a great question. I'm not sure of the answer, but I'll find out and get back to you by tomorrow.","You should ask someone else."],a:2,exp:"Acknowledge the question, be honest about not knowing, commit to finding out, and give a timeline. This builds trust with parents."},
        {id:"rq027",type:"fill",q:"I need to ___ a request for new textbooks. Who should I ___ it to?",a:"submit ... address",exp:"'Submit a request' is the formal process. 'Address it to' = direct it to the right person. Understanding school administrative processes is important."},
        {id:"rq028",type:"error",q:"Could you borrow me your stapler? I will return it back to you after.",a:"Could you lend me your stapler? I will return it to you afterwards.",exp:"'Lend me' (give to use) not 'borrow me' (take to use). Chinese 借 covers both directions. 'Return it to you' (no 'back' — redundant). 'Afterwards' (not 'after' alone as a time word)."},
        {id:"rq029",type:"fill",q:"I'm reaching out to see if there's any ___ in the budget for new robotics equipment for the ___ department.",a:"room ... Technology",exp:"'Reaching out' = contacting. 'Room in the budget' = available funds. Professional budget request language."},
        {id:"rq030",type:"open",q:"Write a request to the school librarian for help with a research lesson.",a:"Hi Maria, I am planning a research lesson for my Year 9 IST class next Thursday and was wondering if you would be available to help the students with their database searches. There are 24 students, and they will be researching multimedia production techniques. It would be great if you could briefly show them how to use the EBSCO database at the start of the lesson. Would that work for you? Thanks so much. Yunshu",exp:"Specific: date, class, number of students, topic, and what you need from them. 'Would that work for you?' checks availability respectfully."},
        {id:"rq031",type:"fill",q:"I don't want to ___ you with extra work, but could you possibly ___-read my report?",a:"burden ... proof",exp:"'Burden you with extra work' acknowledges the ask. 'Proofread' = check for errors. A polite, considerate request."},
        {id:"rq032",type:"mc",q:"What does 'I'll leave it with you' mean?",options:["I'll physically leave something on your desk","I trust you to handle it and make a decision","I'm abandoning the task","I don't care about it anymore"],a:1,exp:"'I'll leave it with you' means 'I trust your judgement on this matter'. It delegates responsibility politely. Very common in Australian workplaces."},
        {id:"rq033",type:"error",q:"Please help me to find a room for the after school program. I am very need it.",a:"Could you please help me find a room for the after-school programme? I really need it.",exp:"'Help me find' (no 'to' after 'help'). 'After-school programme' (hyphenated, Australian spelling). 'Really need' (adverb, not 'very need'). 'Very' doesn't modify verbs."},
        {id:"rq034",type:"fill",q:"If it's not too much ___, could you show me how to use the new ___ system?",a:"trouble ... attendance",exp:"'If it's not too much trouble' is a classic Australian politeness phrase. 'Attendance system' = roll-marking software. Acknowledging the imposition is culturally valued."},
        {id:"rq035",type:"fill",q:"I'd love to pick your ___ about how you run your Year 10 ___.",a:"brain ... elective",exp:"'Pick your brain' = get your insights/expertise informally. 'Elective' = a subject students choose (not compulsory). This is casual colleague language."},
        {id:"rq036",type:"error",q:"Can you borrow me some whiteboard markers? I run out of them.",a:"Can you lend me some whiteboard markers? I've run out of them.",exp:"'Lend me' (give temporarily), not 'borrow me'. 'I've run out' (present perfect — the result matters now). Chinese 借 doesn't distinguish lend/borrow."},
        {id:"rq037",type:"fill",q:"Would you be ___ to swap duties with me next Tuesday? I have a specialist ___ during that time.",a:"willing ... appointment",exp:"'Willing to swap' is polite. 'Specialist appointment' is personal but gives enough context. You don't need to share details."},
        {id:"rq038",type:"mc",q:"Which is the most polite way to ask for more time on a task?",options:["I need more time.","Would it be possible to get a short extension? I want to make sure the work is thorough.","I can't finish it on time.","Just give me a few more days."],a:1,exp:"'Would it be possible' is polite. 'Short extension' is specific. 'I want to make sure the work is thorough' gives a positive reason. Quality over speed."},
        {id:"rq039",type:"fill",q:"I hate to be a ___, but could you turn the music down in your classroom? It's coming through the ___.",a:"pain ... wall",exp:"'Hate to be a pain' = sorry to bother you about this. Very Australian softener. 'Coming through the wall' explains the impact factually."},
        {id:"rq040",type:"fill",q:"Is there any ___ I could get access to the assessment ___ from last year? I'd like to use them as a reference.",a:"way ... tasks",exp:"'Any way I could' is very polite. 'Assessment tasks from last year' is specific. 'As a reference' explains why. Clear, professional request."}
      ]
    },
    {
      id: "parent-communication",
      title: "Communicating with Parents",
      theory: "Parent communication in Australian schools must be professional, empathetic, and solution-focused. Always lead with something positive (the 'sandwich' approach). Be specific about concerns but avoid jargon. Use 'we' language to show partnership. Chinese speakers may find the level of softening required unusual — in Chinese educational culture, directness about a child's weaknesses is often expected.",
      exercises: [
        {id:"pc001",type:"fill",q:"Dear Mrs Henderson,\n\nThank you for taking the ___ to meet with me today. I really ___ your involvement in Liam's education.",a:"time ... value",exp:"'Taking the time' acknowledges the parent's effort. 'Value your involvement' positions parents as partners. This opening builds rapport."},
        {id:"pc002",type:"mc",q:"Which opening sentence is best for an email about a behavioural concern?",options:["Your son has been very naughty in class.","I'm writing to let you know about some challenges Oliver has been facing in class, and to discuss how we can work together to support him.","Oliver is always disruptive and I can't teach when he's in my class.","I need to report Oliver's bad behaviour to you."],a:1,exp:"'Challenges he has been facing' frames the issue empathetically. 'Work together to support him' creates a partnership. Avoid blame language ('naughty', 'bad')."},
        {id:"pc003",type:"fill",q:"I wanted to share some ___ news about Aisha's progress. She has shown a real ___ in her writing this term.",a:"positive ... improvement",exp:"Leading with positive news builds the relationship. 'Real improvement' is specific and encouraging."},
        {id:"pc004",type:"error",q:"Your daughter is very lazy and always don't do her homework.",a:"Your daughter has been finding it difficult to keep up with her homework recently.",exp:"Never call a student 'lazy' to parents. 'Finding it difficult' is empathetic. 'Recently' suggests this is changeable, not permanent. Huge cultural difference from Chinese directness."},
        {id:"pc005",type:"fill",q:"I'm reaching out because I've noticed a ___ in Jake's engagement in class over the past two ___.",a:"change ... weeks",exp:"'Noticed a change' is neutral — it could be positive or negative. 'Over the past two weeks' is specific. Opening with observation rather than judgement."},
        {id:"pc006",type:"mc",q:"A parent is upset about their child's grade. What is the best first response?",options:["The grade is fair. Your child didn't do the work.","I understand this is disappointing. Let me walk you through the assessment criteria and show you specifically where the gaps are.","Grades are not my decision — it's the rubric.","Maybe your child should try harder."],a:1,exp:"Validate the emotion ('I understand'). Then provide objective evidence (criteria, specifics). This approach is professional, empathetic, and evidence-based."},
        {id:"pc007",type:"fill",q:"I'd like to ___ a meeting to discuss how we can best ___ Priya's learning needs.",a:"arrange ... support",exp:"'Arrange a meeting' is professional. 'Support Priya's learning needs' focuses on the student and positions the teacher and parent as a team."},
        {id:"pc008",type:"error",q:"I suggest that your child should see a psychologist because he have many behaviour problems.",a:"I have noticed that Max has been finding some social situations challenging. I would like to discuss whether additional support might be helpful for him.",exp:"Never diagnose or recommend specific professionals directly. 'Finding social situations challenging' is sensitive. 'Additional support' is the appropriate school term. Let the school counsellor make referrals."},
        {id:"pc009",type:"fill",q:"We've been working with Hannah on her time ___ skills, and she's starting to show real ___.",a:"management ... progress",exp:"'Time management skills' names a specific area. 'Starting to show real progress' is encouraging and suggests ongoing growth."},
        {id:"pc010",type:"mc",q:"What does 'learning support' mean in an Australian school context?",options:["Extra homework","Specialised help for students with additional learning needs","A punishment for poor performance","Advanced classes for gifted students"],a:1,exp:"'Learning support' refers to additional assistance for students who need help with their learning. It includes adjustments, extra time, modified tasks, and specialist teacher input."},
        {id:"pc011",type:"fill",q:"I understand your ___ and I want to assure you that we are taking this matter very ___.",a:"concern ... seriously",exp:"'I understand your concern' validates the parent. 'Taking it seriously' assures them of action. Standard response to a parental complaint."},
        {id:"pc012",type:"error",q:"Your son fight with another boy at lunch time. He must control his temper.",a:"I wanted to let you know about an incident at lunchtime involving your son and another student. We have spoken to both boys and are working with them on conflict resolution.",exp:"Avoid one-sided blame. 'An incident involving' is neutral. 'Working on conflict resolution' shows a constructive approach. Never tell parents to 'control' their child's emotions."},
        {id:"pc013",type:"fill",q:"Please feel free to ___ out to me at any time if you have questions or ___.",a:"reach ... concerns",exp:"'Feel free to reach out' is a warm, open invitation. 'Questions or concerns' covers all bases. Standard professional closing for parent emails."},
        {id:"pc014",type:"open",q:"Write an email to parents about an upcoming excursion.",a:"Dear Year 8 Families, I am writing to let you know about an exciting excursion for the Year 8 Science class. On Thursday 20 March, we will be visiting the Australian Museum in Sydney to support our current unit on ecosystems and biodiversity. Students will need to wear full school uniform and bring a packed lunch and a water bottle. The cost is $15 per student, which covers transport and entry. Please complete and return the permission slip by Monday 10 March. If you have any questions, please do not hesitate to contact me. Kind regards, Yunshu Gao",exp:"Clear, organised, includes all essential information: date, destination, purpose, requirements, cost, deadline. Professional but warm tone."},
        {id:"pc015",type:"fill",q:"I'd like to work ___ with you to develop a ___ that supports Emily's needs both at school and at home.",a:"together ... plan",exp:"'Work together' = partnership. 'Develop a plan' is proactive and solution-focused. This frames the teacher-parent relationship collaboratively."},
        {id:"pc016",type:"mc",q:"When is it appropriate to contact parents by phone rather than email?",options:["Never — always use email","For urgent matters or sensitive issues that need a personal touch","Whenever you feel like it","Only when the principal tells you to"],a:1,exp:"Phone calls are best for urgent/sensitive matters (injuries, serious incidents). The personal touch conveys care. Email is better for routine updates and documentation."},
        {id:"pc017",type:"fill",q:"Thank you for bringing this to my ___. I will ___ into it and get back to you by the end of the week.",a:"attention ... look",exp:"'Bringing to my attention' = informing me. 'Look into it' = investigate. Committing to a timeline ('end of the week') builds trust."},
        {id:"pc018",type:"error",q:"Your child academic performance is very low. He needs to study more harder.",a:"Your child's academic performance has room for improvement. With some additional effort and support, I believe he can make strong progress.",exp:"'Child's' needs possessive. 'Room for improvement' replaces 'very low'. 'More harder' is incorrect — 'harder' is already comparative. Positive framing is essential in Australian parent communication."},
        {id:"pc019",type:"fill",q:"I'm pleased to let you know that Tom has been ___ for the Young Leaders ___ this term.",a:"selected ... programme",exp:"'Selected for' = chosen. 'Programme' (Australian spelling). Sharing good news strengthens the home-school connection."},
        {id:"pc020",type:"mc",q:"What should you always do after a difficult parent conversation?",options:["Forget about it and move on","Document what was discussed and any agreed actions","Complain to colleagues about the parent","Send the parent a strongly worded follow-up email"],a:1,exp:"Documentation protects both the teacher and the student. Record the date, attendees, key points discussed, and agreed next steps. This is standard professional practice."},
        {id:"pc021",type:"fill",q:"We believe that with the right ___, Sophia can achieve her full ___.",a:"support ... potential",exp:"'Right support' and 'full potential' are positive, aspirational phrases that parents respond well to. This communicates belief in the student."},
        {id:"pc022",type:"error",q:"I want to inform you that your child absent three day this week without no reason.",a:"I would like to inform you that your child was absent for three days this week without an explanation.",exp:"'Would like' (more polite). 'Was absent' (past tense). 'Three days' (plural). 'Without an explanation' (double negative 'without no' is incorrect). Multiple errors common for Chinese speakers."},
        {id:"pc023",type:"open",q:"Write a brief positive note to go home with a student who had a great day.",a:"Dear Mr and Mrs Lee, I just wanted to let you know that Wei had an outstanding day today. He volunteered to help a classmate who was struggling with the task, and his presentation to the class was confident and well-prepared. You should be very proud of him. Kind regards, Ms Gao",exp:"Short, specific, positive. Names the behaviours observed. 'You should be very proud' connects the school success to the family. These notes are powerful for building relationships."},
        {id:"pc024",type:"fill",q:"I've ___ some additional resources that you and Amira can use at home to ___ her reading skills.",a:"prepared ... build",exp:"Providing take-home resources shows proactive support. 'Build her reading skills' is positive and constructive."},
        {id:"pc025",type:"mc",q:"What is the best approach when a parent disagrees with your teaching method?",options:["Tell them you're the professional and they should trust you","Listen to their perspective, explain your reasoning, and find common ground","Immediately change your approach to please them","Refer them to the principal without discussing it"],a:1,exp:"Listening first, then explaining with evidence, then finding common ground. Parents have valid perspectives. Professional communication means dialogue, not defence."},
        {id:"pc026",type:"fill",q:"I look forward to ___ you at the parent-teacher ___ next Thursday.",a:"seeing ... evening",exp:"'Seeing you at the parent-teacher evening' is a standard invitation closing. 'Parent-teacher evening' (or 'night') is the Australian term for these events."},
        {id:"pc027",type:"error",q:"I am worry about your son's attendance. He has been absent many time recently.",a:"I am worried about your son's attendance. He has been absent many times recently.",exp:"'Worried' (past participle as adjective, not base form). 'Many times' (countable, needs plural). 'Worry' vs 'worried' confusion is common for Chinese speakers."},
        {id:"pc028",type:"fill",q:"I'd be happy to ___ a time for us to meet and discuss how we can continue to ___ Daniel's growth.",a:"organise ... nurture",exp:"'Organise a time' (Australian spelling). 'Nurture growth' is warm and professional. 'Continue to' suggests ongoing partnership."},
        {id:"pc029",type:"open",q:"Write an email informing parents about a change to the school's homework policy.",a:"Dear Year 9 Families, I am writing to let you know about a change to our homework expectations for Term 2. Based on current research and feedback from students and families, we will be moving to a flexible homework model. Students will receive a weekly task list rather than daily assignments, allowing them to manage their own time and balance extracurricular commitments. The quality and completion of homework will still be monitored, and I will provide feedback each week. If you have any questions about this change, please feel free to contact me. Kind regards, Yunshu Gao",exp:"Explain the change, the reason for it (research + feedback), what it looks like in practice, and how quality will be maintained. Invite questions. Professional and transparent."},
        {id:"pc030",type:"fill",q:"We would like to ___ you to our annual showcase evening, where students will be ___ their projects from this term.",a:"invite ... presenting",exp:"'Invite you to' the event. 'Presenting their projects' — student showcase events are a key part of Australian school community engagement."},
        {id:"pc031",type:"mc",q:"Which phrase is best for ending a difficult parent email?",options:["I hope you understand.","Please let me know if you would like to discuss this further. I am committed to supporting your child's success.","Don't contact me about this again.","That's my final word on the matter."],a:1,exp:"Keeping the door open and reaffirming commitment to the student. This prevents the conversation from feeling closed or adversarial."},
        {id:"pc032",type:"error",q:"We are very happy with your daughter progress. She is improve very quick.",a:"We are very happy with your daughter's progress. She is improving very quickly.",exp:"'Daughter's progress' (possessive). 'Is improving' (present continuous). 'Quickly' (adverb form). Three common Chinese speaker errors in one sentence."},
        {id:"pc033",type:"fill",q:"As a follow-up to our conversation, I've ___ the school counsellor, who will ___ out to you directly.",a:"contacted ... reach",exp:"'As a follow-up' connects to a prior conversation. 'Contacted the counsellor' shows action taken. 'Reach out to you' = contact you. Following through on promises builds trust."},
        {id:"pc034",type:"fill",q:"Your son's ___ to class has been exceptional this term. He consistently ___ a positive attitude.",a:"contribution ... demonstrates",exp:"'Contribution to class' acknowledges active participation. 'Demonstrates a positive attitude' is professional feedback language."},
        {id:"pc035",type:"mc",q:"What should you do if a parent sends an angry email late at night?",options:["Reply immediately while the emotions are fresh","Wait until the next morning, re-read it calmly, and compose a measured response","Forward it to the whole staff","Ignore it completely"],a:1,exp:"Never respond to angry emails immediately. Waiting allows emotions to settle. A calm, measured response the next day is more professional and less likely to escalate the situation."},
        {id:"pc036",type:"fill",q:"I want to assure you that your child's ___ and learning are our top ___.",a:"wellbeing ... priorities",exp:"'Wellbeing and learning' covers both emotional and academic support. 'Top priorities' reassures parents that their child matters. Standard parent communication language."},
        {id:"pc037",type:"error",q:"Your daughter need to wear correct uniform to school. If she not wear uniform, she will get detention.",a:"Your daughter needs to wear the correct uniform to school. If she does not wear her uniform, there will be a consequence.",exp:"'Needs' (third person). 'The correct uniform' (specific). 'Does not wear' (auxiliary needed). 'Consequence' is more professional than 'detention' in parent communication."},
        {id:"pc038",type:"fill",q:"We are holding a ___ session for parents on cybersafety next Thursday evening. I strongly encourage you to ___.",a:"information ... attend",exp:"'Information session' = an event to inform parents. 'Strongly encourage' is professional persuasion without being demanding."},
        {id:"pc039",type:"mc",q:"What should you never do when communicating with parents?",options:["Use professional language","Share the student's grades with the parent","Compare their child negatively to other students","Offer to meet in person"],a:2,exp:"Never compare a child to their peers in parent communication. It violates privacy and damages trust. Focus on the individual student's progress and potential."},
        {id:"pc040",type:"fill",q:"I appreciate your ___ in raising this concern. Working ___ is the best way to support your child's success.",a:"openness ... together",exp:"'Appreciate your openness' validates the parent's courage in raising an issue. 'Working together' reinforces the partnership model."}
      ]
    },
    {
      id: "reporting-updates",
      title: "Reports & Updates to Colleagues",
      theory: "Professional reporting in Australian schools involves clear, concise updates to colleagues about student progress, incidents, program updates, and administrative matters. Use formal-but-approachable tone. Structure reports with dot points for clarity. Always distinguish between observations (what you saw) and interpretations (what you think it means).",
      exercises: [
        {id:"ru001",type:"fill",q:"I'd like to ___ you all on the Year 7 assessment results from last ___.",a:"update ... week",exp:"'Update you all on' is the standard meeting/email opener for sharing new information. Direct and professional."},
        {id:"ru002",type:"mc",q:"Which is the best way to report a student welfare concern to the year adviser?",options:["I think something's wrong with Sarah but I'm not sure what.","I've noticed Sarah has been withdrawn and tearful in my last three lessons. She hasn't completed any work and seems reluctant to interact with peers.","Sarah's being weird lately.","Sarah's probably got problems at home."],a:1,exp:"Report specific, observable behaviours (withdrawn, tearful) with frequency (last three lessons) and impact (not completing work). Avoid speculation ('problems at home') and vague language ('weird')."},
        {id:"ru003",type:"fill",q:"Just a quick update: the new ___ have arrived and are ready to be ___ to classes.",a:"textbooks ... distributed",exp:"'Quick update' signals brief information. 'Distributed to classes' = given out. Administrative updates keep the team informed."},
        {id:"ru004",type:"error",q:"The student behaviour in my class is very bad this week. I think maybe is because of the hot weather.",a:"Student behaviour in my classes has been challenging this week. I suspect the hot weather may be a contributing factor.",exp:"'Has been challenging' is more professional than 'very bad'. 'I suspect' + 'may be a contributing factor' is measured professional language. Remove 'maybe is' — incomplete sentence structure."},
        {id:"ru005",type:"fill",q:"I've ___ a significant improvement in student ___ since we introduced the new merit system.",a:"noticed ... engagement",exp:"'Noticed a significant improvement' reports an observation. 'Student engagement' is a key educational metric in Australian schools."},
        {id:"ru006",type:"mc",q:"When writing an incident report, what should you include?",options:["Your personal opinion about who was to blame","Only the facts: who, what, when, where, and what actions were taken","A detailed emotional account of how it made you feel","Your recommendation for expulsion"],a:1,exp:"Incident reports must be factual and objective. Include: date/time, location, people involved, what happened (observed, not interpreted), and what action was taken."},
        {id:"ru007",type:"fill",q:"For your ___, I've attached the updated scope and sequence for Term 2. Please ___ any changes highlighted in yellow.",a:"reference ... note",exp:"'For your reference' = for your information/records. 'Note any changes' = pay attention to. Polite, professional information sharing."},
        {id:"ru008",type:"error",q:"I want to let everyone know the computer room will be close for renovation next week.",a:"I wanted to let everyone know that the computer room will be closed for renovation next week.",exp:"'Wanted' (past tense is softer). 'Will be closed' (passive, not active). 'That' improves clarity after 'know'. 'Closed' not 'close'."},
        {id:"ru009",type:"fill",q:"The data ___ that our Year 9 cohort has improved by 15% in ___ this semester.",a:"shows ... literacy",exp:"'The data shows' (reporting evidence). 'Improved by 15% in literacy' is specific and measurable. Data-driven reporting is valued in Australian schools."},
        {id:"ru010",type:"mc",q:"What is a 'welfare referral' in an Australian school?",options:["A referral to a fitness program","A formal notification to the school counsellor or wellbeing team about a student of concern","A letter to the parents","A detention slip"],a:1,exp:"Welfare referrals flag students who may need emotional, social, or psychological support. They go to the wellbeing team, school counsellor, or year adviser. This is a critical safety net in Australian schools."},
        {id:"ru011",type:"fill",q:"As ___ at the last faculty meeting, I've completed the audit of our assessment ___ for Year 10.",a:"requested ... tasks",exp:"'As requested' references a prior action item. 'Audit of assessment tasks' = systematic review. Following up on agreed actions shows professionalism."},
        {id:"ru012",type:"error",q:"The meeting minutes is attached. Please to read it before the next meeting.",a:"The meeting minutes are attached. Please read them before the next meeting.",exp:"'Minutes are' (plural noun). 'Read them' (plural pronoun). 'Please read' (no 'to' after 'please' + imperative). 'Minutes' as a record is always plural."},
        {id:"ru013",type:"fill",q:"I wanted to ___ to the team that three students in my Year 8 class have been ___ to learning support.",a:"flag ... referred",exp:"'Flag to the team' = bring to attention. 'Referred to learning support' = formally directed to additional services. Key reporting language."},
        {id:"ru014",type:"open",q:"Write a brief email update to your head of department about how a new teaching strategy is going.",a:"Hi David, Just a quick update on the collaborative learning strategy we trialled in Week 3. So far, I have used it in three Year 9 lessons. Student engagement has noticeably increased — the quieter students are participating more, and the quality of group discussions has improved. One challenge is that transitions between activities take longer than expected, so I am working on tightening up my timing. I will continue to trial it next week and report back with more detailed observations. Let me know if you would like to come and observe a lesson. Cheers, Yunshu",exp:"Structured update: what was trialled, results so far, challenges identified, next steps. Offering observation shows openness to feedback. 'Cheers' is fine for a close colleague."},
        {id:"ru015",type:"fill",q:"The ___ rate for homework in my Year 7 class has dropped from 85% to 60% over the past ___ weeks.",a:"completion ... four",exp:"Reporting specific data (percentages, timeframes) makes concerns concrete and actionable. This data-driven approach is expected in Australian schools."},
        {id:"ru016",type:"mc",q:"What is the best way to share student data with colleagues?",options:["Post it on the staffroom noticeboard","Share via a secure school platform with appropriate access controls","Email it to the whole school","Discuss it openly at lunch with names included"],a:1,exp:"Student data must be shared securely and only with staff who need to know. Privacy legislation (the Privacy Act) governs how schools handle student information in Australia."},
        {id:"ru017",type:"fill",q:"I'd like to ___ that we review our approach to differentiation in the upcoming faculty ___.",a:"suggest ... meeting",exp:"'Suggest that we review' is a professional way to raise an agenda item. 'Faculty meeting' is the regular department meeting in Australian schools."},
        {id:"ru018",type:"error",q:"I am writing to report that a incident occurred in my class today. One student push another student.",a:"I am writing to report that an incident occurred in my class today. One student pushed another student.",exp:"'An incident' (vowel sound). 'Pushed' (past tense). Incident reports must use past tense for completed events. Article and tense errors are common for Chinese speakers."},
        {id:"ru019",type:"fill",q:"Please be ___ that the assessment due date has been ___ to Friday 28 March.",a:"advised ... extended",exp:"'Please be advised' is formal notification language. 'Extended to' = deadline moved later. Used in official school communications."},
        {id:"ru020",type:"mc",q:"What does 'KLA' stand for in Australian education?",options:["Key Learning Area","Keep Learning Always","Kids Learning Activities","Knowledge and Literacy Assessment"],a:0,exp:"KLA = Key Learning Area. The main subject areas in the Australian/NSW curriculum (e.g., English, Mathematics, Science, HSIE, TAS, PDHPE, CAPA). Essential professional terminology."},
        {id:"ru021",type:"fill",q:"The student ___ survey results indicate that 78% of students feel ___ in their learning environment.",a:"wellbeing ... safe",exp:"'Wellbeing survey' (Australian spelling) is a regular school data collection. Reporting survey results is a common professional task."},
        {id:"ru022",type:"error",q:"According the latest data, our attendance rate have improve significantly.",a:"According to the latest data, our attendance rate has improved significantly.",exp:"'According to' (requires preposition). 'Rate has' (singular). 'Has improved' (present perfect with 'significantly'). Three common errors."},
        {id:"ru023",type:"fill",q:"I've ___ a summary of the key takeaways from the professional development day. The main ___ were...",a:"prepared ... themes",exp:"'Prepared a summary' shows initiative. 'Key takeaways' and 'main themes' are standard reporting vocabulary."},
        {id:"ru024",type:"open",q:"Write a brief handover note for a casual (relief) teacher covering your class.",a:"Hi, Thank you for covering my Year 8 Technology class today. The lesson is already prepared — students know what to do. The lesson slides are on the classroom computer desktop in a folder called 'Week 6'. Students should complete the design task worksheet (copies are on my desk). Seating plan is on the wall. A few students to keep an eye on: Jack (Row 3) can be off-task — a quiet word usually works. Mia (front table) has anxiety — please check in with her if she seems overwhelmed. If you have any issues, the teacher next door (Room 12, Mr Peters) can help. Thanks again. Yunshu Gao",exp:"Good handover notes include: lesson plan location, materials, seating plan, student information (behaviour/welfare), and emergency contact. Be specific and supportive."},
        {id:"ru025",type:"fill",q:"The annual school ___ will be published next week. All staff contributions are due by ___.",a:"report ... Friday",exp:"'Annual school report' is the public document summarising the school's achievements. Staff often contribute sections about their KLA."},
        {id:"ru026",type:"mc",q:"What should you do before escalating a student issue to the deputy principal?",options:["Nothing — go straight to the deputy","Document the issue, the strategies you have tried, and their outcomes","Complain to your colleagues first","Wait until the problem goes away"],a:1,exp:"Documentation of attempted strategies is essential before escalation. It shows you have tried to resolve the issue at your level and provides evidence for the next steps."},
        {id:"ru027",type:"fill",q:"I'm writing to ___ that we have successfully completed the NESA ___ for our Year 11 program.",a:"confirm ... audit",exp:"'Confirm' = officially verify. 'NESA audit' = NSW Education Standards Authority review. Understanding regulatory processes is part of professional competence."},
        {id:"ru028",type:"error",q:"All teacher must attend the meeting on Monday. It will start at 3:15pm sharp.",a:"All teachers must attend the meeting on Monday. It will start at 3:15 p.m. sharp.",exp:"'Teachers' (plural). 'P.m.' is the standard Australian/British formatting. 'Sharp' means exactly at that time. Chinese speakers often forget plurals."},
        {id:"ru029",type:"fill",q:"The ___ indicates that students perform better when given regular, ___ feedback on their progress.",a:"research ... constructive",exp:"'The research indicates' is evidence-based language. 'Constructive feedback' = helpful, specific suggestions for improvement. Key educational vocabulary."},
        {id:"ru030",type:"open",q:"Write a brief end-of-term summary for your head of department about your Year 7 class.",a:"Year 7 Technology — Term 1 Summary: The class completed the Engineering and Sustainable Design unit. Key achievements: all students submitted their design portfolio, and the average grade was a B. Student engagement was high throughout the practical activities. Areas for improvement: some students struggled with the written reflection component, particularly in articulating their design decisions. I plan to introduce sentence starters and scaffold templates next term to address this. Three students were referred to learning support for additional literacy assistance. Overall, it has been a positive term with strong student growth.",exp:"End-of-term summaries should include: what was covered, achievements, challenges, data, planned improvements, and any referrals. Concise but comprehensive."},
        {id:"ru031",type:"fill",q:"Please find ___ the risk assessment for the Year 9 excursion. I'd appreciate your ___ before I submit it to the principal.",a:"attached ... approval",exp:"Risk assessments are mandatory for excursions in NSW. Having your HoD approve them before submission is standard procedure."},
        {id:"ru032",type:"mc",q:"What is a 'stage' in the NSW education context?",options:["A performance platform","A group of two consecutive year levels (e.g., Stage 4 = Years 7-8)","A unit of work","A testing phase"],a:1,exp:"In NSW: Stage 4 = Years 7-8, Stage 5 = Years 9-10, Stage 6 = Years 11-12. Understanding stage groupings is essential for curriculum alignment and professional communication."},
        {id:"ru033",type:"error",q:"I have been observe that many student in my class need extra support with their writing skill.",a:"I have observed that many students in my class need extra support with their writing skills.",exp:"'Have observed' (present perfect, not 'been observe'). 'Students' (plural). 'Skills' (plural). Professional observation language."},
        {id:"ru034",type:"fill",q:"As part of our ongoing ___ improvement, I've identified three areas where we can ___ our practice.",a:"school ... strengthen",exp:"'School improvement' is the formal term for whole-school development. 'Strengthen our practice' is positive professional language."},
        {id:"ru035",type:"fill",q:"The ___ for the new elective course has been ___ by the curriculum committee.",a:"proposal ... approved",exp:"'Proposal approved by' — passive voice is appropriate for formal reporting. 'Curriculum committee' is the school body that oversees course offerings."},
        {id:"ru036",type:"error",q:"I want to report the class attendance. This week many students absent and the rate is decrease.",a:"I would like to report on class attendance this week. Several students have been absent, and the attendance rate has decreased.",exp:"'Report on' (preposition needed). 'Several students' (more specific than 'many'). 'Have been absent' (present perfect). 'Has decreased' (present perfect — change over time)."},
        {id:"ru037",type:"fill",q:"The key ___ from this term's data are summarised in the table below. Overall, we are trending in a ___ direction.",a:"findings ... positive",exp:"'Key findings' = main conclusions from data. 'Trending in a positive direction' = improving. Professional data reporting language."},
        {id:"ru038",type:"fill",q:"I'd like to flag a ___ regarding student welfare. Three students in my class have shown signs of ___ this week.",a:"concern ... distress",exp:"'Flag a concern' = raise an issue for attention. 'Signs of distress' describes observable behaviour without diagnosing. Appropriate welfare reporting language."},
        {id:"ru039",type:"mc",q:"What is the correct way to report student data to colleagues?",options:["Share names freely in the staffroom","Use de-identified data when possible and share names only with relevant staff","Post it on the school noticeboard","Discuss it in front of students"],a:1,exp:"Student data privacy is protected by law in Australia. Use de-identified data (percentages, trends) broadly. Share names only with staff who need to know (year adviser, counsellor)."},
        {id:"ru040",type:"fill",q:"To ___ up the term, I would say that the programme has been a success, with ___ completion rates above 90%.",a:"sum ... student",exp:"'Sum up the term' = provide a final summary. 'Student completion rates above 90%' is specific, measurable evidence of success."}
      ]
    }
  ]
},
// ============================================================
// MODULE 3: STAFFROOM SMALL TALK & SOCIAL ENGLISH
// ============================================================
staffroomTalk: {
  title: "Staffroom Small Talk & Social English",
  sections: [
    {
      id: "greetings-openers",
      title: "Greetings & Conversation Openers",
      theory: "Australian staffroom culture is very social. Small talk is not 'wasting time' — it builds professional relationships and trust. Common openers reference weekends, weather, students, and shared experiences. The key Australian cultural value is being approachable and 'down to earth'. Chinese speakers may feel small talk is unnecessary or uncomfortable, but in Australia it is essential for belonging.",
      exercises: [
        {id:"go001",type:"fill",q:"Morning, Sarah! How was your ___? Did you get up to ___ much?",a:"weekend ... anything",exp:"'How was your weekend?' is the #1 Monday morning conversation opener in Australian workplaces. 'Get up to anything' = do anything interesting. Very casual."},
        {id:"go002",type:"mc",q:"A colleague says 'How are you going?' What is the expected response?",options:["I am going to the staffroom.","Good thanks, how about you?","I am fine thank you and you?","I have no problems."],a:1,exp:"'How are you going?' is the Australian version of 'How are you?' The natural response is 'Good thanks, how about you?' — short and warm. 'I am fine thank you and you?' sounds overly formal."},
        {id:"go003",type:"fill",q:"Can you ___ it's already Week 6? This term is ___ by!",a:"believe ... flying",exp:"'Can you believe...' expresses shared surprise. 'Flying by' = going very fast. This is a classic staffroom conversation opener about how fast the term is going."},
        {id:"go004",type:"error",q:"How do you do? I am very glad to meet you.",a:"Hi! Nice to meet you. I'm Yunshu — I teach Technology.",exp:"'How do you do' is extremely formal and outdated in Australian English. 'Hi! Nice to meet you' + your name + your role is natural and warm. Chinese textbooks often teach overly formal greetings."},
        {id:"go005",type:"fill",q:"Hey, have you ___ the new café that opened near the school? The coffee is ___!",a:"tried ... amazing",exp:"Recommending local food/coffee is a classic Australian conversation topic. 'Have you tried...?' is a natural opener. Australians take coffee very seriously!"},
        {id:"go006",type:"mc",q:"What does 'Not bad' mean as a response to 'How are you?'",options:["I'm feeling terrible","I'm OK — things are going reasonably well","I'm upset but trying to hide it","I'm neither good nor bad"],a:1,exp:"'Not bad' is classic Australian understatement. It usually means 'quite good, actually'. Australians often downplay positives. 'Not bad at all' is even more positive."},
        {id:"go007",type:"fill",q:"Long time no see! How have you ___? I haven't ___ you since the PD day.",a:"been ... seen",exp:"'Long time no see' is informal but widely used. 'How have you been?' asks about the period since you last spoke. 'Haven't seen you since...' provides context."},
        {id:"go008",type:"error",q:"Today weather is very hot. I think maybe will rain later.",a:"It's boiling today, isn't it? I reckon it might rain later.",exp:"'It's boiling' (more natural than 'very hot'). Australian English uses 'it' as a dummy subject for weather. 'I reckon' (very Australian for 'I think'). 'Might' (possibility, more natural than 'maybe will')."},
        {id:"go009",type:"fill",q:"Happy Friday, everyone! ___ exciting plans for the ___?",a:"Any ... weekend",exp:"'Happy Friday' is a common end-of-week greeting in Australian workplaces. Asking about weekend plans is a standard social conversation."},
        {id:"go010",type:"mc",q:"A new staff member joins. What is the best opening line?",options:["Who are you?","Hi there! Welcome to the team. I'm Yunshu — I teach Technology. How are you settling in?","You must be the new person.","Are you lost?"],a:1,exp:"Warm, welcoming, introduces yourself, asks about their experience. 'How are you settling in?' shows genuine interest. Australians value making newcomers feel included."},
        {id:"go011",type:"fill",q:"I'm absolutely ___ today. I had Year 9 last period and they were ___!",a:"exhausted ... wild",exp:"Sharing how tired you are is a bonding topic in teaching. 'Absolutely exhausted' is emphatic. 'They were wild' = very energetic/difficult. Humour helps."},
        {id:"go012",type:"error",q:"Are you free in this weekend? We can go have a coffee together.",a:"Are you free this weekend? We could go for a coffee together.",exp:"'This weekend' (no 'in'). 'Could go for a coffee' (suggestion form; 'go for a coffee' is the Australian phrase, not 'go have')."},
        {id:"go013",type:"fill",q:"Did you catch the ___ last night? That game was ___!",a:"footy ... incredible",exp:"'The footy' (AFL or NRL depending on the state) is Australia's most popular conversation topic. Even if you don't follow it, knowing the language helps you connect."},
        {id:"go014",type:"open",q:"A colleague asks 'How was your holiday?' Write a natural response about a trip to the Blue Mountains.",a:"Oh, it was lovely, thanks! We drove up to the Blue Mountains for a couple of days. The weather was perfect and we did the Three Sisters walk — have you done that one? The views were stunning. It was so nice to just switch off for a bit. How about you — did you get away anywhere?",exp:"Natural response: brief details, enthusiasm, a question back. 'Switch off' = relax and not think about work. Always reciprocate by asking about them."},
        {id:"go015",type:"fill",q:"I'm ___ for a coffee. Does anyone want me to ___ them one?",a:"gagging ... grab",exp:"'Gagging for a coffee' = desperately want one (informal). 'Grab you one' = get/buy one for you. Very common staffroom offer in Australia."},
        {id:"go016",type:"mc",q:"What does 'How's things?' mean?",options:["How are your physical possessions?","How is everything going in general?","What things do you have?","Can you count your belongings?"],a:1,exp:"'How's things?' is informal Australian for 'How's everything going?' It's grammatically incorrect (should be 'How are things?') but very common in casual speech."},
        {id:"go017",type:"fill",q:"That's a nice jacket! Is it ___? I've been meaning to get a new one ___.",a:"new ... myself",exp:"Complimenting clothing is a safe, friendly conversation opener. 'Is it new?' shows interest. 'Meaning to' = planning/intending to."},
        {id:"go018",type:"error",q:"I heard you are sick last week. Are you feeling more better now?",a:"I heard you were sick last week. Are you feeling better now?",exp:"'Were sick' (past tense for last week). 'Better' is already comparative — 'more better' is a double comparative error. Very common for Chinese speakers."},
        {id:"go019",type:"fill",q:"What a ___! I can't believe how much we got done in that ___.",a:"day ... meeting",exp:"'What a day!' expresses shared experience. This opener invites the other person to agree and share their own experience."},
        {id:"go020",type:"mc",q:"What does 'arvo' mean in Australian English?",options:["A type of food","Afternoon","An argument","A holiday"],a:1,exp:"'Arvo' = afternoon. Very common in Australian slang. 'This arvo' = this afternoon. Other common shortenings: 'brekkie' (breakfast), 'servo' (petrol station), 'ambo' (ambulance)."},
        {id:"go021",type:"fill",q:"I'm so glad it's nearly the ___. I really need a ___ from the kids!",a:"holidays ... break",exp:"Teachers bonding over needing a break is universal! 'Glad it's nearly the holidays' is a classic end-of-term staffroom phrase."},
        {id:"go022",type:"error",q:"Excuse me, do you have a minute? I want to chat you about something.",a:"Excuse me, do you have a minute? I want to chat to you about something.",exp:"'Chat to you' (not 'chat you'). 'Chat' requires a preposition before the person: 'chat to', 'chat with'. Chinese 聊你 doesn't need a preposition."},
        {id:"go023",type:"fill",q:"You look a bit ___. Everything alright? Do you want to ___ about it?",a:"down ... talk",exp:"Checking on a colleague's wellbeing is important. 'Look a bit down' = seem sad. 'Want to talk about it?' offers support without being pushy."},
        {id:"go024",type:"open",q:"A colleague mentions they're training for a marathon. Write a natural follow-up response.",a:"Oh wow, that is impressive! How long have you been training for? Which marathon is it — the Sydney one? I have always wanted to try running but I never seem to find the time. What got you into it?",exp:"Show genuine interest, ask follow-up questions, relate it to yourself briefly, then redirect back to them. This is the pattern of natural conversation."},
        {id:"go025",type:"fill",q:"Have you heard the ___? Apparently the principal is ___ at the end of the term.",a:"news ... retiring",exp:"Staffroom news/gossip is social currency. 'Have you heard?' is the standard opener for sharing news. 'Apparently' signals it may not be confirmed."},
        {id:"go026",type:"mc",q:"What is 'banter' in Australian workplace culture?",options:["Serious argument","Playful, friendly teasing between colleagues","Formal discussion","Gossip about someone behind their back"],a:1,exp:"Banter is light, humorous teasing that builds camaraderie. It is a big part of Australian culture. The key is that it's mutual, affectionate, and never mean-spirited."},
        {id:"go027",type:"fill",q:"I'm thinking of ___ Korean tonight. Do you know any good ___ around here?",a:"ordering ... places",exp:"Food is a universal conversation topic. 'Ordering Korean' = getting Korean takeaway food. 'Any good places around here?' asks for recommendations."},
        {id:"go028",type:"error",q:"Thank you very much for invite me to your party last weekend. I enjoyed very much.",a:"Thanks so much for inviting me to your party last weekend. I really enjoyed it.",exp:"'For inviting' (gerund after preposition). 'Really enjoyed it' needs 'it' as object. 'Thanks so much' is more natural than 'Thank you very much' in casual conversation."},
        {id:"go029",type:"fill",q:"Is it just me, or is this ___ going really slowly? I feel like Friday is ___ away.",a:"week ... ages",exp:"'Is it just me, or...' invites agreement. 'Ages away' = very far in the future. Shared complaints about the week are bonding experiences!"},
        {id:"go030",type:"open",q:"You bump into a colleague in the corridor between lessons. Write a brief, natural exchange.",a:"Oh hey, Mark! How is your day going? Crazy morning — I had a Year 9 class that would not sit still. Anyway, are you coming to the staff drinks on Friday? A few of us are heading to the pub after school. It would be great to see you there!",exp:"Brief, energetic, a quick shared experience, then a social invitation. This is natural corridor chat — you don't have time for a long conversation between lessons."},
        {id:"go031",type:"fill",q:"Sorry, I didn't ___ that. Could you say it ___?",a:"catch ... again",exp:"'Didn't catch that' = didn't hear/understand. Very natural and non-embarrassing way to ask someone to repeat themselves. Better than 'What?' or 'Pardon?'"},
        {id:"go032",type:"error",q:"How are you? I am fine, thank you, and you?",a:"How are you? Good thanks, how about you?",exp:"The textbook response 'I am fine thank you and you' sounds robotic. Natural Australian: 'Good thanks, how about you?' or 'Not bad, yourself?'. Chinese textbooks teach overly formal greetings."},
        {id:"go033",type:"fill",q:"I bumped ___ Rachel at the shops yesterday. Small ___, right?",a:"into ... world",exp:"'Bumped into' = met unexpectedly. 'Small world' = what a coincidence. Both are casual conversation phrases."},
        {id:"go034",type:"mc",q:"A colleague says 'TGIF!' What does this mean?",options:["The Game Is Fun","Thank God It's Friday","Teachers Get Inspected Friday","That's Good Information, Friend"],a:1,exp:"TGIF = Thank God It's Friday. Said when people are relieved the working week is ending. Very common in Australian workplaces on Friday afternoons."},
        {id:"go035",type:"fill",q:"Hey, I haven't seen you in ___! Where have you ___?",a:"ages ... been",exp:"'In ages' = for a long time. 'Where have you been?' asks what they've been up to. Very casual, warm greeting after not seeing someone."},
        {id:"go036",type:"open",q:"A colleague walks into the staffroom looking stressed. Write a natural greeting and check-in.",a:"Oh hey, you look like you have had a rough morning. Are you alright? Do you want a coffee? I am about to make one. Sometimes you just need five minutes to breathe, hey?",exp:"Acknowledge their state, offer practical help (coffee), normalise taking a break. 'Hey?' at the end is very Australian — it invites agreement."},
        {id:"go037",type:"fill",q:"Did you hear? Apparently they're going to ___ the staffroom. About time — those chairs are ___!",a:"renovate ... ancient",exp:"Sharing school news/gossip is bonding. 'About time' = it should have happened long ago. 'Ancient' is humorous hyperbole for old furniture."},
        {id:"go038",type:"error",q:"Nice to meet you. May I know your name please?",a:"Nice to meet you! I'm Yunshu. What's your name?",exp:"'May I know your name' is overly formal Chinese English (请问你叫什么名字). Australian style: introduce yourself first, then ask. More natural and warm."},
        {id:"go039",type:"fill",q:"You look like you could use a ___. Rough day with the ___?",a:"break ... kids",exp:"'Could use a break' = really need a break. 'Rough day with the kids' = difficult day with students. Empathetic, casual check-in."}
      ]
    },
    {
      id: "responding-naturally",
      title: "Responding Naturally in Conversations",
      theory: "Natural English responses use fillers (well, you know, I mean), reactions (oh really?, no way!, that's great!), and follow-up questions. Chinese speakers often give very short, closed responses which can seem disinterested. The key is to react, comment, and ask something back to keep the conversation flowing.",
      exercises: [
        {id:"rn001",type:"fill",q:"A: 'I'm thinking of doing a Master's degree.' B: 'Oh ___, that's exciting! What would you ___ in?'",a:"wow ... specialise",exp:"'Oh wow' shows genuine interest. A follow-up question keeps the conversation going. Chinese speakers often just say 'Good' which closes the conversation."},
        {id:"rn002",type:"mc",q:"A colleague tells you their child is sick. What is the most natural response?",options:["OK.","Oh no, that's not good. I hope they feel better soon.","That is a pity.","You should take them to the doctor."],a:1,exp:"'Oh no' shows empathy. 'Hope they feel better soon' is warm and natural. 'That is a pity' is too formal. Giving advice immediately is pushy."},
        {id:"rn003",type:"fill",q:"A: 'The traffic was terrible this morning.' B: 'Tell me about it! It took me ___ an hour just to get to ___.'",a:"over ... school",exp:"'Tell me about it!' = I had the same experience / I completely agree. Adding your own experience creates connection."},
        {id:"rn004",type:"error",q:"A: 'I got promoted!' B: 'That is good.'",a:"A: 'I got promoted!' B: 'Oh, congratulations! That is fantastic! You really deserve it.'",exp:"'That is good' is a very flat response for exciting news. Show enthusiasm: 'Congratulations!', 'Fantastic!', 'You deserve it!' Chinese conversational style is more understated, but English expects matching energy."},
        {id:"rn005",type:"fill",q:"A: 'I went to a great restaurant on the weekend.' B: 'Oh nice! ___ was it? I'm always looking for good ___ recommendations.'",a:"Where ... food",exp:"Follow-up questions (where, what, how) show genuine interest and keep conversation flowing. 'I'm always looking for...' relates it to yourself."},
        {id:"rn006",type:"mc",q:"What does 'Fair enough' mean in Australian English?",options:["That's not fair","I accept/understand your point","You're being too fair","I disagree strongly"],a:1,exp:"'Fair enough' = I accept what you're saying, even if I don't fully agree. It's a very common Australian response that keeps things amicable. Not confrontational at all."},
        {id:"rn007",type:"fill",q:"A: 'I'm going to Bali for the holidays.' B: 'Oh, lucky ___! I've always wanted to go there. How long are you going ___?'",a:"you ... for",exp:"'Lucky you!' expresses friendly envy. 'How long are you going for?' is a natural follow-up. Chinese speakers might just say '很好' (very good) which doesn't continue the conversation."},
        {id:"rn008",type:"error",q:"A: 'I failed my driving test.' B: 'Don't worry. Next time you will pass it surely.'",a:"A: 'I failed my driving test.' B: 'Oh no, that's tough. But don't worry — you'll get it next time for sure.'",exp:"'That's tough' acknowledges the feeling. 'You'll get it next time for sure' is more natural than 'you will pass it surely'. Word order matters."},
        {id:"rn009",type:"fill",q:"A: 'Sorry I'm late.' B: 'No ___ at all! We just got ___.'",a:"worries ... started",exp:"'No worries' is THE classic Australian response. It means 'it's fine, don't apologise'. Very important phrase to master. 'We just got started' reassures them."},
        {id:"rn010",type:"mc",q:"What is the best response when someone says 'Thanks for your help'?",options:["You're welcome.","No worries!","It was nothing special.","Don't mention it — it's my duty."],a:1,exp:"'No worries!' is the most natural Australian response to thanks. 'You're welcome' is fine but slightly more formal. 'It's my duty' is a Chinese English translation (这是我的义务) that sounds odd."},
        {id:"rn011",type:"fill",q:"A: 'The new principal seems really strict.' B: 'Yeah, I ___ what you mean. ___ again, maybe that's what we need.'",a:"know ... Then",exp:"'I know what you mean' validates without fully committing. 'Then again' introduces an alternative perspective. Balanced, thoughtful response."},
        {id:"rn012",type:"error",q:"A: 'Do you want to come to the movies?' B: 'I have no interest in it.'",a:"A: 'Do you want to come to the movies?' B: 'Thanks for the invite, but I might give it a miss this time. What are you going to see?'",exp:"'I have no interest' is very blunt and hurtful. 'Give it a miss' is a gentle Australian way to decline. Asking a question shows you still value the relationship."},
        {id:"rn013",type:"fill",q:"A: 'My students drove me crazy today.' B: 'I hear you! Year 9 were a handful for me too. What happened in ___?'",a:"yours",exp:"'I hear you' = I understand/sympathise. 'A handful' = difficult to manage. Sharing a similar experience and asking for details shows solidarity."},
        {id:"rn014",type:"mc",q:"What does 'I reckon' mean in Australian English?",options:["I am uncertain","I demand","I think/believe","I remember"],a:2,exp:"'I reckon' is one of the most Australian phrases. It means 'I think' or 'I believe'. Very casual. 'I reckon it'll rain today' = 'I think it'll rain today'."},
        {id:"rn015",type:"fill",q:"A: 'I'm thinking of cutting my hair short.' B: 'Go for ___! I think it would really ___ you.'",a:"it ... suit",exp:"'Go for it!' = do it! (encouraging). 'It would suit you' = it would look good on you. Supportive, enthusiastic response."},
        {id:"rn016",type:"error",q:"A: 'How was your holiday?' B: 'It was very good. I went to many place and eat many delicious food.'",a:"A: 'How was your holiday?' B: 'It was amazing! We visited heaps of places and ate some incredible food.'",exp:"'Amazing' is more engaging than 'very good'. 'Heaps of' is Australian for 'lots of'. 'Visited places' and 'ate food' (past tense). 'Incredible food' not 'delicious food' (overused by Chinese speakers)."},
        {id:"rn017",type:"fill",q:"A: 'I just got engaged!' B: 'Oh my ___! Congratulations! I'm so ___ for you! When's the big day?'",a:"goodness ... happy",exp:"Matching the excitement level of the news. 'Oh my goodness!' = surprise/delight. 'When's the big day?' asks about the wedding date."},
        {id:"rn018",type:"open",q:"A colleague tells you they're stressed about an upcoming observation lesson. Write a supportive response.",a:"I totally understand — observations can be so nerve-wracking. But honestly, you are a great teacher and I am sure it will go really well. Is there anything I can help with? I am happy to sit in on a practice run if that would be useful. And remember, they are coming to see a normal lesson, not a performance. Just be yourself.",exp:"Validate the feeling, affirm their ability, offer practical help, and reframe the situation. This is what colleague support looks like in Australian schools."},
        {id:"rn019",type:"fill",q:"A: 'I stayed up until midnight marking.' B: 'Oh, ___ that. You must be ___.'",a:"same ... knackered",exp:"'Same' or 'Same here' shows shared experience. 'Knackered' = extremely tired (very Australian/British informal). Teacher solidarity!"},
        {id:"rn020",type:"mc",q:"Someone spills coffee on your desk. They say 'I'm so sorry!' What do you say?",options:["You should be more careful!","No worries, accidents happen! Let me grab some paper towels.","How could you do this to me?","I forgive you."],a:1,exp:"'No worries, accidents happen' is the perfect Australian response — calm, forgiving, practical. Immediately offering to help ('let me grab paper towels') shows grace."},
        {id:"rn021",type:"fill",q:"A: 'Do you fancy grabbing lunch?' B: 'Yeah, ___ not! I'm ___. Where do you want to go?'",a:"why ... starving",exp:"'Why not!' = yes, sure. 'Starving' = very hungry (hyperbole). Enthusiastic agreement followed by a practical question."},
        {id:"rn022",type:"error",q:"A: 'I think the policy is unfair.' B: 'I am agree with you. It is very unreasonable.'",a:"A: 'I think the policy is unfair.' B: 'I agree with you. It does seem unreasonable.'",exp:"'Agree' is a verb — no 'am' before it (not like Chinese 同意 which can function more flexibly). 'Does seem' is softer than 'is very'. Chinese speakers commonly add 'am/is' before verbs."},
        {id:"rn023",type:"fill",q:"A: 'I accidentally deleted my whole lesson plan.' B: 'Oh no! That's a ___. Can you ___ it from the recycle bin?'",a:"nightmare ... recover",exp:"'That's a nightmare' = that's terrible (sympathetic hyperbole). 'Recover from the recycle bin' offers a practical solution."},
        {id:"rn024",type:"mc",q:"What does 'You right?' mean in Australian English?",options:["Are you correct?","Are you politically right-wing?","Are you OK? / Can I help you?","Are you on the right side?"],a:2,exp:"'You right?' (without 'are') is uniquely Australian. It means 'Are you OK?' or 'Do you need help?' Often said by shop assistants or when someone looks confused."},
        {id:"rn025",type:"fill",q:"A: 'I just found out I got the permanent position!' B: '___ one! You totally ___!'",a:"Good ... deserved it",exp:"'Good on you!' or 'Good one!' are classic Australian congratulations. 'You totally deserved it' affirms their effort and merit."},
        {id:"rn026",type:"error",q:"A: 'See you tomorrow!' B: 'See you! Have a good night rest.'",a:"A: 'See you tomorrow!' B: 'See you! Have a good night's rest.' (or 'Have a good evening!')",exp:"'Night's rest' needs the possessive. But actually, 'Have a good evening' or just 'Have a good one' is more natural in Australian English."},
        {id:"rn027",type:"open",q:"A colleague shares a funny story about a student saying something unexpected. Write a natural reaction.",a:"Ha! That is hilarious! Kids say the funniest things, don't they? That reminds me of when one of my Year 7s asked me if I was born in the 1900s. I nearly died! They have absolutely no filter at that age.",exp:"Laugh, react, share a similar story. This is how staffroom bonding works. Relating your own experience keeps the conversation going."},
        {id:"rn028",type:"fill",q:"A: 'I just finished report writing.' B: 'Oh, what a ___! That must be such a weight off your ___.'",a:"relief ... shoulders",exp:"'What a relief' shares their positive feeling. 'Weight off your shoulders' = a burden removed. Empathetic and natural."},
        {id:"rn029",type:"mc",q:"What does 'heaps' mean in Australian English?",options:["Piles of rubbish","A lot / very much","Tall buildings","A type of food"],a:1,exp:"'Heaps' = a lot. 'Heaps good' = really good (SA slang). 'Heaps of work' = lots of work. Very common in casual Australian English."},
        {id:"rn030",type:"fill",q:"A: 'Sorry, I completely forgot about the meeting.' B: 'Honestly, don't ___ about it. We all have those ___.'",a:"stress ... days",exp:"'Don't stress about it' = don't worry (very Australian). 'We all have those days' normalises the mistake and removes guilt."},
        {id:"rn031",type:"error",q:"A: 'I passed my driving test!' B: 'Congratulation! You must be very exciting!'",a:"A: 'I passed my driving test!' B: 'Congratulations! You must be so excited!'",exp:"'Congratulations' (always plural). 'Excited' (feeling), not 'exciting' (the thing causing the feeling). '-ed' = how you feel, '-ing' = the cause. Very common Chinese speaker confusion."},
        {id:"rn032",type:"fill",q:"A: 'I'm thinking of leaving teaching.' B: 'Oh really? That's a big ___. What's ___ you to think about that?'",a:"decision ... prompted",exp:"'That's a big decision' shows you take it seriously. 'What's prompted you?' asks the reason without judgement. Good active listening."},
        {id:"rn033",type:"mc",q:"A colleague says 'I'm over it.' What does this mean?",options:["I have climbed over something","I am no longer upset about it / I am fed up","I have finished a task","I am above it all"],a:1,exp:"'I'm over it' can mean 'I'm fed up' (frustrated) OR 'I've moved past it' (no longer bothered), depending on context. Very Australian expression."},
        {id:"rn034",type:"fill",q:"A: 'The printer broke again.' B: 'Of ___ it did. That thing has a ___ of its own!'",a:"course ... mind",exp:"'Of course it did' = unsurprised exasperation (humorous). 'Has a mind of its own' = seems to do what it wants (humorous personification)."},
        {id:"rn035",type:"fill",q:"A: 'How was the PD session?' B: 'To be ___, it was a bit dry. But I picked up a ___ useful tips.'",a:"honest ... few",exp:"'To be honest' signals a candid response. 'A bit dry' = a little boring (gentle critique). 'A few useful tips' balances with something positive. Australians hedge negative opinions."},
        {id:"rn036",type:"fill",q:"A: 'The photocopier is broken again.' B: 'Typical! That ___ is always on the ___.'",a:"thing ... blink",exp:"'Typical!' = this always happens (exasperated). 'On the blink' = not working properly (Australian/British slang). Shared frustrations about school equipment are classic bonding moments."},
        {id:"rn037",type:"mc",q:"A colleague says 'I could murder a coffee right now.' What do they mean?",options:["They want to harm someone at a cafe","They desperately want a coffee","They think coffee is terrible","They are angry at the barista"],a:1,exp:"'I could murder a coffee' = I desperately want one. It's colourful Australian/British hyperbole. Also: 'I'm dying for a coffee', 'I'm gagging for a coffee'. Not violent at all!"},
        {id:"rn038",type:"error",q:"A: 'I got a new car!' B: 'Oh that's nice. What colour is it?'",a:"A: 'I got a new car!' B: 'Oh wow, how exciting! What kind did you get? I bet you're stoked!'",exp:"The original response ('that's nice') is too flat for exciting news. Match the energy: 'How exciting!', 'What kind?', 'You must be stoked!' (stoked = very happy/excited, very Australian)."},
        {id:"rn039",type:"fill",q:"A: 'I just ran my first 5K!' B: 'That's ___ ! How did it feel? I bet you're pretty ___ of yourself.'",a:"amazing ... proud",exp:"'That's amazing!' matches their achievement energy. 'How did it feel?' shows genuine interest. 'Pretty proud of yourself' affirms their accomplishment warmly."},
        {id:"rn040",type:"fill",q:"A: 'I'm so tired.' B: 'Same here. I ___ sleep a wink last night. Roll on ___!'",a:"didn't ... Friday",exp:"'Same here' = me too. 'Didn't sleep a wink' = didn't sleep at all. 'Roll on Friday!' = I wish Friday would hurry up and arrive. Classic tired-teacher solidarity."}
      ]
    },
    {
      id: "opinions-agreeing",
      title: "Sharing Opinions & Agreeing/Disagreeing",
      theory: "In Australian workplaces, opinions are shared openly but tactfully. Agreeing is easy — 'Absolutely', 'Spot on', 'I couldn't agree more'. Disagreeing requires softening — 'I see what you mean, but...', 'I take your point, however...'. Never say 'You are wrong'. Chinese speakers may either avoid sharing opinions (too deferential) or be too direct (没有, 不对).",
      exercises: [
        {id:"oa001",type:"fill",q:"I ___ agree more. The new assessment policy is definitely a step in the right ___.",a:"couldn't ... direction",exp:"'I couldn't agree more' is the strongest form of agreement. 'Step in the right direction' = a positive change (but not perfect yet)."},
        {id:"oa002",type:"mc",q:"Which is the best way to disagree politely with a colleague's idea?",options:["That's wrong.","No, I don't think so.","I see where you're coming from, but have you considered looking at it from this angle?","That doesn't make any sense."],a:2,exp:"'I see where you're coming from' validates their perspective. 'Have you considered...' introduces your alternative as a suggestion, not a correction."},
        {id:"oa003",type:"fill",q:"That's a really ___ point. I hadn't thought about it from that ___ before.",a:"good ... angle",exp:"'Good point' validates the person. 'Hadn't thought about it from that angle' shows openness and intellectual humility."},
        {id:"oa004",type:"error",q:"I think your idea is wrong. My way is more better.",a:"I take your point, but I wonder if there might be another approach that could work even better.",exp:"Never say 'your idea is wrong' to a colleague. 'More better' is a double comparative. 'I wonder if' + 'another approach' + 'could work' is diplomatically structured."},
        {id:"oa005",type:"fill",q:"___ on! That's exactly what I was ___.",a:"Spot ... thinking",exp:"'Spot on' = exactly right (very Australian). 'Exactly what I was thinking' shows alignment and builds on their idea."},
        {id:"oa006",type:"mc",q:"A colleague suggests something you think won't work. What is the most diplomatic response?",options:["That'll never work.","I appreciate the suggestion. One concern I have is... Could we think about how to address that?","Sure, whatever you want.","I don't care either way."],a:1,exp:"'I appreciate the suggestion' is respectful. Naming a specific concern is constructive. Asking them to help solve it is collaborative."},
        {id:"oa007",type:"fill",q:"I ___ your point, but I'm not entirely ___ that approach would work with our Year 7 cohort.",a:"take ... convinced",exp:"'I take your point' = I understand. 'Not entirely convinced' is softer than 'I disagree'. Specifying the context (Year 7) makes the disagreement practical, not personal."},
        {id:"oa008",type:"error",q:"I am not agree with this idea. I think it is not good for students.",a:"I'm not sure I agree with this approach. I wonder whether it might have some unintended consequences for students.",exp:"'Not agree' — should be 'don't agree' or 'not sure I agree'. 'Not good' is vague — 'unintended consequences' is more professional and specific."},
        {id:"oa009",type:"fill",q:"You've ___ the nail on the head. That's ___ the issue we need to address.",a:"hit ... precisely",exp:"'Hit the nail on the head' = identified the issue perfectly. 'Precisely' = exactly. Strong agreement with emphasis."},
        {id:"oa010",type:"mc",q:"What does 'I'm on the fence about it' mean?",options:["I'm sitting on a fence","I'm undecided / I could go either way","I'm against it","I'm strongly in favour"],a:1,exp:"'On the fence' = undecided, seeing merits in both sides. It's a way of not committing to a position while acknowledging the complexity. Very useful in meetings."},
        {id:"oa011",type:"fill",q:"I'm ___ torn on this one. On one hand, it could work. On the ___ hand, it's a big risk.",a:"a bit ... other",exp:"'A bit torn' = conflicted. 'On one hand... on the other hand' is the classic structure for presenting both sides of an argument."},
        {id:"oa012",type:"error",q:"I very much support your opinion. I think same like you.",a:"I strongly support your view. I think the same way you do.",exp:"'Strongly support' (adverb). 'Your view' is more professional than 'opinion' in meetings. 'Think the same way you do' is the correct phrase."},
        {id:"oa013",type:"fill",q:"To be ___, I think we need to rethink our approach to ___.",a:"honest ... homework",exp:"'To be honest' signals a candid opinion is coming. It suggests the speaker may be saying something others haven't. Good for raising concerns."},
        {id:"oa014",type:"open",q:"A colleague argues that homework is essential. You think it should be optional. Write your response.",a:"I can see why you feel that way, and I know homework has its benefits, especially for building study habits. But from what I have read, the research on homework at the secondary level is actually quite mixed. I have found that when I make homework optional but meaningful, the students who do it tend to produce better quality work. Maybe we could trial a flexible approach and see how it goes?",exp:"Acknowledge their position, reference evidence, share your experience, propose a trial. This is a mature, collegial disagreement that keeps the relationship intact."},
        {id:"oa015",type:"fill",q:"That's an interesting ___. I'm not sure I'm 100% on board, but I'd like to hear more about how you'd ___ it.",a:"idea ... implement",exp:"'Interesting idea' is neutral but positive. 'Not 100% on board' = slight reservation. 'Hear more about implementation' shows willingness to be persuaded."},
        {id:"oa016",type:"mc",q:"What does 'playing devil's advocate' mean?",options:["Being intentionally evil","Arguing the opposite side to test an idea, even if you don't believe it","Defending a bad person","Being negative about everything"],a:1,exp:"Playing devil's advocate means presenting the opposing argument to test the strength of an idea. 'Just to play devil's advocate...' signals you don't necessarily believe what you're about to say."},
        {id:"oa017",type:"fill",q:"I completely ___ with what you said about student engagement. It really ___ with my own experience.",a:"agree ... resonates",exp:"'Completely agree' + explanation of why. 'Resonates with my experience' = matches/connects with what I've found too."},
        {id:"oa018",type:"error",q:"In my opinion, I think that this method is not suitable. We should change it.",a:"In my view, this method may not be the best fit for our context. Perhaps we could explore some alternatives.",exp:"'In my opinion, I think' is redundant (choose one). 'May not be the best fit' is softer than 'not suitable'. 'Could explore alternatives' is more constructive than 'should change'."},
        {id:"oa019",type:"fill",q:"Just to ___ devil's advocate for a moment — what if the students actually ___ having less structure?",a:"play ... prefer",exp:"Devil's advocate framing allows you to raise a controversial point without personal commitment. Useful in professional discussions."},
        {id:"oa020",type:"mc",q:"Which phrase best shows partial agreement?",options:["Absolutely!","No way!","I see your point, and I partially agree, but I think there are some aspects we haven't considered.","That's completely wrong."],a:2,exp:"Partial agreement acknowledges valid points while introducing additional considerations. This is a sophisticated communication skill in professional settings."},
        {id:"oa021",type:"fill",q:"You raise a ___ point. I think we need to find a ___ ground that works for everyone.",a:"valid ... middle",exp:"'Valid point' respects their contribution. 'Find a middle ground' = compromise. This is consensus-building language."},
        {id:"oa022",type:"error",q:"I don't have any opinion about this topic. Whatever you decide is fine for me.",a:"I don't have a strong opinion on this one. I'm happy to go with whatever the team decides.",exp:"'Don't have any opinion' sounds disengaged. 'Don't have a strong opinion' is honest. 'Happy to go with the team' shows flexibility, not indifference."},
        {id:"oa023",type:"fill",q:"I think we're all ___ the same page here. Let's move ___ with the plan.",a:"on ... forward",exp:"'On the same page' = in agreement. 'Move forward with' = proceed. These are standard consensus-confirming phrases in meetings."},
        {id:"oa024",type:"open",q:"In a staff meeting, someone proposes banning mobile phones entirely. You think a balanced approach is better. Write your response.",a:"I completely understand the frustration with phones in classrooms, and I agree that they can be a major distraction. However, I have seen some really effective use of phones as learning tools — for research, quick polls, and creating content. Rather than a blanket ban, could we consider a policy where phones are only out when directed by the teacher? That way, we get the benefits without the constant battle.",exp:"Acknowledge the frustration, agree with the core concern, present evidence of the alternative, propose a middle ground. Collaborative, not confrontational."},
        {id:"oa025",type:"fill",q:"I ___ to differ on that one. I think the evidence suggests ___.",a:"beg ... otherwise",exp:"'Beg to differ' is a formal, polite way to disagree. 'The evidence suggests otherwise' grounds the disagreement in data, not personal preference."},
        {id:"oa026",type:"mc",q:"What does 'That's a stretch' mean?",options:["That's a physical exercise","That's a bit of an exaggeration or unlikely conclusion","That's very flexible","That's a long walk"],a:1,exp:"'That's a stretch' politely suggests someone's argument or conclusion goes too far. It's a gentle way to express scepticism."},
        {id:"oa027",type:"fill",q:"Absolutely! I was just about to say the same ___. Great ___ think alike!",a:"thing ... minds",exp:"'Great minds think alike' is a playful way to acknowledge shared thinking. Creates a positive, collaborative atmosphere."},
        {id:"oa028",type:"error",q:"I am total agree with your idea. Let us do like what you say.",a:"I totally agree with your idea. Let's go with your suggestion.",exp:"'Totally' (adverb, not adjective). 'Let's go with your suggestion' is more natural than 'do like what you say'."},
        {id:"oa029",type:"fill",q:"I appreciate you ___ that up. It's something we definitely need to ___ more thought.",a:"bringing ... give",exp:"'Bringing that up' = raising the topic. 'Give more thought' = think about further. Acknowledging someone's contribution encourages future participation."},
        {id:"oa030",type:"fill",q:"That's ___ I was going to suggest. I think we're definitely on the right ___.",a:"exactly what ... track",exp:"'Exactly what I was going to suggest' creates connection. 'On the right track' = heading in the correct direction."},
        {id:"oa031",type:"error",q:"I very support this idea. I think it is a very good plan.",a:"I strongly support this idea. I think it is an excellent plan.",exp:"'Strongly support' (adverb + verb). 'Very' cannot modify a verb. 'Excellent' is more professional than 'very good'. Chinese 我很支持 translates to 'I very support'."},
        {id:"oa032",type:"fill",q:"I'd have to respectfully ___ on that point. The evidence doesn't quite ___ that conclusion.",a:"disagree ... support",exp:"'Respectfully disagree' is the most polished disagreement phrase. 'Evidence doesn't support that conclusion' is evidence-based reasoning."},
        {id:"oa033",type:"mc",q:"What does 'I'm inclined to agree' mean?",options:["I completely agree","I tend to agree but I'm not 100% certain","I lean towards disagreeing","I have no opinion"],a:1,exp:"'Inclined to agree' = I'm leaning towards agreement but have some reservations. It signals partial agreement with room for nuance. Sophisticated professional language."},
        {id:"oa034",type:"fill",q:"While I see the ___ of this approach, I think we should also weigh up the potential ___.",a:"merit ... downsides",exp:"'See the merit' acknowledges the value. 'Weigh up the downsides' = consider the negatives. Balanced, analytical thinking."},
        {id:"oa035",type:"fill",q:"I think we're ___ at this from different angles, but ultimately we want the same ___ for our students.",a:"looking ... thing",exp:"'Looking at it from different angles' reframes disagreement as perspective difference. 'Want the same thing' finds common ground. De-escalation through shared purpose."}
      ]
    },
    {
      id: "weekend-plans-hobbies",
      title: "Talking About Plans, Weekends & Hobbies",
      theory: "Talking about weekends, holidays, and hobbies is the #1 social bonding tool in Australian workplaces. The formula: share briefly, show enthusiasm, ask questions back. Australians love talking about food, sport, travel, and outdoor activities. Chinese speakers sometimes feel these conversations are pointless, but they build the trust needed for professional collaboration.",
      exercises: [
        {id:"wp001",type:"fill",q:"Not much planned for the weekend — just a quiet one at home. Might ___ a few things around the house and ___ up on some Netflix.",a:"do ... catch",exp:"'A quiet one at home' is a classic Australian weekend description. 'Do a few things' = small tasks. 'Catch up on Netflix' = watch shows you've missed."},
        {id:"wp002",type:"mc",q:"A colleague asks 'Got much on this weekend?' What does this mean?",options:["Are you wearing a lot of clothes?","Do you have many plans for the weekend?","Is something on your desk?","Are you working overtime?"],a:1,exp:"'Got much on?' is very Australian for 'Do you have many plans?' Casual, friendly, invites sharing. The natural response is to briefly share your plans."},
        {id:"wp003",type:"fill",q:"We're thinking of taking the kids to the ___ this weekend. The weather's supposed to be ___.",a:"beach ... gorgeous",exp:"'Taking the kids to the beach' is quintessentially Australian. 'Supposed to be gorgeous' = forecast is good. Beach culture is central to Australian life."},
        {id:"wp004",type:"error",q:"On weekend, I usually stay at home and do nothing. It is very boring.",a:"On the weekend, I usually have a lazy day at home — just pottering around and relaxing. It's actually really nice.",exp:"'On THE weekend' (article needed). 'Have a lazy day' and 'pottering around' sound positive. Saying 'do nothing, very boring' kills the conversation. Reframe rest as a positive choice."},
        {id:"wp005",type:"fill",q:"I've recently ___ into hiking. There are some amazing ___ around Sydney.",a:"got ... trails",exp:"'Got into' = started doing as a hobby. 'Amazing trails' — Australians love outdoor activities. This is a great conversation topic that invites recommendations."},
        {id:"wp006",type:"mc",q:"What does 'I could do with a holiday' mean?",options:["I'm planning a holiday right now","I really need a holiday / I'm tired and need a break","I could afford a holiday","I don't want a holiday"],a:1,exp:"'Could do with' = really need / would benefit from. 'I could do with a coffee' = I really need a coffee. Very common Australian expression."},
        {id:"wp007",type:"fill",q:"We went to this ___ little restaurant in Newtown on Saturday night. The food was absolutely ___.",a:"cute ... divine",exp:"'Cute little restaurant' — Australian food culture is huge. 'Absolutely divine' = incredibly delicious. Sharing food experiences is prime social conversation."},
        {id:"wp008",type:"error",q:"I like very much to cooking. Every weekend I will cook Chinese food for my family.",a:"I really enjoy cooking. Every weekend I cook Chinese food for my family.",exp:"'Really enjoy cooking' (not 'like very much to cooking'). Present simple for habits: 'I cook' (not 'I will cook'). 'Will' implies future intention, not routine."},
        {id:"wp009",type:"fill",q:"Have you got any holidays coming up? I'm ___ forward to the long ___ in June.",a:"looking ... weekend",exp:"'Looking forward to' = excited about. 'Long weekend' = a public holiday that extends the weekend. Australians love their long weekends!"},
        {id:"wp010",type:"mc",q:"What is a 'barbie' in Australian English?",options:["A doll","A barbecue","A haircut","A barista"],a:1,exp:"'Barbie' = barbecue. 'We're having a barbie on Saturday' = We're having a BBQ. This is iconic Australian culture. 'Throw a barbie' = host a BBQ."},
        {id:"wp011",type:"fill",q:"I'm not really into sport, but I ___ watching the tennis at the Australian ___.",a:"enjoy ... Open",exp:"'Not really into sport' hedges the admission. 'The Australian Open' is a major tennis event in Melbourne every January. Cultural reference points help social bonding."},
        {id:"wp012",type:"error",q:"Last weekend I went to shopping and bought many things. I spent too much moneys.",a:"Last weekend I went shopping and bought heaps of stuff. I spent way too much money.",exp:"'Went shopping' (no 'to'). 'Heaps of stuff' is Australian informal. 'Money' is uncountable (never 'moneys'). 'Way too much' is more natural than 'too much'."},
        {id:"wp013",type:"fill",q:"I've been meaning to ___ that new exhibition at the Art Gallery. Have you ___ it yet?",a:"check out ... seen",exp:"'Been meaning to check out' = intending to visit. 'Have you seen it yet?' invites their opinion. Cultural activities are good conversation topics."},
        {id:"wp014",type:"open",q:"A colleague asks what you did over the school holidays. You stayed home and relaxed. Write a natural response.",a:"Honestly, not a lot! I just had a really chilled couple of weeks at home. Caught up on sleep, did some cooking, and binge-watched a Korean drama on Netflix. Oh, and I finally got around to organising my study — that had been bugging me for ages. Sometimes you just need a proper rest, you know? How about you — did you get away anywhere?",exp:"Make even a quiet holiday sound positive and interesting. Use Australian phrases: 'chilled', 'caught up on', 'got around to', 'bugging me for ages'. Always ask them back."},
        {id:"wp015",type:"fill",q:"That sounds like a great ___! I wish I could ___ something like that.",a:"trip ... do",exp:"Positive reaction + aspiration. 'Sounds like a great trip' is enthusiastic. 'Wish I could do something like that' shows friendly envy."},
        {id:"wp016",type:"mc",q:"What does 'a lazy Sunday' imply?",options:["A boring, wasted day","A relaxing day with no obligations — very positive","A day you oversleep and miss things","A day when you feel unmotivated"],a:1,exp:"'Lazy Sunday' is very positive in Australian culture — it means a deliberate day of relaxation with no pressure. Rest is valued, not seen as laziness."},
        {id:"wp017",type:"fill",q:"I'm thinking of ___ up a new hobby. Maybe pottery or something ___.",a:"picking ... creative",exp:"'Picking up a new hobby' = starting a new leisure activity. 'Or something creative' leaves it open. Hobbies are a valued conversation topic."},
        {id:"wp018",type:"error",q:"I don't have any hobby. In my free time I just play phone.",a:"I don't really have a specific hobby at the moment. In my free time I usually just scroll through my phone.",exp:"'Don't really have a specific hobby' is more social than 'don't have any hobby'. 'Scroll through my phone' is the correct phrase — 'play phone' is Chinglish from 玩手机."},
        {id:"wp019",type:"fill",q:"We had a ___  on Saturday. Just a few friends, some good food, and a couple of ___ in the backyard.",a:"get-together ... drinks",exp:"'Get-together' = informal social gathering. 'A couple of drinks in the backyard' is quintessentially Australian. Describing casual social events is a key skill."},
        {id:"wp020",type:"mc",q:"Your colleague says 'I'm flat out this weekend.' What does this mean?",options:["They fell over","They are lying down resting","They are extremely busy","They are tired and sleeping"],a:2,exp:"'Flat out' = extremely busy. 'I'm flat out at work' = I have no free time. Very common Australian expression. Can also mean 'as fast as possible'."},
        {id:"wp021",type:"fill",q:"I've booked a little ___ down to the South Coast. Just a couple of nights to get away from it ___.",a:"getaway ... all",exp:"'Getaway' = short holiday/trip. 'Get away from it all' = escape daily stress. Short trips are very popular in Australia."},
        {id:"wp022",type:"error",q:"Next holiday I plan to go back my country to visit my family. It's been long time.",a:"Next holidays I'm planning to go back to my country to visit my family. It's been a long time.",exp:"'Next holidays' (plural in Australian English). 'Go back to' (preposition needed). 'Planning to go' (more natural for near-future plans). 'A long time' (article needed)."},
        {id:"wp023",type:"fill",q:"Have you been to any good ___ lately? I'm always on the lookout for new ___.",a:"restaurants ... places",exp:"Food recommendations are a goldmine for social conversation. 'On the lookout for' = looking for/searching for."},
        {id:"wp024",type:"open",q:"A colleague mentions they're learning guitar. Write a natural conversational response showing interest.",a:"Oh nice! How long have you been learning for? I have always wanted to learn an instrument but I have absolutely zero musical talent. Are you teaching yourself or taking lessons? My neighbour plays guitar and it sounds amazing. What kind of music are you into?",exp:"Multiple follow-up questions, self-deprecating humour ('zero musical talent'), relating to your own life. This keeps the conversation flowing naturally."},
        {id:"wp025",type:"fill",q:"We're hosting a ___ warming party next month. You should ___!",a:"house ... come",exp:"'House warming party' = party when someone moves to a new home. 'You should come!' = casual invitation. Social invitations build professional relationships."},
        {id:"wp026",type:"mc",q:"What does 'brekkie' mean?",options:["A break between classes","Breakfast","A broken item","A type of bread"],a:1,exp:"'Brekkie' = breakfast. Australians shorten everything: brekkie (breakfast), arvo (afternoon), avo (avocado), Maccas (McDonald's), Chrissie (Christmas)."},
        {id:"wp027",type:"fill",q:"I spent the whole weekend binge-___ a new series on Stan. I couldn't ___ watching!",a:"watching ... stop",exp:"'Binge-watching' = watching many episodes consecutively. 'Couldn't stop watching' shows enthusiasm. Stan is an Australian streaming service."},
        {id:"wp028",type:"error",q:"I want to travel to many countries but I am afraid of fly. The plane makes me very nervous.",a:"I'd love to travel to lots of different countries, but I'm a bit afraid of flying. Planes make me quite nervous.",exp:"'I'd love to' is more natural than 'I want to'. 'Afraid of flying' (gerund). 'Planes' (plural). 'Quite nervous' is more natural than 'very nervous'."},
        {id:"wp029",type:"fill",q:"Sounds like you had a pretty ___ weekend! Mine was the complete ___ — I didn't leave the house once.",a:"adventurous ... opposite",exp:"'Pretty adventurous' praises their experience. 'Complete opposite' contrasts humorously. Self-deprecating humour about being lazy is very Australian."},
        {id:"wp030",type:"fill",q:"I'm counting down the ___ until the school holidays. Only three more ___ to go!",a:"days ... weeks",exp:"'Counting down' = eagerly waiting. Teachers counting down to holidays is a universal bonding topic. It's not unprofessional — it's human!"},
        {id:"wp031",type:"error",q:"Last weekend I and my husband went to the Blue Mountains. The scenery is very beautiful.",a:"Last weekend my husband and I went to the Blue Mountains. The scenery was very beautiful.",exp:"'My husband and I' (others first, then 'I', not 'I and my husband'). 'Was beautiful' (past tense for completed trip). Both are common Chinese speaker patterns."},
        {id:"wp032",type:"fill",q:"We're having a few people ___ for a barbecue on Saturday. You're more than ___ to join us!",a:"over ... welcome",exp:"'Having people over' = inviting them to your home. 'More than welcome' = very warmly invited. Social invitation language."},
        {id:"wp033",type:"mc",q:"What does 'a long weekend' mean in Australia?",options:["A weekend that feels long because you're bored","A three-day weekend due to a public holiday","Working on the weekend","A weekend trip to a faraway place"],a:1,exp:"'Long weekend' = Saturday + Sunday + Monday public holiday (or Friday off). Australians love long weekends — there are several each year. 'What are you doing for the long weekend?'"},
        {id:"wp034",type:"fill",q:"I finally got around to ___ that book you recommended. I couldn't ___ it down!",a:"reading ... put",exp:"'Got around to' = finally found time for. 'Couldn't put it down' = it was so good I kept reading. Book recommendations are great conversation topics."},
        {id:"wp035",type:"fill",q:"We took the kids to ___ last Sunday. They had an absolute ___ on the jumping castle.",a:"Taronga Zoo ... blast",exp:"'Taronga Zoo' is a famous Sydney landmark. 'Had an absolute blast' = had an amazing time. Very Australian expression."}
      ]
    }
  ]
},
// ============================================================
// MODULE 4: MEETINGS & PROFESSIONAL DISCUSSIONS
// ============================================================
meetingsExplanations: {
  title: "Meetings & Professional Discussions",
  sections: [
    {
      id: "contributing-ideas",
      title: "Contributing Ideas in Meetings",
      theory: "Australian meetings are relatively informal compared to many Asian cultures. Everyone is expected to contribute, regardless of seniority. Raising your hand is not necessary — just speak when there is a natural pause. Use phrases like 'I'd like to suggest...', 'One thing we could try is...', or 'What if we...'. Chinese speakers often wait to be asked, which can be interpreted as disengagement.",
      exercises: [
        {id:"mi001",type:"fill",q:"I'd like to ___ something. What if we tried a different ___ to the timetabling issue?",a:"suggest ... approach",exp:"'I'd like to suggest' is a clear, professional way to introduce an idea. 'What if we tried...' frames it as a possibility, not a demand."},
        {id:"mi002",type:"mc",q:"Which phrase is best for introducing a new idea in a staff meeting?",options:["I think everyone is wrong and we should do this instead.","I've been thinking about this, and one option could be to restructure the assessment schedule.","Well obviously the answer is...","Someone should probably do something about this."],a:1,exp:"'I've been thinking about this' shows reflection. 'One option could be' presents it as one possibility among many. Collegial and non-threatening."},
        {id:"mi003",type:"fill",q:"Building on what Sarah said, I think we could also ___ peer mentoring as a way to ___ student engagement.",a:"introduce ... boost",exp:"'Building on what X said' credits a colleague and connects your idea to theirs. 'Introduce peer mentoring' proposes a specific action."},
        {id:"mi004",type:"error",q:"I have a idea. Maybe we can to try using more technology in the classroom.",a:"I have an idea. Maybe we could try using more technology in the classroom.",exp:"'An idea' (vowel sound). 'Could try' (not 'can to try' — modal + base form). 'Could' is softer than 'can' for suggestions."},
        {id:"mi005",type:"fill",q:"Just to ___ in here — I think there's an opportunity to ___ our approach to homework.",a:"jump ... rethink",exp:"'Just to jump in' signals you're entering the conversation. 'Rethink our approach' is more collaborative than 'change the homework'."},
        {id:"mi006",type:"mc",q:"You have data that supports a point being discussed. How do you introduce it?",options:["Everyone listen to my data!","I was actually looking at the data on this, and it shows that...","The numbers prove I'm right.","Data data data."],a:1,exp:"'I was actually looking at the data' sounds natural and well-prepared. 'It shows that...' lets the evidence speak. Evidence-based contributions are highly valued."},
        {id:"mi007",type:"fill",q:"One thing I've ___ that works well in my classroom is ___ learning stations for different ability levels.",a:"found ... using",exp:"Sharing what works in your practice is the best way to contribute. 'One thing I've found' positions it as experience, not instruction."},
        {id:"mi008",type:"error",q:"I want to say my opinion. I think the principal should to change the policy.",a:"I'd like to share my thoughts on this. I think the policy could benefit from some adjustments.",exp:"'Share my thoughts' is softer than 'say my opinion'. 'Could benefit from adjustments' is more diplomatic than 'the principal should change'. Never target individuals."},
        {id:"mi009",type:"fill",q:"Has anyone ___ trialling a flipped classroom model? I've read some promising ___ about it.",a:"considered ... research",exp:"'Has anyone considered...' invites collective thinking. 'Promising research' supports the suggestion with evidence."},
        {id:"mi010",type:"mc",q:"What does 'to piggyback on that' mean in a meeting?",options:["To ride on someone's back","To add to what someone just said","To disagree with someone","To repeat what someone said"],a:1,exp:"'To piggyback on that' means to add a related point to what someone just said. 'Piggybacking on Sarah's point...' is a common meeting phrase."},
        {id:"mi011",type:"fill",q:"I appreciate the ___ here, but I think we might be overcomplicating things. What about a ___ solution?",a:"discussion ... simpler",exp:"'I appreciate the discussion' is respectful. 'Overcomplicating things' is honest but non-judgemental. 'Simpler solution' redirects constructively."},
        {id:"mi012",type:"open",q:"You want to propose a lunchtime coding club at a faculty meeting. Write what you would say.",a:"I have been thinking about ways to extend our students who are interested in technology outside of class time. I would like to propose running a lunchtime coding club, maybe once a week on Wednesdays. I have had several students ask about extra programming opportunities, and I think it could also help with our school's STEM goals. I am happy to run it, and I would just need access to the computer room. What does everyone think?",exp:"Clear proposal with rationale, practical details, alignment with school goals, and an invitation for feedback. Offering to run it yourself shows initiative."},
        {id:"mi013",type:"fill",q:"This is just a ___, but what if we partnered with the English department on a cross-curricular ___?",a:"thought ... project",exp:"'Just a thought' softens the suggestion. 'Cross-curricular project' connects subjects. Collaboration across departments is valued in Australian schools."},
        {id:"mi014",type:"mc",q:"When is it appropriate to share a concern in a meeting?",options:["Never — concerns should only be raised privately","When it affects the team and you can frame it constructively","Only if the principal asks for concerns","Whenever you feel like complaining"],a:1,exp:"Concerns that affect the team belong in team meetings, but frame them constructively: 'One challenge I've noticed is...' + 'A possible solution could be...'"},
        {id:"mi015",type:"fill",q:"I know this might be a ___ idea, but bear with me — what if we completely ___ our assessment model?",a:"bold ... redesigned",exp:"'Bold idea' acknowledges it's unusual. 'Bear with me' asks for patience. 'Redesigned' suggests major change. Framing signals confidence."},
        {id:"mi016",type:"error",q:"I want to discuss about the new curriculum. I think it have many problem.",a:"I'd like to discuss the new curriculum. I think it has a number of areas that need attention.",exp:"'Discuss' (no 'about'). 'Has' (singular). 'Areas that need attention' is more professional than 'many problems'. Constructive framing matters."},
        {id:"mi017",type:"fill",q:"To add to the conversation, I've seen other schools ___ this successfully by ___ parent volunteers.",a:"do ... involving",exp:"'I've seen other schools do this' provides an external example. 'Involving parent volunteers' offers a practical strategy."},
        {id:"mi018",type:"fill",q:"What if we set up a working ___ to look into this further? I'd be happy to be ___ of it.",a:"group ... part",exp:"'Working group' = a small team investigating a specific issue. 'Happy to be part of it' shows willingness to contribute. Proactive and collaborative."},
        {id:"mi019",type:"mc",q:"Your idea was just dismissed by a senior colleague. What is the best response?",options:["Fine, forget I said anything.","I understand your concern. Could I explain the reasoning behind it a bit more?","You're wrong — my idea is better.","I'll just stay quiet from now on."],a:1,exp:"'I understand your concern' acknowledges them. 'Could I explain the reasoning?' gives yourself another chance without confrontation. Resilience in meetings is professional."},
        {id:"mi020",type:"fill",q:"I'm ___ about implementing this without proper training. Could we ___ some professional development first?",a:"concerned ... organise",exp:"'Concerned about' raises a legitimate issue. 'Could we organise PD first?' proposes a solution. Raising concerns with solutions is the professional standard."},
        {id:"mi021",type:"error",q:"In my before school, we did different. I think maybe we should try same way here.",a:"At my previous school, we did it differently. Perhaps we could try a similar approach here.",exp:"'Previous school' not 'before school'. 'Did it differently' needs object pronoun. 'Perhaps we could try a similar approach' is more diplomatic than 'should try same way'."},
        {id:"mi022",type:"fill",q:"Can I ___ something from the student perspective? I think they would really ___ from more hands-on activities.",a:"add ... benefit",exp:"'From the student perspective' frames your contribution. 'Benefit from' is the correct collocation (not 'benefit of' or 'benefit with')."},
        {id:"mi023",type:"open",q:"At a faculty meeting, the team is discussing declining assessment results. Contribute a constructive idea.",a:"I have been looking at the data, and I noticed that the biggest drops are in the extended response sections. I wonder if we could spend some time as a faculty developing a shared approach to teaching extended writing across all our subjects. Something like common paragraph structures or sentence starters that students see consistently. I would be happy to pull together some resources as a starting point if people think it is worth exploring.",exp:"Data-driven observation, specific solution, offer to contribute. This demonstrates professional leadership without overstepping."},
        {id:"mi024",type:"fill",q:"I don't want to ___ off topic, but I think this connects to the broader issue of student ___.",a:"go ... wellbeing",exp:"'I don't want to go off topic' signals awareness of the agenda. Connecting to a broader issue shows strategic thinking. 'Student wellbeing' is a priority in Australian schools."},
        {id:"mi025",type:"mc",q:"What does 'let's park that for now' mean in a meeting?",options:["Let's go to the car park","Let's set that aside temporarily and come back to it later","Let's abandon that idea completely","Let's vote on it"],a:1,exp:"'Park that' = temporarily set aside a topic that's not relevant to the current discussion. It will be revisited later. Very common meeting language."},
        {id:"mi026",type:"fill",q:"Sorry to ___ in, but I just wanted to make a quick point about the ___ implications.",a:"cut ... budget",exp:"'Sorry to cut in' = polite interruption. 'Quick point about budget implications' signals it's brief and relevant."},
        {id:"mi027",type:"error",q:"I am agree with the plan. But I think we need more detail before we can start to implement it.",a:"I agree with the plan. But I think we need more detail before we can start implementing it.",exp:"'I agree' (no 'am'). 'Start implementing' (start + gerund) is more natural than 'start to implement' in this context."},
        {id:"mi028",type:"fill",q:"From a practical ___, I think we need to consider the ___ on teacher workload.",a:"standpoint ... impact",exp:"'From a practical standpoint' grounds the discussion. 'Impact on teacher workload' is a legitimate concern in any school initiative."},
        {id:"mi029",type:"fill",q:"Could I ___ an example from my own experience? Last term, I tried ___ and it worked really well.",a:"share ... this",exp:"'Share an example from experience' is how teachers contribute knowledge. Personal case studies are powerful in faculty discussions."},
        {id:"mi030",type:"mc",q:"What is the best way to support a colleague's idea in a meeting?",options:["Stay silent","That's great, I love it, best idea ever!","I really like that suggestion. I think it would work well because... [specific reason]","Whatever you think is fine."],a:2,exp:"Specific support with reasoning ('I think it would work because...') is more valuable than generic praise. It also signals to others that the idea has been thoughtfully considered."},
        {id:"mi031",type:"fill",q:"That's a really ___ idea. Could you ___ on how you see it working in practice?",a:"interesting ... elaborate",exp:"'Could you elaborate' = could you explain in more detail. This shows interest and helps the person develop their idea. Collaborative inquiry."},
        {id:"mi032",type:"error",q:"I am not understanding what is the plan. Can someone explain me?",a:"I'm not quite following the plan. Could someone explain it to me?",exp:"'Not quite following' is more natural than 'not understanding'. 'Explain it to me' needs 'it' and 'to'. Embedded question: 'what the plan is' not 'what is the plan'."},
        {id:"mi033",type:"fill",q:"Just to ___ track — are we still on the ___ agenda item, or have we moved on?",a:"keep ... same",exp:"'Keep track' = stay oriented. Asking about the agenda shows active engagement and helps keep the meeting focused."},
        {id:"mi034",type:"open",q:"The meeting has been going for an hour and no decisions have been made. What do you say?",a:"I'm aware that we've been discussing this for a while, and there are some great ideas on the table. Could we perhaps narrow it down to two or three options and make a decision today? Otherwise, we might end up going around in circles. Perhaps we could vote or agree on a trial period?",exp:"Acknowledges the good discussion, proposes a decision-making process, uses 'we' language. This is leadership without being bossy."},
        {id:"mi035",type:"fill",q:"I'd like to ___ a motion that we adopt the new assessment ___ from next term.",a:"move ... framework",exp:"'Move a motion' = formally propose for a vote. 'Assessment framework' is a structured system for assessment. Formal meeting language."},
        {id:"mi036",type:"error",q:"I want to add a point. In my opinion I think we should consider change the timetable.",a:"I'd like to add a point. In my opinion, we should consider changing the timetable.",exp:"'I'd like to' is more polite than 'I want to'. 'In my opinion I think' is redundant — use one. 'Consider changing' (consider + gerund, not infinitive)."},
        {id:"mi037",type:"fill",q:"Before we ___ up, are there any other items anyone would like to ___ to the table?",a:"wrap ... bring",exp:"'Wrap up' = finish the meeting. 'Bring to the table' = raise for discussion. Both are standard meeting management phrases."},
        {id:"mi038",type:"mc",q:"What does 'action item' mean in a meeting?",options:["Something exciting that happened","A specific task assigned to a person with a deadline","A list of discussion topics","A vote on a proposal"],a:1,exp:"An action item is a task someone must complete after the meeting. It includes WHO does WHAT by WHEN. Clear action items make meetings productive."},
        {id:"mi039",type:"fill",q:"I'd like to ___ a different perspective on this. From my experience teaching EAL/D students, I've found that ___.",a:"offer ... scaffolding is essential",exp:"'Offer a different perspective' is diplomatic. Drawing on specific teaching experience adds credibility. Evidence-based contributions are valued."},
        {id:"mi040",type:"fill",q:"Can I just ___ to that? I think there's an important point about ___ that we haven't addressed yet.",a:"add ... equity",exp:"'Can I just add to that?' is a polite way to contribute without interrupting. 'Equity' is a key concern in Australian education discussions."}
      ]
    },
    {
      id: "asking-clarification",
      title: "Asking for Clarification",
      theory: "Asking for clarification is a professional strength, not a weakness. In Australian culture, it is much better to ask than to guess. Use phrases like 'Sorry, could you run that by me again?', 'Just to clarify...', and 'Do you mean...?'. Chinese speakers often feel embarrassed to ask for clarification (fear of 'losing face'), but in Australian workplaces, not asking is seen as a bigger problem.",
      exercises: [
        {id:"ac001",type:"fill",q:"Sorry, could you ___ that by me again? I want to make sure I've ___ it correctly.",a:"run ... understood",exp:"'Run that by me again' = repeat/explain again. Very natural Australian phrase. 'Make sure I've understood' shows diligence, not confusion."},
        {id:"ac002",type:"mc",q:"You didn't hear what the principal said clearly. What is the best thing to say?",options:["What?","I'm sorry, I didn't quite catch that. Could you repeat it, please?","Never mind.","I wasn't listening."],a:1,exp:"'I didn't quite catch that' is polite and natural. It implies the issue was hearing, not understanding. 'Could you repeat it' is a clear request."},
        {id:"ac003",type:"fill",q:"Just to ___, are you saying that the deadline has been ___ to next Friday?",a:"clarify ... moved",exp:"'Just to clarify' signals you want to confirm understanding. Paraphrasing what you heard ('are you saying that...') checks accuracy."},
        {id:"ac004",type:"error",q:"Excuse me, what means 'differentiation'? I am not understand this word.",a:"Excuse me, what does 'differentiation' mean? I'm not sure I understand this term.",exp:"'What does X mean?' (correct question form, not 'what means X'). 'I'm not sure I understand' is softer than 'I am not understand'. Question word order is different in Chinese."},
        {id:"ac005",type:"fill",q:"When you say 'scaffolded', do you ___ providing templates, or are you talking about something ___?",a:"mean ... different",exp:"'Do you mean X, or are you talking about Y?' narrows down the interpretation. Clarifying jargon is perfectly professional."},
        {id:"ac006",type:"mc",q:"Which phrase politely asks someone to speak more slowly?",options:["Talk slower!","Could you slow down a little? I want to make sure I follow everything.","You're talking too fast for me.","Please reduce your speaking speed."],a:1,exp:"'Could you slow down a little?' is polite and natural. 'I want to make sure I follow everything' frames it as your commitment to understanding, not their fault."},
        {id:"ac007",type:"fill",q:"I'm not quite ___ the distinction between the two ___. Could you give me an example?",a:"following ... approaches",exp:"'Not quite following' = I'm having difficulty understanding. Asking for an example is the best way to clarify abstract concepts."},
        {id:"ac008",type:"error",q:"Can you say again? I don't understand what you are meaning.",a:"Could you say that again, please? I'm not sure I follow what you mean.",exp:"'Say that again' needs 'that'. 'Could' is more polite than 'can'. 'What you mean' (simple present, not continuous 'are meaning'). 'Mean' is a stative verb."},
        {id:"ac009",type:"fill",q:"Sorry, I'm a bit lost. Could we go ___ to the part about the new reporting ___?",a:"back ... system",exp:"'I'm a bit lost' is honest and non-embarrassing. 'Go back to' the specific part helps the speaker know where to restart."},
        {id:"ac010",type:"mc",q:"What is the purpose of paraphrasing in a meeting?",options:["To show off your vocabulary","To check your understanding by restating what someone said in your own words","To waste time","To change what someone said"],a:1,exp:"Paraphrasing ('So what you're saying is...') is a powerful clarification tool. It confirms understanding and shows active listening."},
        {id:"ac011",type:"fill",q:"So if I understand ___, we need to submit the data by Wednesday and the ___ by Friday?",a:"correctly ... report",exp:"'If I understand correctly' + paraphrase is the gold standard for clarification. It gives the other person a chance to confirm or correct."},
        {id:"ac012",type:"error",q:"Excuse me, can I ask? What is the meaning about 'KLA' in this context?",a:"Excuse me, could I ask what 'KLA' stands for in this context?",exp:"'Could I ask what X stands for' is one smooth question. 'Meaning about' should be 'meaning of' or better, 'what X stands for' for acronyms."},
        {id:"ac013",type:"fill",q:"I want to make sure I'm on the same ___ as everyone else. Are we saying that we'll ___ the new policy from Term 2?",a:"page ... implement",exp:"'On the same page' = have the same understanding. Confirming group decisions prevents miscommunication later."},
        {id:"ac014",type:"open",q:"In a meeting, someone uses an acronym you don't know (IEP). Write how you would ask about it.",a:"Sorry to interrupt, but could someone clarify what IEP stands for? I want to make sure I am following the discussion properly.",exp:"Simple, direct, no shame. 'I want to make sure I'm following' frames it positively. IEP = Individual Education Plan (a plan for students with additional needs)."},
        {id:"ac015",type:"fill",q:"Could you ___ a little more on what you mean by 'student-centred learning'? I want to make sure we're ___ it the same way.",a:"elaborate ... interpreting",exp:"'Elaborate a little more' asks for detail. 'Interpreting it the same way' acknowledges that terms can mean different things to different people."},
        {id:"ac016",type:"mc",q:"You receive an email with unclear instructions. What do you do?",options:["Guess what they mean and hope for the best","Reply asking for clarification on the specific points that are unclear","Ignore the email","Forward it to someone else to figure out"],a:1,exp:"Replying with specific questions ('Could you clarify whether X means Y or Z?') is professional. Guessing risks doing the wrong thing. Always ask."},
        {id:"ac017",type:"fill",q:"Sorry, I missed that last bit. Did you say the ___ is due on ___ or Thursday?",a:"report ... Wednesday",exp:"'Missed that last bit' = didn't hear the end. Confirming specific details (date, task) prevents errors."},
        {id:"ac018",type:"error",q:"I have a confusion about the new policy. Can you explain to me more clear?",a:"I'm a bit confused about the new policy. Could you explain it more clearly?",exp:"'I'm confused' (adjective, not noun 'confusion'). 'Explain it more clearly' (adverb 'clearly', not adjective 'clear'). 'I have a confusion' is direct Chinese translation."},
        {id:"ac019",type:"fill",q:"Just to double-___, when you said 'all staff', did you ___ teaching staff only, or support staff as well?",a:"check ... mean",exp:"'Double-check' = verify/confirm. Clarifying who is included in a broad term prevents misunderstandings."},
        {id:"ac020",type:"mc",q:"What is the most professional way to admit you don't understand something?",options:["I'm too stupid to understand this.","I am not familiar with this area yet. Could you point me to some resources so I can get up to speed?","I don't know anything about that.","This is confusing and badly explained."],a:1,exp:"'Not familiar with this area yet' frames it as a growth opportunity, not a deficit. 'Get up to speed' = become knowledgeable about something. Proactive and professional."},
        {id:"ac021",type:"fill",q:"So just to ___ — the action item for me is to prepare the data report by next ___, correct?",a:"recap ... Monday",exp:"'Just to recap' summarises what was agreed. Confirming your specific action item ensures accountability. 'Correct?' invites confirmation."},
        {id:"ac022",type:"error",q:"Sorry, I not understand the technical language. Is it possible you can use simple words?",a:"Sorry, I'm not familiar with some of the technical terms. Would it be possible to explain it in simpler language?",exp:"'I'm not familiar with' is professional. 'Would it be possible' is more polite than 'Is it possible you can'. 'Simpler language' (comparative form)."},
        {id:"ac023",type:"fill",q:"I think I understand the general ___, but could you walk me through the specific ___ involved?",a:"concept ... steps",exp:"'Understand the general concept' = get the big picture. 'Walk me through the steps' = explain the process step by step. Shows engagement."},
        {id:"ac024",type:"open",q:"A colleague explains a new software system very quickly. You need them to slow down. Write your response.",a:"Sorry, could I just slow you down for a moment? I am really keen to learn this, but it is quite a lot of new information at once. Would you mind walking me through it step by step? Maybe we could start with the basics and then build from there?",exp:"Polite pause, genuine enthusiasm, request for step-by-step approach. Framing it as 'a lot of new information' (not 'too fast') is diplomatic."},
        {id:"ac025",type:"fill",q:"Forgive me if this is a ___ question, but what exactly is the difference between formative and ___ assessment?",a:"silly ... summative",exp:"'Forgive me if this is a silly question' disarms any potential embarrassment. In reality, it's never a silly question to clarify fundamental terms."},
        {id:"ac026",type:"mc",q:"What does 'Could you unpack that a bit?' mean?",options:["Open your suitcase","Explain it in more detail","Remove some items","Simplify it"],a:1,exp:"'Unpack' in a discussion means to explain something complex in more detail, breaking it down into its component parts. Common in educational settings."},
        {id:"ac027",type:"fill",q:"I'm picking up what you're ___ down, but I'm not sure how it applies to ___ context specifically.",a:"putting ... our",exp:"'Picking up what you're putting down' = I understand your point (informal). 'How it applies to our context' asks for practical relevance."},
        {id:"ac028",type:"error",q:"Could you please repeat once more? I didn't listen clearly.",a:"Could you please say that once more? I didn't quite catch it.",exp:"'Say that once more' is more natural than 'repeat once more'. 'Didn't quite catch it' = didn't hear/understand. 'Didn't listen clearly' implies you weren't paying attention."},
        {id:"ac029",type:"fill",q:"Am I right in thinking that this ___ to all year groups, or just Stage 4 and ___?",a:"applies ... 5",exp:"'Am I right in thinking' = is my understanding correct. Confirming the scope of a policy/decision is important. 'Stage 4 and 5' = Years 7-10 in NSW."},
        {id:"ac030",type:"fill",q:"Let me see if I've got this ___. We're changing the assessment from a ___ to a portfolio?",a:"straight ... test",exp:"'Got this straight' = understood correctly. Summarising the change checks understanding. 'From a test to a portfolio' shows the shift."},
        {id:"ac031",type:"mc",q:"In an Australian school, what does 'touch base' mean?",options:["Play baseball","Have a brief conversation to check in or update someone","Physical contact","Visit a military base"],a:1,exp:"'Touch base' = have a brief catch-up/update conversation. 'Let's touch base next week' = let's have a quick check-in. Very common workplace phrase."},
        {id:"ac032",type:"fill",q:"Sorry to ___ a potentially obvious question, but could you confirm whether this is mandatory or ___?",a:"ask ... optional",exp:"'Ask a potentially obvious question' — this framing disarms any embarrassment. Confirming mandatory vs optional prevents misunderstandings."},
        {id:"ac033",type:"error",q:"What the deadline is? I want to confirm is next week or this week.",a:"What is the deadline? I want to confirm whether it is next week or this week.",exp:"Question word order: 'What is the deadline?' (not 'What the deadline is'). 'Whether it is' introduces the two options. Chinese question structure differs significantly."},
        {id:"ac034",type:"fill",q:"Could someone ___ me in on what was decided at the last meeting? I was ___ that day.",a:"fill ... absent",exp:"'Fill me in on' = inform me about. 'I was absent' explains why you need the information. Professional and straightforward."},
        {id:"ac035",type:"open",q:"You receive a parent email that is unclear about what they're asking. Write a reply asking for clarification.",a:"Dear Mrs Nguyen, Thank you for your email. I want to make sure I address your concern properly. Could you please clarify whether you are asking about the assessment due date or the assessment criteria? I want to give you the most accurate information. Please feel free to call me on the school number if it is easier to discuss over the phone. Kind regards, Ms Gao",exp:"Professional, respectful, specific about what needs clarifying, offers an alternative communication method. Does not assume or guess."},
        {id:"ac036",type:"fill",q:"I'm not quite sure I ___ the distinction you're making. Could you give me a concrete ___?",a:"follow ... example",exp:"'Don't follow the distinction' = don't understand the difference. 'Concrete example' = specific, real-world illustration. Asking for examples is the best clarification strategy."},
        {id:"ac037",type:"error",q:"Excuse me, I am not understand. Can you repeat once more time?",a:"Excuse me, I'm not sure I understand. Could you say that one more time?",exp:"'I'm not sure I understand' (more natural). 'Could you' (more polite than 'can you'). 'One more time' (not 'once more time'). Three common Chinese speaker patterns."},
        {id:"ac038",type:"fill",q:"Just to make sure we're on the same ___ — the submission deadline is 5 p.m. on Friday, ___?",a:"page ... correct",exp:"'On the same page' = have the same understanding. Adding 'correct?' at the end invites confirmation. Checking critical details prevents errors."},
        {id:"ac039",type:"mc",q:"You missed part of the meeting because someone was talking quietly. What do you say?",options:["Speak up! I can't hear you!","Sorry, I didn't catch the last part. Would you mind speaking up a little?","You're too quiet.","Never mind, I'll figure it out."],a:1,exp:"'Didn't catch the last part' is natural. 'Would you mind speaking up a little?' is polite and specific. Never say 'Speak up!' which is blunt and rude."},
        {id:"ac040",type:"fill",q:"Apologies — I'm still getting my head ___ this. Could you walk me ___ the process one more time?",a:"around ... through",exp:"'Getting my head around' = trying to understand something complex. 'Walk me through' = explain step by step. Both are natural, professional clarification phrases."}
      ]
    },
    {
      id: "summarising-reporting",
      title: "Summarising & Reporting Back",
      theory: "Summarising is a critical professional skill in Australian schools. After meetings, PD sessions, or observations, you need to distil key information clearly. Use structures like 'The main takeaway was...', 'Three key actions were agreed...', 'In summary...'. Chinese speakers may give too much detail or not enough — the skill is finding the right level.",
      exercises: [
        {id:"sr001",type:"fill",q:"To ___ up, we agreed on three key actions: first, review the assessment policy; second, ___ parent feedback; and third, update the scope and sequence.",a:"sum ... gather",exp:"'To sum up' = in summary. Numbered actions make summaries clear and actionable. This is the standard meeting summary format."},
        {id:"sr002",type:"mc",q:"Which is the best way to start a summary email after a meeting?",options:["Dear everyone, here is absolutely everything that was discussed in the meeting today.","Hi all, Just a quick summary of today's meeting and the key action items.","The meeting was long. Here's what happened.","As discussed."],a:1,exp:"'Quick summary' and 'key action items' signal the email will be concise and useful. People rarely want every detail — they want the decisions and next steps."},
        {id:"sr003",type:"fill",q:"The main ___ from the PD session was that explicit teaching of vocabulary across all subjects significantly ___ student outcomes.",a:"takeaway ... improves",exp:"'Main takeaway' = the most important lesson/insight. 'Significantly improves' is evidence-based language. This is how you report on professional learning."},
        {id:"sr004",type:"error",q:"In the meeting, we discuss about many topics. The most important one is the new timetable.",a:"In the meeting, we discussed many topics. The most important one was the new timetable.",exp:"'Discussed' (past tense for a completed meeting). 'Was' (past tense). No 'about' after 'discuss'. Consistent past tense for reporting."},
        {id:"sr005",type:"fill",q:"Three key decisions were ___: the assessment deadline will be extended, parent interviews will be held in Week 8, and a new homework ___ will be trialled.",a:"made ... policy",exp:"Passive voice ('decisions were made') is appropriate for formal summaries. Three clear decisions with specific details."},
        {id:"sr006",type:"mc",q:"After attending a PD day, what is the best way to share what you learned with colleagues?",options:["Don't share — it's only relevant to you","Send a 20-page report","Give a brief 5-minute presentation at the next faculty meeting with 3 key takeaways and practical applications","Forward all the PD materials and let them figure it out"],a:2,exp:"Brief, focused sharing with practical applications is the gold standard. 3 key takeaways + how it applies to your school context. Respects colleagues' time."},
        {id:"sr007",type:"fill",q:"In ___, the data suggests that our Year 8 cohort has made significant gains in numeracy but still ___ support in literacy.",a:"summary ... needs",exp:"'In summary' opens a conclusion. 'Significant gains' = meaningful improvement. 'Still needs support' = area for continued work. Balanced reporting."},
        {id:"sr008",type:"error",q:"I want to report back about what we learn at the conference. The speaker talk about many interesting thing.",a:"I'd like to report back on what we learned at the conference. The speaker talked about many interesting topics.",exp:"'Report back on' (not 'about'). 'Learned' (past tense). 'Talked about' (past). 'Things' needs plural or better, use 'topics'. Multiple tense and plural errors."},
        {id:"sr009",type:"fill",q:"The key action ___ from today's meeting are as ___:",a:"items ... follows",exp:"'Key action items' = tasks assigned to people. 'As follows' introduces a list. Standard meeting minutes format."},
        {id:"sr010",type:"open",q:"Summarise a PD session on differentiated instruction in 3-4 sentences for your colleagues.",a:"The PD session focused on practical strategies for differentiating instruction across all subject areas. The main takeaway was that effective differentiation does not mean creating three separate lessons — it means providing multiple entry points to the same learning goal. We looked at three concrete strategies: tiered tasks, flexible grouping, and learning menus. I think the learning menu approach could work particularly well in our Technology classes.",exp:"Key topic, main insight, specific strategies, personal application. This format is concise, practical, and shows reflection."},
        {id:"sr011",type:"fill",q:"Let me ___ bring everyone up to speed on where we're ___ with the project.",a:"quickly ... at",exp:"'Bring everyone up to speed' = update everyone on current status. 'Where we're at' = current position. Informal but professional."},
        {id:"sr012",type:"mc",q:"What should meeting minutes include?",options:["Every word that was said","Only the funny moments","Date, attendees, key decisions, action items with deadlines and owners","The meeting start time only"],a:2,exp:"Minutes should capture: date, who attended, key decisions made, and action items (who does what by when). They are a record and an accountability tool."},
        {id:"sr013",type:"fill",q:"So to ___ what we've agreed — Rachel will handle the parent communication, and I'll ___ the data analysis.",a:"confirm ... complete",exp:"'To confirm what we've agreed' ensures everyone leaves with the same understanding. Assigning specific people to specific tasks creates accountability."},
        {id:"sr014",type:"error",q:"The meeting start at 3pm and finish at 4pm. We talk about many things.",a:"The meeting started at 3 p.m. and finished at 4 p.m. We discussed several topics.",exp:"Past tense: 'started', 'finished'. 'Discussed' is more professional than 'talked about'. 'Several topics' is better than 'many things'. Reporting requires formal language."},
        {id:"sr015",type:"fill",q:"The feedback from the parent survey was overwhelmingly ___. 92% of parents said they felt well-___ about their child's progress.",a:"positive ... informed",exp:"Reporting survey results: percentage + finding. 'Overwhelmingly positive' = very strongly positive. 'Well-informed' = adequately updated."},
        {id:"sr016",type:"fill",q:"Moving ___, the next steps are to finalise the assessment schedule and ___ it to all teaching staff by Friday.",a:"forward ... distribute",exp:"'Moving forward' = from now on / as the next step. 'Distribute to' = send to / share with. Action-oriented summary language."},
        {id:"sr017",type:"mc",q:"What does 'the long and short of it' mean?",options:["It was both long and short","A detailed technical analysis","The essential summary — in brief","A ruler measurement"],a:2,exp:"'The long and short of it is...' means 'the essential point is...' It signals you're cutting through complexity to give the core message."},
        {id:"sr018",type:"error",q:"Below is the summary about today meeting. Please kindly review and revert with your feedback.",a:"Below is the summary of today's meeting. Please review and send me your feedback.",exp:"'Summary of' (not 'about'). 'Today's meeting' (possessive). 'Send me your feedback' not 'revert' (which means 'go back'). 'Kindly' is unnecessary with 'please'."},
        {id:"sr019",type:"fill",q:"I've ___ the main points from the workshop into a one-page ___. I'll email it to everyone this afternoon.",a:"condensed ... summary",exp:"'Condensed into' = compressed/reduced. 'One-page summary' is concise and usable. Offering to share shows initiative."},
        {id:"sr020",type:"open",q:"You observed a colleague's lesson as part of peer observation. Write a brief summary of what you saw.",a:"I observed Rachel's Year 9 English class on Tuesday. The lesson focused on persuasive writing techniques. Strengths I noted: clear learning intention displayed and referred to, excellent use of modelled examples, and strong differentiation through tiered tasks. One area for development: the transition between the group activity and the independent task could have been smoother — a few students were unsure of what to do next. Overall, it was an engaging and well-structured lesson. I particularly liked the way she used student work samples to demonstrate success criteria.",exp:"Structured: context, strengths (specific), growth area (specific and constructive), overall impression, personal takeaway. This is the peer observation format used in many Australian schools."},
        {id:"sr021",type:"fill",q:"The ___ trend we're seeing across the faculty is an increase in student ___ and a decrease in behavioural referrals.",a:"overall ... achievement",exp:"'Overall trend' describes the big picture. 'Increase in achievement, decrease in referrals' presents data positively."},
        {id:"sr022",type:"fill",q:"To put it ___, we need more resources and more time to ___ this properly.",a:"simply ... implement",exp:"'To put it simply' signals a direct, plain-language summary. 'Implement properly' = do it well with proper support."},
        {id:"sr023",type:"mc",q:"What does 'in a nutshell' mean?",options:["Inside a nut","In very brief summary","In a small container","In nature"],a:1,exp:"'In a nutshell' = in the briefest possible summary. 'In a nutshell, we need to change our approach' gives the core message without detail."},
        {id:"sr024",type:"error",q:"To summary the discussion, we will need to redesign the curriculum and also to hire new staff.",a:"To summarise the discussion, we will need to redesign the curriculum and also hire new staff.",exp:"'Summarise' is the verb (Australian spelling). No second 'to' before 'hire' — parallel structure with 'redesign' (both base form after 'need to')."},
        {id:"sr025",type:"fill",q:"Here's a brief ___ of what we covered: assessment moderation, report writing, and the new ___ plan.",a:"overview ... improvement",exp:"'Brief overview' = short summary. Listing topics covered provides a clear record. 'Improvement plan' is a school development document."},
        {id:"sr026",type:"fill",q:"Just to loop ___ — has everyone received the minutes from last ___?",a:"back ... week",exp:"'Loop back' = return to check on something. Confirming everyone received the minutes ensures accountability. Good follow-up practice."},
        {id:"sr027",type:"open",q:"Write a summary email to your head teacher after attending an external PD session.",a:"Hi David, Just a quick summary of the PD session I attended yesterday on 'Using AI Tools in the Classroom'. The session covered three main areas: ethical use of AI, practical classroom applications, and assessment implications. Key takeaways: 1) AI tools should be taught as a skill, not banned. 2) Schools need clear guidelines on AI use in assessments. 3) There are some great free tools we could trial with senior students. I would love to share more at the next faculty meeting if there is time. Happy to chat about it whenever suits you. Cheers, Yunshu",exp:"Structured, concise, actionable. Three numbered takeaways, an offer to share more, and an informal but professional tone."},
        {id:"sr028",type:"fill",q:"In ___, I believe we've made solid progress this term and are well-___ for a strong finish.",a:"conclusion ... positioned",exp:"'In conclusion' marks the final statement. 'Well-positioned for a strong finish' is positive, forward-looking professional language."},
        {id:"sr029",type:"mc",q:"What does 'take minutes' mean in a meeting context?",options:["Steal time from the meeting","Write an official record of what was discussed and decided","Count the minutes on the clock","Take a short break"],a:1,exp:"'Take minutes' = write the official record of the meeting. 'Who's taking minutes today?' is a standard meeting opening question."},
        {id:"sr030",type:"fill",q:"The ___ line is that we need to act quickly if we want to meet the NESA ___ deadline.",a:"bottom ... compliance",exp:"'Bottom line' = the most important point / the essential conclusion. 'NESA compliance' = meeting the standards authority's requirements."},
        {id:"sr031",type:"error",q:"Allow me to summary. We decide to postpone the event and will reorganise it in Term 3.",a:"Allow me to summarise. We decided to postpone the event and will reorganise it in Term 3.",exp:"'Summarise' (verb, Australian spelling). 'Decided' (past tense for the completed decision). 'Will reorganise' is future because that action hasn't happened yet."},
        {id:"sr032",type:"fill",q:"I'll type up the notes and ___ them around by end of day. Please let me know if I've ___ anything.",a:"circulate ... missed",exp:"'Circulate' = distribute to the group. 'End of day' = by this afternoon/evening. 'Let me know if I've missed anything' invites corrections."},
        {id:"sr033",type:"fill",q:"The general ___ from the group was that we should proceed with caution and ___ the results after one term.",a:"consensus ... evaluate",exp:"'General consensus' = overall agreement. 'Proceed with caution' = go ahead carefully. 'Evaluate results' = assess outcomes. Measured, professional summary."},
        {id:"sr034",type:"mc",q:"What is the best way to present data in a report?",options:["Just list all the numbers","Use visuals like graphs and tables, with brief written explanations of what the data shows","Only use words, no numbers","Present raw data without any interpretation"],a:1,exp:"Data should be presented visually with explanations. 'What does this data tell us?' is the key question. Raw numbers without context are meaningless."},
        {id:"sr035",type:"fill",q:"That ___ up our meeting for today. Thanks for your time, everyone. See you next ___.",a:"wraps ... week",exp:"'That wraps up our meeting' = that concludes our meeting. 'Thanks for your time' is a standard, warm close. Efficient meeting management."},
        {id:"sr036",type:"error",q:"To summary, we will implement the new system from next term. All teacher should prepare for the change.",a:"To summarise, we will implement the new system from next term. All teachers should prepare for the change.",exp:"'Summarise' (verb form, Australian spelling). 'Teachers' (plural). These are common Chinese speaker errors in formal writing."},
        {id:"sr037",type:"fill",q:"Here are the key ___ from today's discussion, along with the agreed ___ and deadlines.",a:"outcomes ... actions",exp:"'Key outcomes' = main results/decisions. 'Agreed actions' = tasks everyone committed to. Standard meeting summary format."},
        {id:"sr038",type:"fill",q:"I've ___ the notes into three main categories: curriculum changes, assessment updates, and staffing ___.",a:"organised ... matters",exp:"'Organised into categories' shows clear thinking. Three named categories help readers scan quickly. 'Staffing matters' = HR/personnel issues. Note: 'organised' Australian spelling."}
      ]
    },
    {
      id: "professional-disagreement",
      title: "Polite Disagreement & Alternatives",
      theory: "Disagreeing professionally in Australian culture requires softening phrases, evidence, and alternatives. Never say 'You're wrong' — instead, 'I see it differently' or 'I have a different take on this'. The pattern is: acknowledge + disagree softly + offer alternative + invite discussion.",
      exercises: [
        {id:"pd001",type:"fill",q:"I see where you're coming from, but I have a slightly different ___ on this ___.",a:"take ... issue",exp:"'Different take' = different perspective/viewpoint. 'On this issue' focuses the disagreement. Acknowledging their position first is crucial."},
        {id:"pd002",type:"mc",q:"Your principal proposes something you disagree with. What is the best approach?",options:["Tell them they're wrong in front of everyone","Request a private meeting to discuss your concerns","Publicly disagree to show you have strong opinions","Agree but secretly do something different"],a:1,exp:"Private discussion shows respect and professionalism. Public disagreement with a superior can damage the relationship. Present evidence and alternatives privately."},
        {id:"pd003",type:"fill",q:"I ___ your point, however I'm not sure that approach would work with our particular student ___.",a:"take ... cohort",exp:"'I take your point' = I understand. 'However' is softer than 'but' for disagreement. 'Our particular cohort' = our specific group of students."},
        {id:"pd004",type:"error",q:"No, I don't think so. Your idea will not work. We should do my way instead.",a:"I'm not sure that would work in our context. Could I suggest an alternative approach that might address the same issue?",exp:"Direct rejection is too confrontational. 'Not sure it would work in our context' is diplomatic. Offering an alternative is constructive."},
        {id:"pd005",type:"fill",q:"That's one way to look at it. ___, we could also consider approaching it from the angle of student ___.",a:"Alternatively ... voice",exp:"'That's one way to look at it' is diplomatic. 'Alternatively' introduces another option. 'Student voice' = listening to students' perspectives."},
        {id:"pd006",type:"mc",q:"Which phrase best introduces a disagreement in a meeting?",options:["That's ridiculous.","With all due respect, I see it a bit differently.","You clearly haven't thought this through.","Let me tell you why you're wrong."],a:1,exp:"'With all due respect' + 'I see it a bit differently' is the classic polite disagreement formula. It acknowledges the relationship while signalling a different view."},
        {id:"pd007",type:"fill",q:"I respect your ___, but I'm worried that this could have some unintended ___ for our EAL/D students.",a:"perspective ... consequences",exp:"'Respect your perspective' validates them. 'Unintended consequences' raises a specific concern. Focusing on a vulnerable group strengthens the argument."},
        {id:"pd008",type:"error",q:"I am not agree with this plan. I think it is totally wrong and we must change it.",a:"I'm not fully convinced by this plan. I have some concerns I'd like to raise, and I think we could make some adjustments.",exp:"'Not fully convinced' is softer than 'not agree'. 'Some concerns' is less absolute than 'totally wrong'. 'Adjustments' is collaborative."},
        {id:"pd009",type:"fill",q:"I hear what you're saying, but my ___ tells me we need to tread carefully. Could we do a ___ trial first?",a:"experience ... small",exp:"'My experience tells me' grounds disagreement in personal expertise. 'Tread carefully' = proceed cautiously. 'Small trial' is a compromise."},
        {id:"pd010",type:"mc",q:"A colleague insists on their approach despite your concerns. What do you do?",options:["Keep arguing until they give in","Clearly state your concern once more, then accept the decision and move on","Give them the silent treatment","Complain to the principal"],a:1,exp:"State your concern clearly, then respect the collective decision. Professional maturity means knowing when to advocate and when to accept. You can revisit if new evidence emerges."},
        {id:"pd011",type:"fill",q:"I think there might be a middle ___ here. What if we combined elements of both ___ and evaluated the results?",a:"ground ... approaches",exp:"'Middle ground' = compromise position. 'Combined elements of both' = a synthesis. Offering a compromise is a leadership skill."},
        {id:"pd012",type:"error",q:"I am sorry but I must disagree to you. This method is not good for the students.",a:"I'm sorry, but I have to disagree on this point. I'm not sure this method is the best option for our students.",exp:"'Disagree on this point' (not 'disagree to you'). 'Not the best option' is softer than 'not good'. Focusing the disagreement on the method, not the person."},
        {id:"pd013",type:"fill",q:"With the ___ of respect, I think we need to look at the evidence more closely before making a ___.",a:"greatest ... decision",exp:"'With the greatest of respect' signals a firm but polite disagreement is coming. 'Look at evidence more closely' advocates for evidence-based decision-making."},
        {id:"pd014",type:"open",q:"Your head teacher wants to reduce Technology class time from 3 periods to 2 per week. Write your professional response.",a:"I appreciate you sharing this proposal, and I understand the pressures on the timetable. However, I do have some significant concerns about reducing Technology from three periods to two. The practical nature of our subject means that students need adequate time for hands-on projects. Reducing to two periods would mean either cutting content or rushing through tasks, neither of which would serve the students well. Could we explore some alternatives? For example, perhaps we could restructure the lesson blocks rather than reducing the total time. I am happy to sit down and work through the options with you.",exp:"Acknowledge the constraint, present specific concerns with evidence, propose alternatives, offer to collaborate. This is professional advocacy for your subject."},
        {id:"pd015",type:"fill",q:"I appreciate the ___ behind the idea, but in practice I think we'd face some significant ___ challenges.",a:"intention ... logistical",exp:"Separating the intention (good) from the practice (problematic) is a diplomatic disagreement technique. 'Logistical challenges' names practical issues."},
        {id:"pd016",type:"mc",q:"What does 'let's agree to disagree' mean?",options:["We both agree now","We accept that we have different views and will not try to convince each other further","We are enemies now","One of us must be wrong"],a:1,exp:"'Agree to disagree' is a mature way to end a disagreement where neither side will change their mind. It maintains the relationship while acknowledging different views."},
        {id:"pd017",type:"fill",q:"I don't want to be ___, but I think we're ignoring a critical aspect of this — the ___ on teacher workload.",a:"negative ... impact",exp:"'Don't want to be negative' disclaims while introducing a concern. 'Ignoring a critical aspect' politely points out an oversight."},
        {id:"pd018",type:"error",q:"I think your plan have some weakness. We need to think more deeper about this problem.",a:"I think the plan has a few areas that could be strengthened. We need to think more deeply about this issue.",exp:"'Plan has' (singular). 'Areas to be strengthened' is positive framing. 'More deeply' (adverb form). 'Issue' is more professional than 'problem'."},
        {id:"pd019",type:"fill",q:"Could I offer an alternative ___? What if instead of cancelling the programme, we ___ it to better suit our needs?",a:"suggestion ... adapted",exp:"'Offer an alternative suggestion' positions your idea alongside theirs. 'Adapted it' = modified to fit. Better than complete rejection."},
        {id:"pd020",type:"fill",q:"I'm playing devil's ___ here, but what if the data is actually telling us the opposite of what we ___?",a:"advocate ... think",exp:"Devil's advocate framing allows you to challenge without personal commitment. Questioning data interpretation is intellectually rigorous."},
        {id:"pd021",type:"mc",q:"What is the best way to disagree with something in a written report?",options:["Write 'WRONG' in the margin","Provide specific evidence-based comments that propose alternatives","Cross out the section you disagree with","Don't say anything and hope it changes"],a:1,exp:"Written disagreements must be evidence-based and constructive. Name the specific concern, provide evidence, and suggest an alternative."},
        {id:"pd022",type:"fill",q:"I respect that decision, even though I have ___ about it. I'll commit to giving it a fair ___ and we can review after one term.",a:"reservations ... trial",exp:"'Have reservations' = have concerns but accept. 'Give it a fair trial' = try it properly. 'Review after one term' builds in an evaluation point. Professional maturity."},
        {id:"pd023",type:"error",q:"Even though I am not agree, I will follow the decision. But I think later you will know I am right.",a:"Even though I don't agree, I will follow the decision. I hope we can revisit this if the results don't meet expectations.",exp:"'Don't agree' (not 'am not agree'). 'I hope we can revisit' is collaborative. 'You will know I am right' is unprofessional and adversarial."},
        {id:"pd024",type:"fill",q:"I think we owe it to ourselves to ___ all the options before committing to a particular ___ of action.",a:"explore ... course",exp:"'Owe it to ourselves' creates shared responsibility. 'Explore all options' advocates for thorough consideration. 'Course of action' = chosen path."},
        {id:"pd025",type:"open",q:"A colleague says 'We should just give all students the same work — differentiation is too much effort.' Write a diplomatic response that challenges this view.",a:"I understand where you are coming from — differentiation can feel like a lot of extra work, especially when you are already stretched thin. But from what I have seen, when we differentiate effectively, it actually saves time in the long run because students are more engaged and we spend less time managing behaviour. Even small changes, like providing a word bank for struggling students or an extension question for advanced ones, can make a big difference without doubling your workload. Would you be open to trying one or two simple strategies and seeing how it goes?",exp:"Validate the feeling, provide evidence, offer simple entry points, suggest a trial. You challenge the idea without attacking the person."},
        {id:"pd026",type:"fill",q:"I'm not trying to be ___, but I think it's important that we ___ the potential risks before proceeding.",a:"difficult ... acknowledge",exp:"'Not trying to be difficult' softens the challenge. 'Acknowledge potential risks' advocates for due diligence."},
        {id:"pd027",type:"mc",q:"What is the difference between 'I disagree' and 'I'm not sure I agree'?",options:["They mean exactly the same thing","'I'm not sure I agree' is softer and less confrontational — it leaves room for discussion","'I disagree' is more polite","'I'm not sure I agree' means you don't understand"],a:1,exp:"'I'm not sure I agree' is deliberately ambiguous — it signals disagreement while keeping the door open. It is less likely to trigger a defensive reaction."},
        {id:"pd028",type:"fill",q:"Let's ___ back and look at this from a different ___. What are we actually trying to achieve here?",a:"step ... perspective",exp:"'Step back' = pause and reconsider. 'Different perspective' = new angle. Refocusing on the goal can resolve disagreements productively."},
        {id:"pd029",type:"error",q:"I have different opinion from you. I think we should not do this because it will waste time and money.",a:"I have a different perspective on this. My concern is that it may not be the most efficient use of our time and resources.",exp:"'A different perspective' (needs article). 'May not be the most efficient use' is diplomatic. 'Waste time and money' is too blunt for professional discourse."},
        {id:"pd030",type:"fill",q:"I value your ___, and I think we both want the same ___ — we just differ on how to get there.",a:"input ... outcome",exp:"'Value your input' honours their contribution. 'Same outcome' finds common ground. 'Differ on how' focuses the disagreement on method, not goal."},
        {id:"pd031",type:"error",q:"I am opposite your idea. I think your plan cannot work.",a:"I have a different view on this. I'm not confident the plan would work as intended.",exp:"'I am opposite' is Chinglish from 我反对. English: 'I have a different view' or 'I disagree'. 'Cannot work' is too absolute — 'wouldn't work as intended' is softer."},
        {id:"pd032",type:"fill",q:"I appreciate the ___ you've put into this, but I wonder if we've considered all the ___ implications.",a:"thought ... practical",exp:"Validating their effort before raising concerns. 'Practical implications' grounds the disagreement in real-world impact."},
        {id:"pd033",type:"mc",q:"What is the difference between 'I don't agree' and 'I don't entirely agree'?",options:["They mean the same thing","'I don't entirely agree' is stronger disagreement","'I don't entirely agree' signals partial disagreement — you agree with some parts","'I don't agree' is more polite"],a:2,exp:"'Not entirely' softens the disagreement — you're saying 'I agree with parts but not all of it'. This is more nuanced and professional than outright disagreement."},
        {id:"pd034",type:"fill",q:"That's a fair point. I hadn't ___ it from that angle. Let me ___ on it.",a:"considered ... reflect",exp:"Showing willingness to reconsider is a sign of professional maturity. 'Hadn't considered it from that angle' and 'reflect on it' show intellectual openness."},
        {id:"pd035",type:"fill",q:"I think we need to ___ the elephant in the room. Nobody seems willing to ___ that the current approach isn't working.",a:"address ... admit",exp:"'Address the elephant in the room' = raise the obvious issue nobody is talking about. Powerful professional communication skill for meetings."}
      ]
    }
  ]
},
// ============================================================
// MODULE 5: WRITTEN PROFESSIONAL REFLECTIONS
// ============================================================
writtenReflections: {
  title: "Written Professional Reflections",
  sections: [
    {
      id: "lesson-reflections",
      title: "Lesson Reflections & Self-Evaluation",
      theory: "Reflective practice is central to Australian teaching. After each lesson, you should consider what worked, what didn't, and what you would change. Written reflections for your PDP (Professional Development Plan) use professional language. The framework is usually: describe, analyse, evaluate, plan. Chinese speakers may find self-evaluation uncomfortable due to cultural humility norms, but in Australia it is expected and valued.",
      exercises: [
        {id:"lr001",type:"fill",q:"The lesson went ___ overall, but I noticed that the transition between activities was not as ___ as I had planned.",a:"well ... smooth",exp:"'Went well overall' is an honest positive start. 'Not as smooth as planned' is specific and self-aware. Good reflection is balanced."},
        {id:"lr002",type:"mc",q:"Which is the best opening for a lesson reflection?",options:["The lesson was OK.","Today's lesson on electrical circuits achieved its learning intention, with most students demonstrating an understanding of series and parallel circuits by the end of the period.","The students were difficult today.","I taught the lesson about circuits."],a:1,exp:"Links lesson to learning intention and assesses student understanding. Specific, evidence-based, and focused on learning outcomes rather than the teacher's feelings."},
        {id:"lr003",type:"fill",q:"One area where I could ___ is my questioning technique. I tended to ask ___ questions rather than open-ended ones.",a:"improve ... closed",exp:"'Could improve' is self-aware. 'Closed vs open-ended questions' is a specific pedagogical term. Naming the specific weakness shows professional understanding."},
        {id:"lr004",type:"error",q:"The lesson is not going well because students are not listen to me. I will try to do better next time.",a:"The lesson did not go as well as I had hoped because students struggled to stay focused during the explanation. Next time, I will try breaking the explanation into shorter segments with check-for-understanding questions in between.",exp:"Past tense for completed events. 'Struggled to stay focused' is more professional than 'not listen to me'. The improvement plan must be specific."},
        {id:"lr005",type:"fill",q:"Student ___ was high during the practical activity, but ___ noticeably during the written component.",a:"engagement ... dropped",exp:"'Engagement' is the key metric. 'Dropped noticeably' = decreased clearly. Observing patterns helps plan future lessons."},
        {id:"lr006",type:"mc",q:"What does 'differentiation' look like in a reflection?",options:["I gave everyone the same work.","I noticed that the support group benefited from the sentence starters, while the extension group was challenged by the open-ended design task.","I didn't have time for differentiation.","Differentiation is not necessary for my students."],a:1,exp:"Evidence-based differentiation reflection: what was provided, who benefited, and how you know. This shows effective practice and awareness."},
        {id:"lr007",type:"fill",q:"In ___, the lesson achieved its primary learning objective, but there is room for improvement in how I ___ for student diversity.",a:"hindsight ... catered",exp:"'In hindsight' = looking back with reflection. 'Catered for student diversity' = addressed different needs. Professional self-evaluation language."},
        {id:"lr008",type:"error",q:"I think my lesson was very success. All students enjoy the activity and learn many new things.",a:"I believe my lesson was largely successful. Most students appeared to enjoy the activity and demonstrated learning of the key concepts.",exp:"'Largely successful' is more measured. 'Appeared to enjoy' is more accurate than asserting inner states. 'Demonstrated learning' is evidence-based."},
        {id:"lr009",type:"fill",q:"Next time, I would ___ more time for the independent practice phase and less time on the teacher-led ___.",a:"allocate ... explanation",exp:"'Allocate more time' = plan more time. Specific time management adjustments show professional growth."},
        {id:"lr010",type:"open",q:"Write a brief reflection on a lesson where the technology failed (projector didn't work).",a:"The lesson on digital design had to be significantly adapted when the projector stopped working at the start of the period. I quickly pivoted to a whiteboard-based explanation and used printed handouts that I had as a backup. While the lesson still covered the key content, the visual demonstrations I had planned were lost, which affected student understanding of the design process. Key learning: always have a non-digital backup plan. Next time, I will prepare printed screenshots of key design examples that I can distribute if technology fails.",exp:"Describes what happened, what you did, the impact, and what you learned. Specific and actionable. This is exactly what supervisors want to see in reflections."},
        {id:"lr011",type:"fill",q:"The formative assessment data ___ that approximately 70% of students have ___ the learning intention for this unit.",a:"indicates ... achieved",exp:"Using data in reflections is best practice. 'Indicates' is more tentative than 'proves'. '70% achieved' is specific and measurable."},
        {id:"lr012",type:"mc",q:"Which reflection shows the deepest level of analysis?",options:["The lesson went fine.","Students completed the task.","I noticed that students who worked in mixed-ability groups produced stronger work than those in ability-grouped tables, which challenges my usual grouping strategy and suggests I should trial mixed grouping more often.","The students liked the activity."],a:2,exp:"This reflection observes a pattern, questions current practice, and proposes a change based on evidence. This is analytical reflection, not just description."},
        {id:"lr013",type:"fill",q:"A ___ I would make is to provide clearer success ___ at the start of the lesson so students know what they are working towards.",a:"change ... criteria",exp:"'A change I would make' frames it positively as improvement. 'Clearer success criteria' is a specific, actionable adjustment."},
        {id:"lr014",type:"error",q:"I am very satisfy with my teaching today. The students all understand the content.",a:"I am quite satisfied with how the lesson went today. Most students appeared to grasp the key concepts based on their exit ticket responses.",exp:"'Satisfied' (adjective form). 'Quite' softens the claim. 'Appeared to grasp' is more evidence-based. 'Based on exit tickets' cites evidence."},
        {id:"lr015",type:"fill",q:"The Think-Pair-Share strategy worked ___ than expected. Students who rarely contribute were actively ___ in the pair discussion.",a:"better ... participating",exp:"Noting when a strategy exceeds expectations is valuable. 'Rarely contribute' and 'actively participating' show observable change."},
        {id:"lr016",type:"fill",q:"On ___, the lesson achieved its goals. However, the pacing was slightly off — I spent too long on the ___ and rushed the conclusion.",a:"reflection ... introduction",exp:"'On reflection' = looking back. 'Pacing was slightly off' is specific. Naming what took too long and what was rushed is actionable analysis."},
        {id:"lr017",type:"mc",q:"What is an 'exit ticket' in teaching?",options:["A permission slip to leave","A quick assessment at the end of a lesson to check understanding","A bus pass","A reward for good behaviour"],a:1,exp:"Exit tickets are brief tasks (1-3 questions) at the end of a lesson that check whether students have understood the key concept. Excellent formative assessment tool."},
        {id:"lr018",type:"error",q:"I plan to modified my teaching approach next term. I will try use more group work activities.",a:"I plan to modify my teaching approach next term. I will try to use more group work activities.",exp:"'Plan to modify' (infinitive after 'plan to'). 'Try to use' (infinitive after 'try'). Base forms after 'to', not past participles."},
        {id:"lr019",type:"fill",q:"The most ___ aspect of the lesson was the student-led discussion, where students ___ their ideas with genuine enthusiasm.",a:"effective ... shared",exp:"'Most effective aspect' identifies the highlight. 'Shared with genuine enthusiasm' names the observable behaviour."},
        {id:"lr020",type:"open",q:"Write a reflection on a lesson where behaviour management was challenging.",a:"The lesson on sustainable design was disrupted by a small group of students who were off-task and talking over instructions. I used our school's behaviour management steps: a verbal warning, then a choice, and finally a temporary removal to the buddy room for one student. While I managed the situation, I recognise that the disruption occurred because my instructions were too long and the task was not sufficiently scaffolded for the lower-ability students. Next time, I will break the instructions into three short steps with a visual checklist and provide a modified version of the task for students who need additional support.",exp:"Honest about what happened, identifies the root cause (instructions too long, insufficient scaffolding), and proposes specific changes. Does not blame students — looks for what the teacher can control."},
        {id:"lr021",type:"fill",q:"I need to build more ___ into my lesson plans to accommodate unexpected ___ that arise during the lesson.",a:"flexibility ... issues",exp:"'Build flexibility into plans' is a mature teaching insight. Recognising the gap between plans and reality is key to reflective practice."},
        {id:"lr022",type:"mc",q:"What framework is commonly used for reflection in Australian teaching?",options:["The ABC model","The What-So What-Now What model","The XYZ framework","The One-Two-Three approach"],a:1,exp:"'What? So what? Now what?' is one of the most common reflection frameworks. What happened? Why does it matter? What will you do next? Simple and effective."},
        {id:"lr023",type:"fill",q:"My questioning technique has ___ over the term. I now use more open-ended ___ that promote critical thinking.",a:"improved ... questions",exp:"Tracking growth over time is powerful. 'Open-ended questions that promote critical thinking' names a specific pedagogical improvement."},
        {id:"lr024",type:"error",q:"If I can do this lesson again, I will change the group activity. It take too much time and students get bored.",a:"If I could do this lesson again, I would change the group activity. It took too much time and students became bored.",exp:"Hypothetical: 'If I could... I would' (second conditional). 'Took' and 'became' (past tense for the completed lesson). Conditional structures are challenging for Chinese speakers."},
        {id:"lr025",type:"fill",q:"The co-teaching model worked ___ well today. Having two teachers in the room allowed us to provide more ___ support.",a:"particularly ... individualised",exp:"'Co-teaching' is increasingly common in Australian schools. 'Individualised support' names the benefit. Note Australian spelling: 'individualised'."},
        {id:"lr026",type:"fill",q:"Looking ___, I realise that my expectations for the task were too ___ for this particular group of students.",a:"back ... ambitious",exp:"'Looking back' = in retrospect. 'Too ambitious' = the task was too difficult/complex. Honest self-assessment without self-blame."},
        {id:"lr027",type:"open",q:"Write a mid-year reflection on your overall teaching progress.",a:"At the halfway point of the year, I am pleased with the progress I have made in several areas. My classroom management has improved significantly — I am more consistent with routines and more confident in addressing behaviour issues. My lesson planning has become more structured, with clearer learning intentions and better differentiation. One area I still need to develop is my use of formative assessment during lessons. I tend to rely on whole-class questioning rather than strategies that check every student's understanding. My goal for the second half of the year is to implement exit tickets and mini-whiteboards as regular check-for-understanding tools.",exp:"Balanced: strengths, growth areas, specific goals. Links to professional standards. This is exactly the kind of reflection expected in a PDP review meeting."},
        {id:"lr028",type:"fill",q:"This experience has ___ me the importance of being ___ when things don't go according to plan.",a:"taught ... adaptable",exp:"'Taught me the importance of' is a reflective insight phrase. 'Being adaptable' is a key professional quality."},
        {id:"lr029",type:"mc",q:"What does 'evidence-based practice' mean in Australian education?",options:["Collecting physical evidence from students","Using research and data to inform teaching decisions","Practising for evidence collection","Writing lots of documentation"],a:1,exp:"Evidence-based practice means using research findings, student data, and professional observation to make teaching decisions. It is a core expectation in Australian schools."},
        {id:"lr030",type:"fill",q:"The student ___ results from this task will inform my planning for the next ___.",a:"assessment ... unit",exp:"Using assessment data to plan future lessons is the cycle of teaching. 'Inform my planning' shows data-driven practice."},
        {id:"lr031",type:"error",q:"I feel that I making progress in my teaching. The students respect me more than before.",a:"I feel that I am making progress in my teaching. The students seem to respect me more than they did at the start of the year.",exp:"'I am making' (present continuous). 'Seem to respect' is more measurable than asserting. 'Than they did at the start' provides a comparison point."},
        {id:"lr032",type:"fill",q:"My mentor ___ me to try using visual cues instead of verbal instructions for transitions. This significantly ___ the time wasted between activities.",a:"encouraged ... reduced",exp:"Mentoring feedback + implementation + result. This shows you act on advice and measure the impact. Excellent reflective practice."},
        {id:"lr033",type:"fill",q:"One of my key ___ this term has been developing stronger relationships with students, which has ___ impacted both behaviour and learning.",a:"achievements ... positively",exp:"Naming your achievements in reflections builds confidence. 'Positively impacted both behaviour and learning' shows holistic awareness."},
        {id:"lr034",type:"mc",q:"What is a PDP in the Australian teaching context?",options:["Personal Data Protection","Professional Development Plan","Pupil Development Programme","Performance Deficit Protocol"],a:1,exp:"PDP = Professional Development Plan. All Australian teachers maintain one. It includes goals, evidence of progress, and reflection. Reviewed with your supervisor regularly."},
        {id:"lr035",type:"fill",q:"In my next observation, I would like to focus on demonstrating my use of ___ assessment strategies and how I ___ them to adjust my teaching in real time.",a:"formative ... use",exp:"Proactively choosing a focus for observation shows professional initiative. 'Adjust teaching in real time' = responsive teaching."},
        {id:"lr036",type:"error",q:"The lesson was not success because I did not prepare enough. I should have spend more time on planning.",a:"The lesson was not successful because I did not prepare enough. I should have spent more time on planning.",exp:"'Successful' (adjective form needed after 'was'). 'Should have spent' (modal perfect = should have + past participle). Chinese speakers struggle with modal perfect tense."},
        {id:"lr037",type:"fill",q:"If I were to teach this lesson again, I would ___ the group sizes and allow more time for peer ___.",a:"reduce ... feedback",exp:"'If I were to' (hypothetical). 'Reduce group sizes' and 'more time for peer feedback' are specific, actionable changes — not vague intentions."},
        {id:"lr038",type:"mc",q:"What is the most important element of a good lesson reflection?",options:["Describing what happened in detail","Blaming external factors for what went wrong","Analysing WHY something worked or didn't, and planning what to change next time","Listing all the activities you did"],a:2,exp:"Analysis (why) and forward planning (what next) are more valuable than description (what happened). Good reflections ask 'why?' and 'so what?' not just 'what?'"},
        {id:"lr039",type:"fill",q:"The data from the pre-test and post-test ___ that student understanding of the topic ___ significantly over the unit.",a:"shows ... improved",exp:"Pre/post test comparison is strong evidence of learning. 'Shows that' introduces evidence. 'Improved significantly' quantifies growth."},
        {id:"lr040",type:"fill",q:"One unexpected ___ of the lesson was how well the lower-ability students ___ to the hands-on activity.",a:"outcome ... responded",exp:"Noticing unexpected outcomes shows awareness. 'Lower-ability students responded well' challenges assumptions about differentiation. Insightful observation."}
      ]
    },
    {
      id: "incident-reports",
      title: "Incident Reports & Documentation",
      theory: "Incident reports in Australian schools must be factual, objective, and timely. They document what happened (not what you think happened), who was involved, what action was taken, and any follow-up needed. These are legal documents. Use past tense, avoid emotional language, and distinguish between observation and inference.",
      exercises: [
        {id:"ir001",type:"fill",q:"At approximately 1:15 p.m., a physical ___ occurred between two Year 9 students in the ___ near Block C.",a:"altercation ... playground",exp:"'Physical altercation' is the formal term for a fight. 'Approximately 1:15 p.m.' provides precise timing. 'Playground near Block C' gives specific location."},
        {id:"ir002",type:"mc",q:"Which sentence is appropriate for an incident report?",options:["The student was acting like a total idiot.","Student A pushed Student B against the wall, causing Student B to fall to the ground.","Something happened between the two boys.","The student was clearly trying to start a fight."],a:1,exp:"Factual, specific, observable actions. No judgements ('idiot'), vague language ('something'), or assumptions about intent ('trying to start'). Report what you SAW."},
        {id:"ir003",type:"fill",q:"I ___ the two students and directed Student A to sit on the bench while I checked that Student B was not ___.",a:"separated ... injured",exp:"'Separated the students' = intervened physically or verbally. Checking for injuries is the first priority. Record your actions in sequence."},
        {id:"ir004",type:"error",q:"The boy was fight with his classmate because he is always angry and have behaviour issues.",a:"Student A was involved in a physical altercation with Student B. Student A has had previous behavioural incidents documented this term.",exp:"No 'was fight' — 'was involved in'. Use neutral identifiers ('Student A'). 'Has had previous incidents documented' replaces 'always angry' with factual history."},
        {id:"ir005",type:"fill",q:"The student was ___ to the first aid room for assessment. The school nurse confirmed no ___ injuries.",a:"escorted ... serious",exp:"'Escorted to first aid' = accompanied to medical support. 'No serious injuries confirmed' is factual reporting of the medical assessment."},
        {id:"ir006",type:"mc",q:"What should NOT be included in an incident report?",options:["The time and location of the incident","Your personal opinions about the student's character","The names of witnesses","The actions taken by staff"],a:1,exp:"Incident reports must be objective. Personal opinions, character judgements, and assumptions about intent do NOT belong. Only include observable facts."},
        {id:"ir007",type:"fill",q:"Witnesses to the incident include ___ from the same year group and the duty ___, Mr Peters.",a:"three students ... teacher",exp:"Recording witnesses is essential for investigation. Include students and any staff present. Numbers and names matter."},
        {id:"ir008",type:"error",q:"I think the student is lying about what happen. He probably start the fight.",a:"Student A's account of the incident differs from the accounts given by witnesses. A full investigation is needed to determine what occurred.",exp:"No assumptions about lying or blame. 'Accounts differ' is factual. 'Investigation is needed' is the proper next step. Never write your suspicions in a formal report."},
        {id:"ir009",type:"fill",q:"The deputy principal was ___ immediately, and the student's parents were ___ by phone at 2:30 p.m.",a:"notified ... contacted",exp:"'Notified' (informed) and 'contacted' (communicated with) are formal reporting verbs. Recording who was told and when is essential."},
        {id:"ir010",type:"open",q:"Write an incident report about a student who was found with a mobile phone during an exam.",a:"Date: 19 March 2026. Time: 10:45 a.m. Location: Exam Hall, Block A. During the Year 10 Science examination, I observed Student C reach into their pocket and view what appeared to be a mobile phone under the desk. I approached the student and asked them to hand over the device. The student complied and the phone was confiscated. The student was allowed to continue the exam. The phone was handed to the deputy principal, Ms Thompson, at 11:00 a.m. Student C's parents were contacted by the deputy principal at 12:30 p.m. The exam paper has been flagged for review to determine whether academic integrity was compromised.",exp:"Structured: date, time, location, observation, action taken, follow-up. Factual language. 'What appeared to be' (not assuming). 'Flagged for review' shows proper process."},
        {id:"ir011",type:"fill",q:"The student ___ the classroom without permission at 11:20 a.m. I ___ the front office immediately.",a:"left ... notified",exp:"'Left without permission' is factual. 'Notified the front office' is the correct protocol for a missing student. Time stamps matter."},
        {id:"ir012",type:"mc",q:"What is the correct tense for incident reports?",options:["Present tense","Future tense","Past tense","Present perfect tense"],a:2,exp:"Incident reports describe completed events, so past tense is standard: 'The student threw...', 'I observed...', 'The deputy was notified...'. Consistent tense is essential."},
        {id:"ir013",type:"fill",q:"I have ___ this report in the school's online reporting system (Sentral) and ___ a copy to the year adviser.",a:"logged ... forwarded",exp:"'Logged in the system' = recorded officially. 'Sentral' is a common school management system in NSW. 'Forwarded a copy' ensures relevant staff are informed."},
        {id:"ir014",type:"error",q:"The student use bad language to me. I was very angry but I try to stay calm.",a:"The student directed inappropriate language towards me. I remained calm and followed the school's behaviour management procedures.",exp:"'Directed inappropriate language towards' is formal. 'Remained calm and followed procedures' is professional. Never record your emotional state — record your actions."},
        {id:"ir015",type:"fill",q:"A restorative ___ between the two students has been scheduled for tomorrow at ___.",a:"conversation ... recess",exp:"'Restorative conversation' is the follow-up process. Scheduling it promptly shows proper procedure. 'At recess' provides timing."},
        {id:"ir016",type:"fill",q:"Following the incident, a safety ___ was implemented for Student B, including changed seating and supervised ___.",a:"plan ... transitions",exp:"Safety plans protect vulnerable students. 'Changed seating' and 'supervised transitions' are specific protective measures."},
        {id:"ir017",type:"mc",q:"What does 'mandatory reporting' mean in NSW schools?",options:["Reporting attendance data","A legal obligation for teachers to report suspected child abuse or neglect to the Department","Submitting lesson plans","Reporting on student grades"],a:1,exp:"Mandatory reporting in NSW means teachers MUST report any reasonable suspicion of child abuse, neglect, or risk of significant harm to the Department of Communities and Justice. This is a legal obligation."},
        {id:"ir018",type:"error",q:"I am writing to report about an incident that occur in my class yesterday. One student hit other student.",a:"I am writing to report an incident that occurred in my class yesterday. One student struck another student.",exp:"'Report an incident' (no 'about'). 'Occurred' (past tense). 'Struck another student' is formal incident language. Formal register throughout."},
        {id:"ir019",type:"fill",q:"The student disclosed to me that they are experiencing difficulties at home. I have ___ this to the school ___ in accordance with school policy.",a:"reported ... counsellor",exp:"'Disclosed' = told me voluntarily. 'Reported to the counsellor' follows mandatory reporting and welfare protocols. Note Australian spelling: 'counsellor'."},
        {id:"ir020",type:"open",q:"Write a brief incident report about a student who had an anxiety attack in your classroom.",a:"Date: 19 March 2026. Time: 9:30 a.m. Location: Room 205, Technology block. During Period 2, Student D showed signs of distress including rapid breathing, tearfulness, and inability to speak. I moved the other students to a quiet activity and sat with Student D, speaking calmly and encouraging slow breathing. I sent a student to the front office to request the school counsellor. Ms Rodriguez (counsellor) arrived at 9:40 a.m. and took Student D to the wellbeing room. Student D's parents were contacted by Ms Rodriguez at 10:00 a.m. I followed up with Ms Rodriguez at lunch to ensure appropriate support was in place. I will continue to monitor Student D and check in with them at the start of each lesson.",exp:"Calm, factual, focused on actions taken and support provided. No diagnosis (say 'signs of distress', not 'anxiety attack'). Follow-up plan included."},
        {id:"ir021",type:"fill",q:"All staff members present during the incident have been asked to provide ___ written ___ by the end of today.",a:"individual ... statements",exp:"Independent statements from all witnesses prevent accounts from being influenced. 'By end of today' ensures timely documentation."},
        {id:"ir022",type:"mc",q:"When documenting a student's exact words, what should you use?",options:["Paraphrase them","Use direct quotes with quotation marks","Summarise the general idea","Don't record what they said"],a:1,exp:"Direct quotes preserve the exact words spoken. Write: 'Student A said, \"I didn't touch him.\"' This is important for accuracy and potential investigations."},
        {id:"ir023",type:"fill",q:"I observed that the student appeared ___ and was unable to ___ in the lesson following the incident.",a:"distressed ... concentrate",exp:"'Appeared distressed' (observation, not diagnosis). 'Unable to concentrate' describes the impact on learning. Recording post-incident behaviour is important."},
        {id:"ir024",type:"error",q:"Because the student always have problem, I think he should be suspend from the school.",a:"Based on the pattern of incidents this term, I recommend that the situation be reviewed by the senior executive team to determine appropriate next steps.",exp:"'Always have problem' is judgemental. 'Pattern of incidents' is factual. Teachers recommend review, not specific punishments. Decisions about suspension are made by the principal."},
        {id:"ir025",type:"fill",q:"This report is ___ and may be subject to review by the school executive, parents, and the ___.",a:"confidential ... Department",exp:"Incident reports are confidential documents. 'Subject to review' means authorised people may read them. 'The Department' = NSW Department of Education."},
        {id:"ir026",type:"fill",q:"A follow-up meeting with the student's parents has been ___ for Friday 21 March at 3:30 p.m. in the ___.",a:"scheduled ... front office",exp:"Recording follow-up actions shows professional thoroughness. Specific date, time, and location."},
        {id:"ir027",type:"error",q:"I seen the student throw the chair across the room. It was very danger and could hurt someone.",a:"I saw the student throw a chair across the room. This was extremely dangerous and could have injured another student.",exp:"'Saw' (past simple, not 'seen' alone). 'Extremely dangerous' (adjective form). 'Could have injured' (past conditional for potential outcome)."},
        {id:"ir028",type:"fill",q:"No physical ___ was observed, but both students were visibly ___ following the verbal confrontation.",a:"injury ... upset",exp:"Recording the absence of injury is important. 'Visibly upset' = observably distressed. 'Verbal confrontation' distinguishes from physical altercation."},
        {id:"ir029",type:"open",q:"Write a brief note to the year adviser about a student who has been consistently late to your class.",a:"Hi Mark, I wanted to flag that Student E has arrived more than ten minutes late to my Period 3 Technology class on five occasions over the past two weeks (dates: 5, 7, 10, 12, 14 March). I have spoken to the student individually, and they mentioned that they find it hard to get from Block D in time. I have also contacted the parents, who were unaware of the pattern. Could you please look into whether there is a timetable or wellbeing issue contributing to this? Happy to discuss further. Thanks, Yunshu",exp:"Specific data (dates, frequency), actions already taken (spoken to student, contacted parents), possible cause identified, escalation to year adviser with specific request."},
        {id:"ir030",type:"fill",q:"The property ___ was assessed at approximately $50. A replacement has been ordered and the cost will be ___ from the school budget.",a:"damage ... covered",exp:"Documenting property damage includes assessment of value and who will pay. 'Covered from the school budget' records the financial decision."},
        {id:"ir031",type:"mc",q:"What should you do if a student tells you something that triggers mandatory reporting obligations?",options:["Promise the student you won't tell anyone","Listen without judgement, thank them for telling you, and follow your school's reporting procedures immediately","Investigate the matter yourself","Tell the student's friends so they can help"],a:1,exp:"Listen, don't promise confidentiality (you can't), thank them, and report immediately through school procedures. Never investigate or share with others. This is a legal obligation."},
        {id:"ir032",type:"fill",q:"The investigation into the incident is ___. I will provide an updated report once all ___ accounts have been collected.",a:"ongoing ... witness",exp:"'Investigation is ongoing' means it's not resolved yet. 'Witness accounts' = statements from people who saw what happened. Professional follow-up."},
        {id:"ir033",type:"error",q:"Student is keep coming to class late. I already talk to him many times but no improvement.",a:"The student continues to arrive late to class despite multiple conversations. I have documented each instance and the strategies attempted, and I am now referring this matter to the year adviser.",exp:"'Continues to arrive late' (formal). 'Despite multiple conversations' (formal). 'Documented each instance' shows proper process. 'Referring to year adviser' shows escalation."},
        {id:"ir034",type:"fill",q:"Attached is the completed incident ___ form (IRIS). All relevant staff have been ___ and copies filed accordingly.",a:"report ... informed",exp:"IRIS is the online incident reporting system in many NSW schools. 'All relevant staff informed' and 'copies filed' show thorough documentation."},
        {id:"ir035",type:"fill",q:"The student's behaviour plan has been ___ to include additional support during ___ periods, as recommended by the counsellor.",a:"updated ... transition",exp:"Behaviour plans are living documents that should be updated as situations change. 'Transition periods' (between lessons) are high-risk times for some students."},
        {id:"ir036",type:"error",q:"The student refuse to comply with the teacher instruction. He walk out from the classroom without permission.",a:"The student refused to comply with the teacher's instructions. He walked out of the classroom without permission.",exp:"Past tense: 'refused', 'walked'. 'Teacher's instructions' (possessive + plural). 'Walked out OF' (not 'from'). Incident reports must use correct past tense."},
        {id:"ir037",type:"fill",q:"A risk ___ has been completed for the student, and a safety plan is now in ___ until further notice.",a:"assessment ... place",exp:"'Risk assessment' = formal evaluation of potential harm. 'In place' = established and active. 'Until further notice' = until the situation changes."},
        {id:"ir038",type:"mc",q:"When writing an incident report, which tense should you primarily use?",options:["Present tense","Past tense","Future tense","Present perfect"],a:1,exp:"Incident reports describe completed events: past tense throughout. 'The student threw the book. I separated the students. The deputy was notified.' Consistent past tense."},
        {id:"ir039",type:"fill",q:"The incident was ___ by a verbal disagreement that ___ during a group activity in Period 3.",a:"triggered ... occurred",exp:"'Triggered by' = caused by. 'Occurred during' = happened during. Neutral, factual language. No blame or judgement about who started it."},
        {id:"ir040",type:"fill",q:"I have ___ this incident to the year adviser and the school ___ team as per school policy.",a:"reported ... wellbeing",exp:"'Reported to' the correct people. 'As per school policy' shows you followed procedures. 'Wellbeing team' is the student support team in many NSW schools."}
      ]
    },
    {
      id: "professional-goals",
      title: "Setting Professional Goals (PDPs)",
      theory: "Every Australian teacher is required to maintain a Professional Development Plan (PDP). Goals should be SMART: Specific, Measurable, Achievable, Relevant, Time-bound. They must link to the Australian Professional Standards for Teachers. Chinese speakers may write goals that are too vague or too modest — Australian PDPs require specific, ambitious, and evidence-based goals.",
      exercises: [
        {id:"pg001",type:"fill",q:"My professional goal for this term is to ___ my use of formative assessment strategies to better ___ student understanding during lessons.",a:"strengthen ... gauge",exp:"'Strengthen my use of' = improve. 'Gauge student understanding' = measure/assess. This links to Standard 5: Assess, provide feedback and report."},
        {id:"pg002",type:"mc",q:"Which is a well-written SMART goal?",options:["I want to be a better teacher.","By the end of Term 2, I will implement exit tickets in 80% of my lessons and use the data to inform my planning for the following lesson.","I will try to improve my teaching.","I hope to do more professional development."],a:1,exp:"SMART: Specific (exit tickets), Measurable (80%), Achievable, Relevant (assessment), Time-bound (end of Term 2). The other options are too vague."},
        {id:"pg003",type:"fill",q:"This goal aligns with the Australian Professional Standard ___.1: Know students and how they ___.",a:"1 ... learn",exp:"Standard 1: Know students and how they learn. Linking goals to professional standards is mandatory in Australian PDPs."},
        {id:"pg004",type:"error",q:"I hope to improve my teaching skill in the future. I will try my best to become a good teacher.",a:"By the end of Term 2, I aim to improve my questioning techniques by incorporating Bloom's taxonomy levels into my lesson planning. I will measure success by analysing student responses in recorded lessons.",exp:"The original is too vague and sounds like a Chinese self-evaluation (我希望提高). Australian PDPs need specific targets, strategies, evidence, and timelines."},
        {id:"pg005",type:"fill",q:"Evidence of progress towards this goal will include ___ observations, student work samples, and ___ survey data.",a:"lesson ... student",exp:"PDPs require evidence: observations (from mentor/HoD), work samples (student output), and surveys (student feedback). Multiple evidence types are expected."},
        {id:"pg006",type:"mc",q:"Which Australian Professional Standard relates to 'creating and maintaining supportive and safe learning environments'?",options:["Standard 1","Standard 2","Standard 4","Standard 6"],a:2,exp:"Standard 4: Create and maintain supportive and safe learning environments. The seven standards are: 1-Know students, 2-Know content, 3-Plan, 4-Create environment, 5-Assess, 6-Professional engagement, 7-Professional learning."},
        {id:"pg007",type:"fill",q:"I will seek ___ from my mentor teacher on a fortnightly basis to monitor my ___ towards this goal.",a:"feedback ... progress",exp:"Regular feedback from a mentor is expected. 'Fortnightly' = every two weeks (Australian English). 'Monitor progress' = track development."},
        {id:"pg008",type:"error",q:"My goal is to learn more about the curriculum. I think knowing the curriculum is very important for teacher.",a:"My goal is to deepen my understanding of the NSW Technology syllabus by mapping each lesson to specific outcomes and content descriptors. I will review the mapping with my head teacher by the end of Week 6.",exp:"'Deepen understanding' is more specific than 'learn more'. Naming the specific syllabus and a concrete activity (mapping) makes it SMART. A review deadline adds accountability."},
        {id:"pg009",type:"fill",q:"I plan to attend at least two professional ___ sessions this term related to digital literacy and ___ in the classroom.",a:"development ... technology",exp:"PD attendance is a measurable goal. 'At least two' is specific. 'Related to' links PD to a focus area."},
        {id:"pg010",type:"open",q:"Write a SMART professional goal related to improving your classroom management.",a:"By the end of Term 1, I aim to reduce the number of behavioural incidents in my Year 9 class by 50% through implementing a consistent routine of expectations review at the start of each lesson and a points-based positive reinforcement system. I will measure progress by comparing Sentral data from Week 1-4 with data from Week 5-10. I will also seek fortnightly feedback from my mentor on my behaviour management strategies during classroom observations.",exp:"SMART: Specific (Year 9 class, consistent routines, positive reinforcement), Measurable (50% reduction, Sentral data), Achievable, Relevant, Time-bound (end of Term 1). This is exactly what Australian PDP reviewers want to see."},
        {id:"pg011",type:"fill",q:"A key area of ___ for me is differentiating my teaching to meet the needs of EAL/D students in my ___ classroom.",a:"growth ... mainstream",exp:"'Area of growth' = area for improvement (positive framing). 'EAL/D students in mainstream' = English as an Additional Language/Dialect students in regular classes."},
        {id:"pg012",type:"mc",q:"What does 'accreditation' mean for Australian teachers?",options:["Getting a university degree","The formal process of being recognised as meeting professional standards at a specific level","Getting a promotion","Being observed by an inspector"],a:1,exp:"All NSW teachers must be accredited by NESA. New teachers achieve 'Proficient' level and maintain it. Higher levels: Highly Accomplished, Lead. Your PDP supports accreditation."},
        {id:"pg013",type:"fill",q:"I will ___ this goal by trialling cooperative learning structures in at least three lessons per week and ___ the impact on student outcomes.",a:"achieve ... evaluating",exp:"'Achieve this goal by' names the strategy. 'Trialling cooperative learning' is specific. 'Evaluating impact' closes the reflective cycle."},
        {id:"pg014",type:"error",q:"I want to be promote to a senior teacher position. I think I am deserve it because I work very hard.",a:"My long-term professional goal is to develop the skills and evidence base required for progression to a senior teacher role. This term, I will focus on building leadership capacity by mentoring a pre-service teacher and leading a faculty project on assessment moderation.",exp:"'Be promoted' (passive). 'Deserve' doesn't need 'am'. But more importantly, PDPs focus on development actions, not desires. Show what you're DOING to progress."},
        {id:"pg015",type:"fill",q:"I am committed to ___ professional learning throughout my career. This is aligned with Standard ___: Engage professionally with colleagues.",a:"ongoing ... 6",exp:"'Ongoing professional learning' = continuous growth. Standard 6 relates to professional engagement with colleagues, the profession, and the community."},
        {id:"pg016",type:"fill",q:"By Week 10, I will have ___ a portfolio of evidence demonstrating my progress towards achieving Proficient-level ___.",a:"compiled ... accreditation",exp:"'Compiled a portfolio' = gathered evidence. 'Proficient-level accreditation' is the target for new teachers in NSW."},
        {id:"pg017",type:"mc",q:"What type of evidence is strongest for a PDP?",options:["A statement saying 'I'm a good teacher'","Student work samples showing growth over time, supported by annotated observations","A certificate from a one-hour webinar","A list of lessons taught"],a:1,exp:"Student work samples with growth evidence are the strongest. Annotated observations (showing what you did and the impact) demonstrate reflective practice. Multiple evidence types are ideal."},
        {id:"pg018",type:"error",q:"I will finish all my accreditation requirement by the end of this year. Then I can relax and not worry about professional development.",a:"I aim to complete all accreditation requirements by the end of this year. I will then shift my focus to maintaining my accreditation and pursuing areas of professional interest.",exp:"Accreditation maintenance is ongoing — you never 'finish' professional development. The growth mindset is central to Australian teaching culture."},
        {id:"pg019",type:"fill",q:"My short-term goal is to develop a ___ of resources for my Year 7 Technology unit. My long-term goal is to become the faculty's ___ for digital learning.",a:"bank ... coordinator",exp:"Short-term (this term) and long-term (this year or beyond) goals show career planning. 'Coordinator' is a leadership role within a faculty."},
        {id:"pg020",type:"open",q:"Write a reflection on your progress towards a professional goal at the mid-year review point.",a:"At the mid-year point, I have made solid progress towards my goal of improving formative assessment practices. I have successfully implemented exit tickets in approximately 75% of my lessons, which is close to my 80% target. The data from these exit tickets has directly informed my planning — for example, when exit ticket results showed that 40% of students had not understood the concept of parallel circuits, I redesigned the following lesson to include a hands-on demonstration. One challenge has been finding time to analyse the exit ticket data consistently. For the second half of the year, I plan to create a simple spreadsheet template that allows me to input data more efficiently. Overall, I am confident that I will achieve this goal by the end of the year.",exp:"Reports on specific progress (75% vs 80% target), gives a concrete example of impact, identifies a challenge, and proposes a solution. This is exactly the format for a mid-year PDP review."},
        {id:"pg021",type:"fill",q:"I have ___ my goal for this term because I have met all the success ___ outlined in my PDP.",a:"achieved ... criteria",exp:"'Achieved my goal' — marking a goal as complete requires evidence against the criteria. 'Success criteria' = the standards you set."},
        {id:"pg022",type:"mc",q:"What is a 'learning walk' in Australian schools?",options:["A walking excursion","When school leaders briefly visit multiple classrooms to observe teaching practices","A student walk to the library","A fitness activity"],a:1,exp:"Learning walks involve leaders visiting classrooms briefly (5-10 minutes) to observe teaching practices, not to evaluate individual teachers but to get a snapshot of school-wide practices."},
        {id:"pg023",type:"fill",q:"For my ___ accreditation at the Highly Accomplished level, I will need to demonstrate sustained impact on ___ learning across the school.",a:"future ... student",exp:"Higher accreditation levels (Highly Accomplished, Lead) require evidence of impact beyond your own classroom. 'Sustained impact on student learning across the school' is the key criterion."},
        {id:"pg024",type:"error",q:"My goal is improve my English language skill so I can communicate more better with parents and colleague.",a:"My goal is to improve my professional communication skills, particularly in parent interviews and staff meetings. I will do this by attending an academic English course and practising formal written correspondence with my mentor's guidance.",exp:"'Is to improve' (infinitive). 'Communication skills' (plural). 'More better' = 'more effectively' (double comparative). Goals need specific strategies, not just intentions."},
        {id:"pg025",type:"fill",q:"Professional ___ is not a destination but a journey. I am committed to continuous ___ throughout my teaching career.",a:"growth ... improvement",exp:"This philosophy statement reflects the Australian teaching profession's emphasis on lifelong learning. It's a good way to close a PDP document."},
        {id:"pg026",type:"fill",q:"I will document my professional learning by maintaining a reflective ___ and contributing to the school's professional learning ___ each term.",a:"journal ... community",exp:"'Reflective journal' = ongoing written reflection. 'Professional Learning Community' (PLC) is a group of teachers who meet regularly to improve practice."},
        {id:"pg027",type:"mc",q:"What does 'Graduate' level mean in the Australian Professional Standards?",options:["You have graduated from university","You are a beginning teacher who has completed initial teacher education","You are an expert teacher","You are about to retire"],a:1,exp:"Graduate = the entry level for new teachers. The progression is: Graduate > Proficient > Highly Accomplished > Lead. Most teachers achieve Proficient within their first few years."},
        {id:"pg028",type:"fill",q:"My mentor and I have agreed that my next ___ for development is building my ___ in using data to inform teaching.",a:"priority ... confidence",exp:"'Priority for development' frames the focus area. 'Building confidence in using data' is specific and honest. Mentor-guided goals are standard."},
        {id:"pg029",type:"error",q:"I am satisfy with my progress but I know I still have many thing to learn. Teaching is a very challenge profession.",a:"I am satisfied with my progress, but I know I still have much to learn. Teaching is a very challenging profession.",exp:"'Satisfied' (adjective). 'Much to learn' (uncountable for abstract concepts). 'Challenging' (adjective form of 'challenge'). Common Chinese speaker errors."},
        {id:"pg030",type:"fill",q:"Looking ahead to next year, I plan to take on a ___ role by leading the implementation of a new assessment ___ in my faculty.",a:"leadership ... framework",exp:"Career progression through leadership. 'Leading implementation' of a new system shows initiative and capacity for higher-level responsibilities."},
        {id:"pg031",type:"error",q:"I need to improve my class management skill. I hope someday I can become a very good teacher.",a:"I need to improve my classroom management skills. I am committed to developing into a highly effective teacher.",exp:"'Classroom management' (compound noun). 'Skills' (plural). 'Committed to developing' is proactive. 'Highly effective teacher' is specific professional language, not vague 'very good'."},
        {id:"pg032",type:"fill",q:"My next step is to observe experienced ___ and incorporate their strategies into my own ___.",a:"colleagues ... practice",exp:"Observing colleagues is a key PDP action. 'Incorporate into my practice' = adopt and adapt. Note: 'practice' (noun) vs 'practise' (verb) in Australian English."},
        {id:"pg033",type:"mc",q:"What does 'Proficient' level mean in the Australian Professional Standards?",options:["A beginning teacher","A teacher who has demonstrated competence across all seven standards","An expert teacher leading others","A teacher nearing retirement"],a:1,exp:"Proficient is the standard that most teachers achieve within their first few years and maintain throughout their career. It demonstrates competence across Standards 1-7."},
        {id:"pg034",type:"fill",q:"I will gather evidence of student ___ to demonstrate my impact on learning outcomes, as required by Standard ___.",a:"growth ... 5",exp:"Student growth data is powerful PDP evidence. Standard 5: Assess, provide feedback and report on student learning. Linking evidence to standards is essential."},
        {id:"pg035",type:"fill",q:"Peer ___ has been invaluable for my development. Watching how experienced teachers ___ behaviour has given me practical strategies I can use immediately.",a:"observation ... manage",exp:"'Peer observation' = watching a colleague teach. 'Invaluable' = extremely valuable. Naming specific takeaways shows reflective practice."}
      ]
    }
  ]
},
// ============================================================
// MODULE 6: CHINESE-SPEAKER ERROR PATTERNS
// ============================================================
chineseSpeakerErrors: {
  title: "Chinese-Speaker Error Patterns",
  sections: [
    {
      id: "articles-determiners",
      title: "Articles & Determiners (a/an/the/zero)",
      theory: "Chinese has no article system. This is the #1 error pattern for Chinese speakers. English requires articles before singular countable nouns and 'the' for specific references. Rules: 'a/an' = one of many (non-specific), 'the' = specific/known, zero article = general plurals and uncountable nouns.",
      exercises: [
        {id:"ad001",type:"fill",q:"I need to buy ___ new laptop for ___ school.",a:"a ... the",exp:"'A new laptop' — first mention, non-specific (any laptop). 'The school' — specific school you work at. Chinese has no articles, so both are commonly omitted."},
        {id:"ad002",type:"error",q:"She is very good teacher who always helps student.",a:"She is a very good teacher who always helps students.",exp:"'A very good teacher' — singular countable noun needs 'a'. 'Students' — general plural (no article, but needs 's'). Chinese 她是很好的老师 has no articles."},
        {id:"ad003",type:"fill",q:"Could you pass me ___ stapler? It's on ___ shelf next to ___ printer.",a:"the ... the ... the",exp:"All three are 'the' because they are specific, known objects in a shared space. If you said 'a stapler', you would mean any stapler, not the specific one."},
        {id:"ad004",type:"mc",q:"Which sentence uses articles correctly?",options:["I had a meeting with the principal this morning.","I had meeting with principal this morning.","I had the meeting with a principal this morning.","I had a meeting with a the principal this morning."],a:0,exp:"'A meeting' (one of many possible meetings — non-specific). 'The principal' (there is only one principal — specific). This is the a/the distinction."},
        {id:"ad005",type:"fill",q:"___ education is important for ___ future of our country.",a:"(zero article) ... the",exp:"'Education' — general concept (uncountable, zero article). 'The future' — specific (there is only one future). Chinese speakers often add 'the' to general concepts."},
        {id:"ad006",type:"error",q:"I went to the hospital to visit the friend. He had the accident last week.",a:"I went to the hospital to visit a friend. He had an accident last week.",exp:"'A friend' — one of your friends (not specific to the listener). 'An accident' — first mention, non-specific. 'The hospital' is correct (specific/known institution)."},
        {id:"ad007",type:"fill",q:"There is ___ apple on ___ desk. ___ apple is for you.",a:"an ... the ... The",exp:"First mention: 'an apple' (non-specific). 'The desk' (known desk). Second mention: 'The apple' (now specific — the one I just mentioned). This is the key article pattern."},
        {id:"ad008",type:"mc",q:"Which is correct?",options:["The homework is due on the Friday.","Homework is due on Friday.","A homework is due on a Friday.","The homework is due on a Friday."],a:1,exp:"'Homework' is uncountable (no article). 'On Friday' — no article before days of the week in this context. Adding 'the' before days/homework is a very common Chinese speaker error."},
        {id:"ad009",type:"fill",q:"I've been teaching at ___ Arthur Phillip High School for ___ year now.",a:"(zero article) ... a",exp:"No article before proper nouns (school names). 'A year' — not a specific year, just a duration of one year. Chinese speakers often say 'the Arthur Phillip'."},
        {id:"ad010",type:"error",q:"Please give me information about the assessment. I need the help with the planning.",a:"Please give me information about the assessment. I need help with the planning.",exp:"'Information' is uncountable (no article before it). 'Help' is also uncountable — 'the help' implies specific help already discussed. 'The assessment' and 'the planning' are correct (specific)."},
        {id:"ad011",type:"fill",q:"Could you recommend ___ good restaurant? I'm looking for ___ place that serves Thai food.",a:"a ... a",exp:"Both 'a' because you're asking for any recommendation — non-specific. 'A good restaurant' = one of many possible options."},
        {id:"ad012",type:"mc",q:"'I love ___ music' — which article is correct?",options:["a","the","an","no article"],a:3,exp:"General uncountable nouns use no article. 'I love music' (in general). Compare: 'I love the music in this café' (specific music). Chinese speakers often add 'the' to general preferences."},
        {id:"ad013",type:"fill",q:"___ students in my Year 8 class are very enthusiastic about ___ project we started last week.",a:"The ... the",exp:"'The students' — specific (in my class). 'The project' — specific (one we started). Both references are to known, specific things."},
        {id:"ad014",type:"error",q:"I have been to the Japan twice. The Japanese culture is very interesting.",a:"I have been to Japan twice. Japanese culture is very interesting.",exp:"No 'the' before country names (Japan, Australia, China) — except 'the United States', 'the Philippines'. No 'the' before '[nationality] culture' when speaking generally."},
        {id:"ad015",type:"fill",q:"Can I borrow ___ pen? I left ___ at home.",a:"a ... mine",exp:"'A pen' — any pen will do (non-specific). 'Mine' — possessive pronoun replaces 'my pen'. Note: 'I left mine' not 'I left the pen at home' (unless referring to a specific pen)."},
        {id:"ad016",type:"fill",q:"___ weather has been terrible this week. I hope ___ weekend will be better.",a:"The ... the",exp:"'The weather' — when referring to current/local weather (specific). 'The weekend' — the upcoming specific weekend."},
        {id:"ad017",type:"mc",q:"Choose the correct sentence:",options:["I work in the Room 205.","I work in Room 205.","I work in a Room 205.","I work in an Room 205."],a:1,exp:"No article before 'Room + number'. Same rule for: 'Bus 333', 'Platform 2', 'Page 42'. The number already makes it specific."},
        {id:"ad018",type:"error",q:"The life is short. We should enjoy the every moment.",a:"Life is short. We should enjoy every moment.",exp:"'Life' — general concept (no article). 'Every' is already a determiner — never add 'the' before it. Chinese speakers often add 'the' to philosophical statements (人生很短)."},
        {id:"ad019",type:"fill",q:"I had ___ interesting conversation with ___ new teacher who just joined ___ staff.",a:"an ... a ... the",exp:"'An interesting' (vowel sound). 'A new teacher' (first mention). 'The staff' (specific — our school's staff). Three different article uses in one sentence."},
        {id:"ad020",type:"fill",q:"Could you send me ___ email with ___ details? I'll review it over ___ weekend.",a:"an ... the ... the",exp:"'An email' (non-specific). 'The details' (specific details we discussed). 'The weekend' (this coming weekend)."},
        {id:"ad021",type:"mc",q:"Which is correct: 'I'm going to ___ school' or 'I'm going to ___ the school'?",options:["Both are correct but have different meanings","Only 'the school' is correct","Only 'school' is correct","They mean the same thing"],a:0,exp:"'Going to school' = going as a student/teacher (regular activity). 'Going to the school' = going to the physical building for a specific purpose. Same with hospital, church, prison."},
        {id:"ad022",type:"error",q:"The water is important for the health. We should drink eight glass of the water every day.",a:"Water is important for health. We should drink eight glasses of water every day.",exp:"'Water' and 'health' are general concepts (no article). 'Glasses' (plural countable). 'Of water' (no article — general water). Almost every article is wrong in the original."},
        {id:"ad023",type:"fill",q:"___ meeting was productive. We made ___ lot of progress on ___ new curriculum.",a:"The ... a ... the",exp:"'The meeting' (specific, just happened). 'A lot of' (fixed expression). 'The new curriculum' (specific document)."},
        {id:"ad024",type:"fill",q:"I'll meet you at ___ front gate at 3 p.m. Don't forget to bring ___ umbrella — it looks like ___.",a:"the ... an ... rain",exp:"'The front gate' (specific). 'An umbrella' (non-specific, any umbrella). 'Rain' — uncountable, no article. 'It looks like rain' is a fixed expression."},
        {id:"ad025",type:"error",q:"He is a honest person. She is an European student.",a:"He is an honest person. She is a European student.",exp:"'An honest' — 'h' is silent, starts with vowel sound /ɒ/. 'A European' — 'Eu' starts with consonant sound /j/. Articles depend on SOUND, not spelling."},
        {id:"ad026",type:"fill",q:"I teach ___ Technology to Year 7. ___ subject is part of ___ Technology and Applied Studies (TAS) KLA.",a:"(zero article) ... The ... the",exp:"No article before subjects taught ('I teach Technology'). 'The subject' (specific). 'The TAS KLA' (specific grouping)."},
        {id:"ad027",type:"mc",q:"'She plays ___ piano beautifully.' Which article fits?",options:["a","an","the","no article"],a:2,exp:"Musical instruments use 'the' with 'play': 'play the piano', 'play the guitar'. But sports don't: 'play tennis', 'play cricket'. This is a fixed English rule with no Chinese equivalent."},
        {id:"ad028",type:"fill",q:"I had ___ lunch with ___ colleague from ___ English department.",a:"(zero article) ... a ... the",exp:"No article before meals in general ('had lunch'). 'A colleague' (non-specific). 'The English department' (specific department in your school)."},
        {id:"ad029",type:"error",q:"Can you give me the advice? I need a information about the new policy.",a:"Can you give me some advice? I need some information about the new policy.",exp:"'Advice' and 'information' are uncountable — use 'some', never 'a' or 'the' for first mention. These are among the most common Chinese speaker article errors."},
        {id:"ad030",type:"fill",q:"___ student in ___ front row asked ___ excellent question about climate change.",a:"A ... the ... an",exp:"'A student' (non-specific, one of many). 'The front row' (specific location). 'An excellent question' (non-specific, but notable)."},
        {id:"ad031",type:"fill",q:"We visited ___ Art Gallery of New South Wales and saw ___ amazing exhibition on Indigenous ___.",a:"the ... an ... art",exp:"'The Art Gallery of NSW' (proper noun with 'the'). 'An amazing exhibition' (first mention). 'Indigenous art' (general uncountable concept)."},
        {id:"ad032",type:"error",q:"I usually take the bus to the work. It takes about the half hour.",a:"I usually take the bus to work. It takes about half an hour.",exp:"No article before 'work' (regular activity, like 'go to school'). 'Half an hour' is a fixed expression. 'The bus' is correct if you mean a specific bus route."},
        {id:"ad033",type:"fill",q:"___ teacher's job is never boring. Every day brings ___ new challenge and ___ new opportunity to make ___ difference.",a:"A ... a ... a ... a",exp:"All 'a' — these are general, non-specific references about teaching in general. This is philosophical/general statement territory."},
        {id:"ad034",type:"mc",q:"Which is correct: '___ United Kingdom' or just 'United Kingdom'?",options:["The United Kingdom","United Kingdom","A United Kingdom","An United Kingdom"],a:0,exp:"Countries with 'Kingdom', 'States', 'Republic', or 'Islands' use 'the': the UK, the US, the Philippines, the Czech Republic. Most other countries: no article (Australia, China, Japan)."},
        {id:"ad035",type:"fill",q:"I'm reading ___ book about ___ history of Australian education. ___ book was recommended by my mentor.",a:"a ... the ... The",exp:"'A book' (first mention). 'The history' (specific). 'The book' (second mention — now specific). This first/second mention pattern is fundamental."},
        {id:"ad036",type:"error",q:"The teacher gave us the homework about the Australia. I need to finish it by the next Monday.",a:"The teacher gave us homework about Australia. I need to finish it by next Monday.",exp:"'Homework' (uncountable, no article). 'Australia' (country, no article). 'Next Monday' (no article with 'next + day'). Three common article errors."},
        {id:"ad037",type:"fill",q:"Is there ___ parking spot available? I need to find ___ place to park before ___ meeting starts.",a:"a ... a ... the",exp:"'A parking spot' (any one). 'A place' (any place). 'The meeting' (specific, planned meeting)."},
        {id:"ad038",type:"open",q:"Correct all article errors in this passage: 'I went to the Japan for the vacation. I visited the many temples and ate the delicious food. The weather was perfect. Life in the Japan is very different from the life in the Australia.'",a:"I went to Japan for a vacation. I visited many temples and ate delicious food. The weather was perfect. Life in Japan is very different from life in Australia.",exp:"No 'the' before: Japan (country), Australia (country), many (determiner), delicious food (general), life (general concept). 'A vacation' (non-specific). 'The weather' is correct (specific weather during the trip)."},
        {id:"ad039",type:"fill",q:"___ Internet has changed ___ way we teach. Almost ___ lesson now involves some form of digital ___.",a:"The ... the ... every ... technology",exp:"'The Internet' (specific, unique). 'The way' (specific way). 'Every lesson' (determiner, no article). 'Technology' (general uncountable)."},
        {id:"ad040",type:"mc",q:"'I'm looking for ___ accommodation near the school.' Which is correct?",options:["an accommodation","the accommodation","a accommodation","accommodation"],a:3,exp:"'Accommodation' is uncountable in British/Australian English (no 'a' or 'an'). 'I'm looking for accommodation' or 'some accommodation'. This is a common trap for Chinese speakers who treat it as countable."},
        {id:"ad041",type:"fill",q:"___ principal announced that ___ school will be closed for ___ public holiday on Monday.",a:"The ... the ... a",exp:"'The principal' (specific). 'The school' (specific). 'A public holiday' (one of many possible holidays — non-specific at this point)."},
        {id:"ad042",type:"error",q:"She has the long hair and the blue eyes. She is wearing the red dress today.",a:"She has long hair and blue eyes. She is wearing a red dress today.",exp:"Physical descriptions: no article before adjective + uncountable noun ('long hair', 'blue eyes'). 'A red dress' — first mention, non-specific to the listener."},
        {id:"ad043",type:"fill",q:"___ children in ___ classroom should feel safe. That is ___ fundamental right.",a:"(zero article) ... the ... a",exp:"'Children' in general (no article). 'The classroom' (specific context). 'A fundamental right' (one of many rights)."},
        {id:"ad044",type:"fill",q:"I had ___ interview at ___ University of Sydney last week. ___ interview went really well.",a:"an ... the ... The",exp:"'An interview' (first mention). 'The University of Sydney' (proper noun with 'the'). 'The interview' (second mention — now specific)."},
        {id:"ad045",type:"mc",q:"'She gave me ___ useful advice.' Which is correct?",options:["a useful","an useful","some useful","the useful"],a:2,exp:"'Advice' is uncountable — cannot use 'a' or 'an'. 'Some useful advice' is correct. Also: 'a useful' not 'an useful' — 'u' in 'useful' makes a /j/ sound (consonant)."},
        {id:"ad046",type:"error",q:"I have been living in the Sydney for the two years. I love the Australian way of the life.",a:"I have been living in Sydney for two years. I love the Australian way of life.",exp:"No 'the' before city names (Sydney, Melbourne). 'Two years' (no article). 'Way of life' is a fixed phrase (no 'the' before 'life' here)."},
        {id:"ad047",type:"fill",q:"We need ___ volunteer to help with ___ event. Could ___ first person to finish please come and see me?",a:"a ... the ... the",exp:"'A volunteer' (any one). 'The event' (specific planned event). 'The first person' (specific by virtue of 'first')."},
        {id:"ad048",type:"fill",q:"___ research shows that ___ homework has ___ limited impact on learning in ___ primary school.",a:"(zero article) ... (zero article) ... a ... (zero article)",exp:"'Research' (general, uncountable). 'Homework' (general, uncountable). 'A limited impact' (one type of impact). 'Primary school' (general concept). General statements use no articles."},
        {id:"ad049",type:"error",q:"Please open the window. The fresh air will help the students concentrate on the work.",a:"Please open the window. Fresh air will help the students concentrate on their work.",exp:"'The window' (specific). 'Fresh air' (general uncountable — no 'the'). 'Their work' (possessive, not 'the work'). 'The students' (specific — the ones in the room)."},
        {id:"ad050",type:"fill",q:"___ purpose of ___ meeting is to discuss ___ new behaviour management policy.",a:"The ... the ... the",exp:"'The purpose' (specific). 'The meeting' (specific, scheduled). 'The new policy' (specific, already under discussion). When everything is known and specific, use 'the'."}
      ]
    },
    {
      id: "prepositions",
      title: "Prepositions (in/on/at/to/for)",
      theory: "Chinese prepositions do not map 1:1 to English. Many errors come from direct translation of 在 (zài), 对 (duì), 给 (gěi), 用 (yòng). English prepositions are largely idiomatic — they must be learned as part of phrases rather than translated.",
      exercises: [
        {id:"pp001",type:"fill",q:"The meeting is ___ Monday ___ 3 p.m. ___ Room 204.",a:"on ... at ... in",exp:"Time prepositions: 'on' + day (Monday), 'at' + specific time (3 p.m.), 'in' + enclosed space (room). Chinese uses 在 for all three."},
        {id:"pp002",type:"error",q:"I am interested about this topic. I want to learn more about it.",a:"I am interested in this topic. I want to learn more about it.",exp:"'Interested IN' (not 'about'). But 'learn more ABOUT'. Preposition collocations must be memorised — they cannot be logically deduced."},
        {id:"pp003",type:"fill",q:"She arrived ___ school ___ 8:30 ___ the morning.",a:"at ... at ... in",exp:"'At school' (location). 'At 8:30' (specific time). 'In the morning' (part of day). These three prepositions of time/place are the most error-prone for Chinese speakers."},
        {id:"pp004",type:"mc",q:"Which preposition is correct: 'I depend ___ my colleagues for support'?",options:["in","on","at","for"],a:1,exp:"'Depend ON' is a fixed collocation. Chinese 依赖 doesn't specify a preposition in the same way. Other examples: rely on, count on, insist on."},
        {id:"pp005",type:"fill",q:"She apologised ___ being late and explained that she was stuck ___ traffic.",a:"for ... in",exp:"'Apologise FOR' + gerund (reason). 'Stuck IN traffic' (trapped inside). Chinese 为迟到道歉 translates differently."},
        {id:"pp006",type:"error",q:"I am good in mathematics but I am not good in English.",a:"I am good at mathematics but I am not good at English.",exp:"'Good AT' + subject/skill. This is one of the most common preposition errors for Chinese speakers. Chinese 擅长 doesn't specify 'at'."},
        {id:"pp007",type:"fill",q:"The students are working ___ a project about sustainability. They've been working ___ it ___ two weeks.",a:"on ... on ... for",exp:"'Work ON a project'. 'For two weeks' (duration). Chinese 做 doesn't require 'on'. 'For + period of time' indicates duration."},
        {id:"pp008",type:"mc",q:"Which is correct: 'Listen ___ the teacher'?",options:["Listen the","Listen to the","Listen at the","Listen for the"],a:1,exp:"'Listen TO' is mandatory in English. 'Listen' is intransitive — it cannot directly take an object. Chinese 听老师 doesn't need a preposition. This is extremely common."},
        {id:"pp009",type:"fill",q:"I look forward ___ hearing ___ you. Please get back ___ me when you can.",a:"to ... from ... to",exp:"'Look forward TO' + gerund. 'Hearing FROM you' (receiving communication). 'Get back TO me' (reply). Three different prepositions in standard email phrases."},
        {id:"pp010",type:"error",q:"He married with his girlfriend last year. They live in the Parramatta now.",a:"He married his girlfriend last year. They live in Parramatta now.",exp:"'Marry' takes a direct object (no 'with'). 'In Parramatta' (no 'the' before suburb names). Chinese 和...结婚 leads to the 'married with' error."},
        {id:"pp011",type:"fill",q:"Please wait ___ me ___ the entrance. I'll be there ___ ten minutes.",a:"for ... at ... in",exp:"'Wait FOR me' (purpose). 'AT the entrance' (point/location). 'IN ten minutes' (future time). Three key prepositions in one sentence."},
        {id:"pp012",type:"mc",q:"Which is correct: 'She is responsible ___ the Year 7 programme'?",options:["of","about","for","in"],a:2,exp:"'Responsible FOR' = in charge of. Chinese speakers often use 'of' or 'about' by direct translation of 负责. Other: 'responsible for', 'capable of', 'interested in'."},
        {id:"pp013",type:"fill",q:"I'm ___ a hurry. Can we discuss this ___ lunch? I'll meet you ___ the staffroom.",a:"in ... at ... in",exp:"'In a hurry' (state). 'At lunch' (time). 'In the staffroom' (enclosed space). Each preposition has a specific function."},
        {id:"pp014",type:"error",q:"He explained me the rules. I didn't agree about his decision.",a:"He explained the rules to me. I didn't agree with his decision.",exp:"'Explain X TO someone' (not 'explain me'). 'Agree WITH' a person or decision (not 'about'). Both are direct translations from Chinese patterns."},
        {id:"pp015",type:"fill",q:"The excursion will take place ___ 15 March. We will travel ___ bus and arrive ___ the museum ___ 10 a.m.",a:"on ... by ... at ... at",exp:"'On 15 March' (date). 'By bus' (transport method, no article). 'At the museum' (destination). 'At 10 a.m.' (time). Note: 'by bus' not 'by the bus'."},
        {id:"pp016",type:"mc",q:"Which is correct: 'I congratulated her ___ her promotion'?",options:["for","on","about","to"],a:1,exp:"'Congratulate someone ON something'. Chinese 祝贺 doesn't specify the preposition. Other examples: compliment on, focus on, comment on."},
        {id:"pp017",type:"fill",q:"She is ___ leave today. The class will be covered ___ a casual teacher ___ her absence.",a:"on ... by ... during",exp:"'On leave' (state). 'Covered BY' (agent in passive). 'During her absence' (time period). Preposition choice depends on the relationship."},
        {id:"pp018",type:"error",q:"I will discuss about this problem with you later. Let me think about it first.",a:"I will discuss this problem with you later. Let me think about it first.",exp:"'Discuss' takes a direct object (no 'about'). 'Think about' does use 'about'. This is one of the trickiest patterns — some verbs need prepositions and some don't."},
        {id:"pp019",type:"fill",q:"The student was sitting ___ the back of the classroom, leaning ___ the wall.",a:"at ... against",exp:"'At the back' (position). 'Against the wall' (touching/resting on). 'Lean against' is a physical position collocation."},
        {id:"pp020",type:"fill",q:"I applied ___ the position ___ head of department. The interview is ___ next Wednesday.",a:"for ... of ... on",exp:"'Apply FOR a position'. 'Head OF department'. 'ON next Wednesday' (specific day). 'Apply for' is the correct collocation (not 'apply to the position')."},
        {id:"pp021",type:"mc",q:"'I'm worried ___ the exam results.' Which preposition fits?",options:["for","about","of","on"],a:1,exp:"'Worried ABOUT' = anxious/concerned regarding. Chinese 担心 leads to various preposition guesses. 'Worried about' (a situation), 'afraid of' (a thing), 'nervous about' (an event)."},
        {id:"pp022",type:"error",q:"She reminded about me to bring my laptop tomorrow.",a:"She reminded me to bring my laptop tomorrow.",exp:"'Remind someone TO do something' — no 'about' and the person is a direct object (not 'about me'). Chinese 提醒 followed by indirect object leads to this error."},
        {id:"pp023",type:"fill",q:"I was impressed ___ the quality of student work. They put a lot of effort ___ the project.",a:"by ... into",exp:"'Impressed BY' (passive cause). 'Put effort INTO' (directed action). Both are fixed collocations that must be memorised."},
        {id:"pp024",type:"fill",q:"He insisted ___ finishing the task himself, despite being ___ a lot of pressure ___ time.",a:"on ... under ... for",exp:"'Insisted ON' + gerund. 'Under pressure' (state). 'Pressure for time' = time pressure. Three different prepositions with different relationships."},
        {id:"pp025",type:"error",q:"She is capable to handle difficult situations. I have confidence to her ability.",a:"She is capable of handling difficult situations. I have confidence in her ability.",exp:"'Capable OF' + gerund. 'Confidence IN'. These are fixed adjective/noun + preposition patterns. Chinese doesn't specify these prepositions."},
        {id:"pp026",type:"fill",q:"The report was submitted ___ time. The principal was pleased ___ the results.",a:"on ... with",exp:"'On time' (not late). 'Pleased WITH' (satisfied regarding). 'On time' vs 'in time' — 'on time' = punctual, 'in time' = not too late."},
        {id:"pp027",type:"mc",q:"Which is correct: 'She succeeded ___ finishing the course'?",options:["at","in","on","to"],a:1,exp:"'Succeed IN' + gerund. Chinese 成功做到 doesn't use a preposition in the same way. Compare: 'succeed in' vs 'fail at' vs 'excel in'."},
        {id:"pp028",type:"fill",q:"I'll pick you up ___ the corner of George Street and King Street. Meet me ___ the traffic lights.",a:"at ... at",exp:"'At the corner' (specific point). 'At the traffic lights' (specific point). 'At' is used for specific points/locations."},
        {id:"pp029",type:"error",q:"The answer of this question is not easy. We need to think deeply about it.",a:"The answer to this question is not easy. We need to think deeply about it.",exp:"'Answer TO a question' (not 'of'). This is a fixed collocation. Chinese 这个问题的答案 leads to 'answer of'. Other: 'key to success', 'solution to the problem'."},
        {id:"pp030",type:"fill",q:"I'm not very familiar ___ the new software. Could you provide me ___ a quick tutorial?",a:"with ... with",exp:"'Familiar WITH' (knowing something). 'Provide someone WITH something'. Both use 'with' but for different reasons. Fixed collocations."},
        {id:"pp031",type:"fill",q:"The students participated ___ the debate with enthusiasm. The winning team will compete ___ the state level.",a:"in ... at",exp:"'Participate IN' (take part). 'Compete AT the state level' (level of competition). 'In' for activity, 'at' for level."},
        {id:"pp032",type:"error",q:"I was born in 1996 in the February. I came to Australia on 2023.",a:"I was born in 1996 in February. I came to Australia in 2023.",exp:"No 'the' before months. 'In + year' (not 'on'). 'In + month'. 'On' is only for specific dates: 'on 15 February'. Time preposition rules are strict."},
        {id:"pp033",type:"fill",q:"He specialises ___ digital technology and is passionate ___ integrating it ___ the classroom.",a:"in ... about ... into",exp:"'Specialise IN'. 'Passionate ABOUT'. 'Integrate INTO'. Three different prepositions for three different verbs. Must be memorised individually."},
        {id:"pp034",type:"mc",q:"'She suffers ___ anxiety during exams.' Which preposition is correct?",options:["of","from","with","by"],a:1,exp:"'Suffer FROM' = experience a condition. Chinese 患有 or 受...之苦 doesn't specify 'from'. Medical/condition collocations: suffer from, recover from, benefit from."},
        {id:"pp035",type:"fill",q:"I'll be away ___ business ___ Thursday ___ Friday. Can you cover my classes?",a:"on ... from ... to",exp:"'On business' (purpose of travel). 'From Thursday to Friday' (time range). 'Away on business' is a fixed phrase."},
        {id:"pp036",type:"error",q:"I searched the information on the internet. I found many useful website.",a:"I searched for information on the internet. I found many useful websites.",exp:"'Search FOR' (not 'search the information'). 'On the internet'. 'Websites' (plural). 'Search' can take a direct object if it's the place: 'I searched the internet FOR information'."},
        {id:"pp037",type:"fill",q:"We need to focus ___ improving student outcomes. I believe ___ the power of education.",a:"on ... in",exp:"'Focus ON' (direct attention). 'Believe IN' (have faith in). Both are high-frequency collocations in professional English."},
        {id:"pp038",type:"fill",q:"The students are divided ___ four groups. Each group is responsible ___ a different topic.",a:"into ... for",exp:"'Divided INTO' (separation). 'Responsible FOR' (accountable for). Common classroom organisation language."},
        {id:"pp039",type:"open",q:"Write three sentences using 'in', 'on', and 'at' for time expressions about a school event.",a:"The school concert will be held in November. It is on Thursday the 20th. It starts at 6:30 p.m.",exp:"'In November' (month). 'On Thursday' (day). 'At 6:30 p.m.' (time). The rule: IN = months/years/seasons, ON = days/dates, AT = specific times."},
        {id:"pp040",type:"fill",q:"She graduated ___ the University of Sydney and has been teaching ___ 2020.",a:"from ... since",exp:"'Graduate FROM' (origin). 'Since 2020' (from a point in time until now). 'Since' with present perfect: 'has been teaching since'."},
        {id:"pp041",type:"error",q:"They are different each other. One is quiet and the other is very outgoing.",a:"They are different from each other. One is quiet and the other is very outgoing.",exp:"'Different FROM each other' in Australian/British English (Americans also accept 'different than'). Chinese 互相不同 doesn't need a preposition."},
        {id:"pp042",type:"fill",q:"I apologise ___ the inconvenience. We are doing our best to deal ___ the situation.",a:"for ... with",exp:"'Apologise FOR' (reason). 'Deal WITH' (handle). Standard professional language with correct prepositions."},
        {id:"pp043",type:"mc",q:"Which is correct: 'I'm used ___ waking up early'?",options:["at","for","to","with"],a:2,exp:"'Used TO + gerund' = accustomed to. 'I'm used to the Australian weather.' Chinese speakers confuse this with 'used to + base verb' (past habit). 'Used to' after 'be' takes a gerund."},
        {id:"pp044",type:"fill",q:"She complained ___ the noise level and asked the students to be quiet. The teacher next door also complained ___ the disruption.",a:"about ... about",exp:"'Complain ABOUT' = express dissatisfaction regarding. Both sentences use 'about' for the subject of the complaint."},
        {id:"pp045",type:"error",q:"I'm looking forward to see you on the meeting next week.",a:"I'm looking forward to seeing you at the meeting next week.",exp:"'Looking forward TO + gerund' (seeing, not see). 'AT the meeting' (not 'on'). The 'to' in 'look forward to' is a preposition, so it takes a gerund."},
        {id:"pp046",type:"fill",q:"He was absent ___ school ___ three days ___ a row.",a:"from ... for ... in",exp:"'Absent FROM' (away). 'FOR three days' (duration). 'In a row' (consecutive). Each preposition has a distinct function."},
        {id:"pp047",type:"fill",q:"I'll meet you ___ the car park ___ five. We'll go ___ car.",a:"in ... at ... by",exp:"'In the car park' (enclosed area). 'At five' (time). 'By car' (mode of transport — no article). Transport: by car, by bus, by train (no article)."},
        {id:"pp048",type:"mc",q:"'They prevented him ___ leaving early.' Which preposition?",options:["to","from","for","of"],a:1,exp:"'Prevent FROM + gerund'. Chinese 阻止 doesn't require 'from'. Similar pattern: 'stop from', 'keep from', 'prohibit from'."},
        {id:"pp049",type:"error",q:"I am satisfy with my result. I am very proud about my students.",a:"I am satisfied with my results. I am very proud of my students.",exp:"'Satisfied WITH'. 'Proud OF'. These adjective + preposition patterns must be memorised. Chinese 对...满意 and 为...骄傲 use different structures."},
        {id:"pp050",type:"fill",q:"The school is located ___ the corner of Victoria Road and Church Street, ___ a short walk ___ the station.",a:"on ... within ... from",exp:"'On the corner' (intersection). 'Within a short walk' (distance). 'From the station' (starting point). Location prepositions require precision."}
      ]
    },
    {
      id: "tense-consistency",
      title: "Tense Consistency & Time Markers",
      theory: "Chinese does not conjugate verbs for tense. Tense is indicated by context words (了 le, 过 guò, 会 huì). English requires consistent verb forms. The most common errors are: using present tense for past events, mixing tenses within a paragraph, and struggling with present perfect.",
      exercises: [
        {id:"tc001",type:"fill",q:"Yesterday, I ___ a great lesson on circuits. The students ___ really engaged.",a:"taught ... were",exp:"'Yesterday' demands past simple: 'taught', 'were'. Chinese speakers often use present tense because 昨天我教 doesn't change the verb form."},
        {id:"tc002",type:"error",q:"Last week we have a meeting about the new curriculum. The principal say we need to make changes.",a:"Last week we had a meeting about the new curriculum. The principal said we need to make changes.",exp:"'Last week' = past simple required: 'had', 'said'. Chinese speakers often use 'have' and 'say' for all time contexts because Mandarin doesn't conjugate."},
        {id:"tc003",type:"fill",q:"I ___ at this school for two years. Before that, I ___ in China.",a:"have been ... lived",exp:"'Have been' (present perfect — started in past, continues to now). 'Lived' (past simple — completed action). The present perfect is the hardest tense for Chinese speakers."},
        {id:"tc004",type:"mc",q:"Which sentence correctly uses present perfect?",options:["I have went to the meeting yesterday.","I have been to Japan three times.","I have finish the report last week.","I have ate lunch already."],a:1,exp:"Present perfect: 'have been to Japan three times' (no specific time mentioned). Present perfect CANNOT be used with past time markers like 'yesterday' or 'last week'. Past participle: 'been', 'finished', 'eaten'."},
        {id:"tc005",type:"fill",q:"She ___ teaching for 15 years and still ___ every day.",a:"has been ... loves",exp:"'Has been teaching for 15 years' (present perfect continuous — ongoing). 'Still loves' (present simple — current state). Duration + continuing state."},
        {id:"tc006",type:"error",q:"When I arrive at school this morning, the meeting already start.",a:"When I arrived at school this morning, the meeting had already started.",exp:"'Arrived' (past simple — the later event). 'Had already started' (past perfect — the earlier event). Past perfect shows which event happened FIRST. Chinese uses 已经 without verb changes."},
        {id:"tc007",type:"fill",q:"By next Friday, we ___ ___ all the assessments and the results ___ ready for parents.",a:"will have ... marked ... will be",exp:"'Will have marked' (future perfect — completed by a future point). 'Will be ready' (future simple — state at that time). Future time expressions need future tenses."},
        {id:"tc008",type:"mc",q:"'I ___ here since 2023.' Which verb form is correct?",options:["am working","work","have been working","was working"],a:2,exp:"'Since 2023' requires present perfect continuous: 'have been working' (started in 2023, still working now). 'Since' + point in time always triggers present perfect."},
        {id:"tc009",type:"fill",q:"While I ___ explaining the task, a student ___ a question about the deadline.",a:"was ... asked",exp:"'While I was explaining' (past continuous — background action). 'Asked' (past simple — interrupting action). This is the classic past continuous + past simple pattern."},
        {id:"tc010",type:"error",q:"I am teaching at this school since last year. Before I come here, I am working at a school in China.",a:"I have been teaching at this school since last year. Before I came here, I was working at a school in China.",exp:"'Since' requires present perfect ('have been teaching'). 'Before I came' (past simple). 'I was working' (past continuous for ongoing past action). Three tense corrections."},
        {id:"tc011",type:"fill",q:"The students ___ their projects last week. They ___ very proud of what they ___ achieved.",a:"finished ... were ... had",exp:"'Finished' (past simple — completed). 'Were' (past simple — feeling at that time). 'Had achieved' (past perfect — achievement before the feeling)."},
        {id:"tc012",type:"mc",q:"When do you use 'used to'?",options:["For something you do now","For a past habit or state that is no longer true","For something you will do in the future","For something happening right now"],a:1,exp:"'I used to live in China' = I lived there before, but I don't now. 'Used to' has no Chinese equivalent — Chinese uses 以前 (before) with present tense verbs."},
        {id:"tc013",type:"fill",q:"Right now, the students ___ on their projects. They ___ been working on them for three ___.",a:"are working ... have ... weeks",exp:"'Are working' (present continuous — happening now). 'Have been working for three weeks' (present perfect continuous — duration up to now)."},
        {id:"tc014",type:"error",q:"Tomorrow we will have a excursion. The bus will arrived at 8:30. Students should to bring their own lunch.",a:"Tomorrow we will have an excursion. The bus will arrive at 8:30. Students should bring their own lunch.",exp:"'An excursion' (vowel sound). 'Will arrive' (base form after 'will'). 'Should bring' (base form after modal). Multiple errors in one paragraph."},
        {id:"tc015",type:"fill",q:"By the time the bell ___, most students ___ already ___ their work.",a:"rang ... had ... submitted",exp:"'By the time + past simple' triggers 'had + past participle' (past perfect) in the main clause. The bell ringing was the later event."},
        {id:"tc016",type:"fill",q:"I ___ this approach in my Year 8 class next week and will report back on how it ___.",a:"will trial ... goes",exp:"'Will trial' (future — planned action). 'How it goes' (present simple for future events in time clauses). Don't use 'will' in both clauses."},
        {id:"tc017",type:"error",q:"She has been work here for five years. She work very hard and always help other teachers.",a:"She has been working here for five years. She works very hard and always helps other teachers.",exp:"'Has been working' (present perfect continuous). 'Works' and 'helps' (third person singular 's'). Chinese verbs don't conjugate for person or tense."},
        {id:"tc018",type:"mc",q:"Which sentence is correct?",options:["I have visited Sydney last month.","I visited Sydney last month.","I visit Sydney last month.","I was visiting Sydney last month."],a:1,exp:"'Last month' = specific past time = past simple 'visited'. Present perfect ('have visited') cannot be used with specific past time markers. This is a fundamental rule."},
        {id:"tc019",type:"fill",q:"If the weather ___ good tomorrow, we ___ the lesson outside.",a:"is ... will have",exp:"First conditional: 'If + present simple, will + base verb'. Do NOT use 'will' in the if-clause. Chinese speakers often say 'If the weather will be good'."},
        {id:"tc020",type:"error",q:"I am teach here for two year. Next year I will change to a different school maybe.",a:"I have been teaching here for two years. Next year I might move to a different school.",exp:"'Have been teaching for two years' (present perfect with 'for'). 'Might move' (possibility, softer than 'will change maybe'). 'Move to' not 'change to' a school."},
        {id:"tc021",type:"fill",q:"When she ___ the room, everyone ___ quietly. Nobody ___ a word.",a:"entered ... was working ... said",exp:"Narrative past: 'entered', 'was working' (background), 'said' (event). Past simple and past continuous work together in narratives."},
        {id:"tc022",type:"open",q:"Rewrite this paragraph with correct tenses: 'Yesterday I go to the staff meeting. The principal talk about the new policy. She say we need to change our assessment approach. I think it is a good idea so I agree with her.'",a:"Yesterday I went to the staff meeting. The principal talked about the new policy. She said we need to change our assessment approach. I thought it was a good idea so I agreed with her.",exp:"All past simple because the events are completed: went, talked, said, thought, agreed. 'She said we need to change' — the reported content can stay in present if it is still true."},
        {id:"tc023",type:"fill",q:"The school ___ in 1896. It ___ serving the local community for over 125 years.",a:"was founded ... has been",exp:"'Was founded' (past simple — specific point in time). 'Has been serving' (present perfect continuous — started in past, continues now)."},
        {id:"tc024",type:"mc",q:"'While I ___ the report, the phone rang.'",options:["write","was writing","have written","am writing"],a:1,exp:"'While' + past continuous (background action) + past simple (interrupting action). This is one of the most common English tense patterns for narrating past events."},
        {id:"tc025",type:"fill",q:"I wish I ___ more confident in meetings. If I ___ better English, I would contribute more.",a:"were ... had",exp:"Second conditional (hypothetical): 'wish + past simple', 'If + past simple, would + base'. 'Were' (not 'was') is preferred in formal English after 'wish' and 'if'."},
        {id:"tc026",type:"error",q:"She doesn't came to school today because she is sick. Her mother call the office this morning.",a:"She didn't come to school today because she is sick. Her mother called the office this morning.",exp:"'Didn't come' (past simple negative). 'Is sick' (present — she's still sick). 'Called' (past simple — completed action). Mixed tenses are valid when the time references change."},
        {id:"tc027",type:"fill",q:"By this time next year, I ___ ___ my probationary period and ___ a fully accredited teacher.",a:"will have ... completed ... become",exp:"'Will have completed' (future perfect — before a future point). 'Become' (future simple after 'will have... and'). Future milestones."},
        {id:"tc028",type:"fill",q:"The lesson ___ very well. I was particularly pleased with how the students ___ to the group activity.",a:"went ... responded",exp:"Both past simple for completed lesson evaluation. 'Went well' and 'responded to' are standard lesson reflection language."},
        {id:"tc029",type:"mc",q:"'I ___ here for three years when I finally got promoted.'",options:["worked","have worked","had been working","am working"],a:2,exp:"Past perfect continuous: 'had been working for three years' describes duration UP TO another past event (getting promoted). Two past events: the longer one uses past perfect continuous."},
        {id:"tc030",type:"error",q:"Next week the students will presented their projects. They already finish preparing.",a:"Next week the students will present their projects. They have already finished preparing.",exp:"'Will present' (future simple — base form after will). 'Have already finished' (present perfect — completed but relevant now). Chinese uses 了 for both 'already' contexts."},
        {id:"tc031",type:"fill",q:"She told me she ___ coming to the meeting, but she ___ change her mind later.",a:"was ... might",exp:"'Was coming' (reported speech — 'I'm coming' becomes 'she was coming'). 'Might change' (possibility). Reported speech tense shifts are challenging."},
        {id:"tc032",type:"fill",q:"I've never ___ such a motivated class. They ___ to surprise me every lesson.",a:"had ... continue",exp:"'Never had' (present perfect — life experience). 'Continue to surprise' (present simple — ongoing pattern). The mix works because the second part is current."},
        {id:"tc033",type:"error",q:"After I graduate from university, I start teaching. I teach for one year before I come to Australia.",a:"After I graduated from university, I started teaching. I taught for one year before I came to Australia.",exp:"Completed past sequence: 'graduated', 'started', 'taught', 'came'. All past simple for a sequential narrative. Chinese speakers default to present tense for stories."},
        {id:"tc034",type:"fill",q:"If I ___ known about the policy change earlier, I ___ ___ my lesson plan differently.",a:"had ... would have ... prepared",exp:"Third conditional (past hypothetical): 'If + past perfect, would have + past participle'. For unrealised past possibilities. 'If I had known... I would have prepared...'"},
        {id:"tc035",type:"mc",q:"Which time marker triggers present perfect?",options:["Yesterday","Last week","Since 2023","Three days ago"],a:2,exp:"'Since + point in time' triggers present perfect. 'Yesterday', 'last week', 'ago' trigger past simple. This is the key distinction."},
        {id:"tc036",type:"fill",q:"The students ___ really hard all term. I'm confident they ___ well in the upcoming exam.",a:"have worked ... will do",exp:"'Have worked' (present perfect — result matters now). 'Will do well' (future prediction based on evidence). Linking past effort to future expectation."},
        {id:"tc037",type:"error",q:"I am living in Sydney since two years. I very like this city.",a:"I have been living in Sydney for two years. I really like this city.",exp:"'Have been living' with 'for two years' (duration). 'For' not 'since' with durations. 'Really like' not 'very like' — 'very' doesn't modify verbs."},
        {id:"tc038",type:"fill",q:"When I first ___ at the school, I ___ nervous, but now I ___ much more confident.",a:"arrived ... was ... feel",exp:"Three time frames: past simple (first arrival), past simple (feeling then), present simple (feeling now). Tense shift follows the time shift."},
        {id:"tc039",type:"open",q:"Write a paragraph about your career journey using at least three different tenses correctly.",a:"I grew up in China and studied Geography at university. After graduating, I worked as a researcher for several years. In 2024, I moved to Australia to pursue a career in teaching. Since then, I have been working at Arthur Phillip High School as a Technology teacher. Currently, I am completing my teaching qualifications through Southern Cross University. By next year, I will have achieved full accreditation and will be looking for new ways to grow professionally.",exp:"Past simple (grew up, studied, worked, moved), present perfect continuous (have been working), present continuous (am completing), future perfect (will have achieved). Each tense has a clear purpose."},
        {id:"tc040",type:"fill",q:"The government ___ announced that the curriculum ___ change next year. Schools ___ been given until December to prepare.",a:"has ... will ... have",exp:"'Has announced' (recent completed action). 'Will change' (future). 'Have been given' (present perfect passive). Three tenses in one news update."}
      ]
    },    {
      id: "word-order-chinglish",
      title: "Word Order & Chinglish Patterns",
      theory: "Chinese word order differs from English in several systematic ways. Common Chinglish patterns include topic-comment structure, double subjects, and adjective/adverb placement. Chinese is a topic-prominent language (topic first, comment second), while English is subject-prominent (subject-verb-object). This leads to structures like 'This book I already read' instead of 'I have already read this book'.",
      exercises: [
        {id:"wo001",type:"error",q:"This problem I already think about it for a long time.",a:"I have already thought about this problem for a long time.",exp:"Chinese topic-comment structure: 这个问题我已经想了很久了. English requires SVO order: subject (I) + verb (have thought) + object (this problem). The topic cannot come first."},
        {id:"wo002",type:"fill",q:"She speaks English ___. (fluently / fluent)",a:"fluently",exp:"Adverbs of manner come AFTER the verb: 'speaks English fluently'. Chinese places adverbs BEFORE the verb: 她流利地说英语. This is a fundamental word order difference."},
        {id:"wo003",type:"error",q:"Tomorrow if rains, we will cancel the excursion.",a:"If it rains tomorrow, we will cancel the excursion.",exp:"English needs a subject pronoun 'it' for weather (Chinese doesn't: 明天如果下雨). Time/condition clauses can go first or second, but 'tomorrow' is better inside the clause."},
        {id:"wo004",type:"mc",q:"Which sentence has correct English word order?",options:["Very much I like this school.","I like this school very much.","This school I very much like.","Like very much I this school."],a:1,exp:"English: Subject + Verb + Object + Adverb. 'I like this school very much.' Chinese allows the adverb before the verb and the object at the start, but English does not."},
        {id:"wo005",type:"fill",q:"Although she is tired, she ___ continues to work hard. (still / yet)",a:"still",exp:"'Still' goes before the main verb or after 'be': 'she still continues'. Chinese 虽然...但是 structure doesn't change — English 'although' doesn't need 'but'. Using both is a common Chinglish error."},
        {id:"wo006",type:"error",q:"Although he is young, but he is very responsible.",a:"Although he is young, he is very responsible.",exp:"Classic Chinglish: using both 'although' and 'but'. Chinese 虽然...但是 requires both, but English uses ONLY ONE: 'Although X, Y' OR 'X, but Y'. Never both together."},
        {id:"wo007",type:"fill",q:"He ___ only arrived five minutes ago. (has / have)",a:"has",exp:"Third person singular 'has'. 'Only' placement: 'He has only arrived' or 'He only arrived'. Chinese speakers sometimes put 'only' in odd positions."},
        {id:"wo008",type:"error",q:"Because the weather is bad, so we stay inside.",a:"Because the weather is bad, we stay inside.",exp:"Same pattern as 'although/but': Chinese 因为...所以 requires both connectors, but English uses only ONE: 'Because X, Y' OR 'X, so Y'. Never both."},
        {id:"wo009",type:"mc",q:"Which adverb placement is correct?",options:["I always am happy to help.","Always I am happy to help.","I am always happy to help.","I am happy always to help."],a:2,exp:"Frequency adverbs (always, usually, never) go AFTER 'be' but BEFORE other verbs: 'I am always happy' but 'I always help'. Chinese places 总是 before the verb regardless."},
        {id:"wo010",type:"error",q:"My English level is not good enough. My Chinese is much better than English.",a:"My English is not good enough. My Chinese is much better than my English.",exp:"Missing possessive 'my' before the second 'English'. Chinese 我的中文比英文好 omits the second possessive naturally, but English requires it."},
        {id:"wo011",type:"fill",q:"I ___ at home yesterday because I was sick. (stayed / stay)",a:"stayed",exp:"Past tense 'stayed'. The time marker 'yesterday' requires past simple. 'Stay' would be present tense. Chinese verbs don't change form."},
        {id:"wo012",type:"error",q:"He very likes music. Especially he likes classical music.",a:"He really likes music. He especially likes classical music.",exp:"'Very' cannot modify verbs — use 'really'. 'Especially' goes after the subject, not at the start: 'He especially likes'. Chinese 他很喜欢音乐 and 特别是 have different positions."},
        {id:"wo013",type:"fill",q:"The teacher asked the students ___ they had finished. (whether / weather)",a:"whether",exp:"'Whether' introduces an indirect question. 'Weather' = climate. Common homophones. Indirect questions don't invert: 'asked whether they had' (not 'had they')."},
        {id:"wo014",type:"mc",q:"Which question formation is correct?",options:["Why you are late today?","Why are you late today?","Why today are you late?","Are you why late today?"],a:1,exp:"English question word order: Question word + auxiliary + subject + main verb. 'Why are you late?' Chinese: 你今天为什么迟到 has the question word in a different position."},
        {id:"wo015",type:"error",q:"I don't know what should I do about this situation.",a:"I don't know what I should do about this situation.",exp:"Embedded/indirect questions use STATEMENT word order: 'what I should do' (not 'what should I do'). Direct question: 'What should I do?' Embedded: 'I don't know what I should do.'"},
        {id:"wo016",type:"fill",q:"She not only teaches Technology ___ also coaches the school basketball team.",a:"but",exp:"'Not only... but also...' is a correlative conjunction pair. Chinese 不仅...而且 has a similar structure, but the word order in the clause can differ."},
        {id:"wo017",type:"error",q:"You can tell me what is the problem? I want to help you.",a:"Can you tell me what the problem is? I want to help you.",exp:"Two errors: the first sentence is a question (needs 'Can you...?'). The embedded question uses statement order: 'what the problem is' (not 'what is the problem')."},
        {id:"wo018",type:"fill",q:"The more you practise, the ___ your English will become.",a:"better",exp:"'The more X, the more Y' is a comparative structure. Chinese 越...越... has a similar parallel structure. 'The more... the better' is a very common pattern."},
        {id:"wo019",type:"error",q:"She asked me where do I live and what is my phone number.",a:"She asked me where I live and what my phone number is.",exp:"Reported questions: statement word order. 'Where I live' (not 'where do I live'). 'What my phone number is' (not 'what is my number'). Chinese indirect questions keep the same word order as direct ones."},
        {id:"wo020",type:"mc",q:"Which is correct?",options:["He gave to me a book.","He gave a book to me.","He gave me a book.","Both B and C are correct."],a:3,exp:"Both 'gave a book to me' and 'gave me a book' are correct. The double object construction (gave me a book) is more common. 'Gave to me a book' is incorrect word order."},
        {id:"wo021",type:"error",q:"I have many homework today. Tonight I will do all of them.",a:"I have a lot of homework today. Tonight I will do all of it.",exp:"'Homework' is uncountable — 'a lot of homework' (not 'many'). 'All of it' (not 'them' — uncountable takes singular pronoun). Chinese 很多作业 treats it as countable."},
        {id:"wo022",type:"fill",q:"I wonder ___ she will come to the meeting tomorrow.",a:"whether",exp:"'I wonder whether/if' introduces an indirect question. Statement order follows: 'whether she will come'. Chinese speakers sometimes invert: 'whether will she come'."},
        {id:"wo023",type:"error",q:"The reason why I came late is because the traffic was very bad.",a:"The reason I was late is that the traffic was heavy.",exp:"'The reason is that...' (not 'the reason is because' — redundant). 'Heavy traffic' (not 'bad traffic' — collocation). 'Was late' (not 'came late' in this structure)."},
        {id:"wo024",type:"open",q:"Rewrite these Chinglish sentences in natural English: 'This movie I already watched. Very boring. The ending not good.'",a:"I have already watched this movie. It was really boring. The ending was not very good.",exp:"SVO word order: 'I have watched this movie' (not topic-first). Add 'It was' (English needs a subject). 'The ending was' (needs a verb — Chinese can omit it)."},
        {id:"wo025",type:"fill",q:"Could you tell me ___ the deadline is? I want to make sure I submit on time.",a:"when",exp:"Indirect question: 'tell me when the deadline is' (statement order). Not 'when is the deadline' in the embedded clause."},
        {id:"wo026",type:"error",q:"My home is very far from school. Every day I need spend one hour on the road.",a:"My home is very far from school. Every day I need to spend an hour commuting.",exp:"'Need to spend' (infinitive after 'need'). 'An hour' (not 'one hour' — more natural). 'Commuting' (not 'on the road' which implies driving)."},
        {id:"wo027",type:"mc",q:"Which placement of 'enough' is correct?",options:["She is enough old to drive.","She is old enough to drive.","Enough she is old to drive.","She is old to drive enough."],a:1,exp:"'Enough' goes AFTER adjectives ('old enough') but BEFORE nouns ('enough time'). Chinese 足够大 puts the intensifier before the adjective, causing this error."},
        {id:"wo028",type:"error",q:"He suggested me to go home early because the weather is bad.",a:"He suggested that I go home early because the weather was bad.",exp:"'Suggest that + subject + base verb' (subjunctive). NOT 'suggest me to go' — Chinese 建议我去 translates directly to this error. 'Suggest' never takes 'object + infinitive'."},
        {id:"wo029",type:"fill",q:"Not only does she teach well, ___ she also inspires her students to think critically.",a:"but",exp:"'Not only does she teach well, but she also inspires...' When 'not only' starts a sentence, the first clause inverts (does she teach) but the second doesn't."},
        {id:"wo030",type:"error",q:"I hope you can give me some suggest about how to improve my lesson.",a:"I hope you can give me some suggestions about how to improve my lessons.",exp:"'Suggestions' (noun plural, not verb 'suggest'). 'Lessons' (plural — you teach many). Chinese 建议 is both noun and verb, causing this confusion."},
        {id:"wo031",type:"fill",q:"Do you know ___ time the meeting starts? I don't want to be late.",a:"what",exp:"'What time' in an indirect question: 'Do you know what time the meeting starts?' Statement order after 'know'."},
        {id:"wo032",type:"error",q:"My opinion is I think we should change the policy.",a:"In my opinion, we should change the policy.",exp:"'My opinion is I think' is redundant — both mean the same thing. Choose one: 'In my opinion' OR 'I think'. Chinese 我的看法是我认为 doubles up naturally."},
        {id:"wo033",type:"mc",q:"Where does 'also' go in the sentence 'She ___ speaks French'?",options:["She also speaks French.","She speaks also French.","Also she speaks French.","She speaks French also."],a:0,exp:"'Also' goes before the main verb (or after 'be'): 'She also speaks French.' Starting with 'Also' is acceptable in writing but less natural in speech."},
        {id:"wo034",type:"fill",q:"I am not sure ___ to do next. Could you give me some guidance?",a:"what",exp:"'What to do next' — question word + infinitive. This structure is common after 'know', 'sure', 'decide', 'wonder'."},
        {id:"wo035",type:"error",q:"Because of I was sick, so I didn't come to school yesterday.",a:"Because I was sick, I didn't come to school yesterday.",exp:"'Because of' takes a noun ('because of my illness'), while 'because' takes a clause ('because I was sick'). And again: no 'so' with 'because'."},
        {id:"wo036",type:"open",q:"Fix the word order in: 'Can you tell me where is the staffroom? I don't know how can I get there.'",a:"Can you tell me where the staffroom is? I don't know how I can get there.",exp:"Both embedded questions need statement word order: 'where the staffroom is' and 'how I can get there'. This is one of the most persistent errors for Chinese speakers."},
        {id:"wo037",type:"fill",q:"She works ___ hard ___ she often stays at school until 6 p.m.",a:"so ... that",exp:"'So + adjective/adverb + that...' = result clause. Chinese 她工作太努力以至于 has a similar structure but the word order within clauses differs."},
        {id:"wo038",type:"error",q:"Even though is raining, the students still want go outside.",a:"Even though it is raining, the students still want to go outside.",exp:"'It is raining' (dummy subject 'it' needed). 'Want to go' (infinitive after 'want'). Both errors common for Chinese speakers."},
        {id:"wo039",type:"mc",q:"Which is correct?",options:["I don't know what means 'scaffolding'.","I don't know what 'scaffolding' means.","I don't know what is meaning 'scaffolding'.","I don't know what does 'scaffolding' mean."],a:1,exp:"Embedded question: 'what scaffolding means' (statement order). Not 'what means scaffolding' (Chinese question pattern 什么意思) or 'what does scaffolding mean' (direct question form)."},
        {id:"wo040",type:"error",q:"Her performance this semester compare with last semester has improved a lot.",a:"Her performance this semester has improved a lot compared with last semester.",exp:"'Compared with' is a participial phrase that goes after the main clause or with 'be'. Chinese 她这学期的表现与上学期相比进步了很多 puts the comparison in the middle."}
      ]
    },
    {
      id: "countable-uncountable",
      title: "Countable vs Uncountable Nouns",
      theory: "Chinese nouns do not distinguish countable from uncountable. Common errors: 'informations', 'homeworks', 'furnitures', 'advices', 'equipments'. English has strict rules: uncountable nouns take no plural 's', no 'a/an', and use 'much/some/a lot of' instead of 'many'.",
      exercises: [
        {id:"cu001",type:"error",q:"Can you give me some informations about the new policy? I need advices on how to implement it.",a:"Can you give me some information about the new policy? I need advice on how to implement it.",exp:"'Information' and 'advice' are ALWAYS uncountable in English. Never add 's'. Chinese 信息/建议 can be counted. This is one of the top 3 Chinese speaker errors."},
        {id:"cu002",type:"fill",q:"I have too much ___ tonight. The students handed in twenty ___ of work.",a:"homework ... pieces",exp:"'Homework' is uncountable (no 'homeworks'). To count it, use 'pieces of homework'. Chinese 作业 is countable."},
        {id:"cu003",type:"mc",q:"Which is correct?",options:["I bought many furnitures for my new house.","I bought a lot of furniture for my new house.","I bought three furnitures.","The furniture are expensive."],a:1,exp:"'Furniture' is uncountable. 'A lot of furniture' (not 'many furnitures'). 'The furniture IS expensive' (singular verb). Chinese 家具 is countable, causing this error."},
        {id:"cu004",type:"fill",q:"We don't have enough ___ for this experiment. Could you order some more ___?",a:"equipment ... supplies",exp:"'Equipment' is uncountable (no 'equipments'). 'Supplies' IS countable (can be plural). Knowing which nouns are countable is essential."},
        {id:"cu005",type:"error",q:"She gave us many useful advices. I wrote them all down.",a:"She gave us a lot of useful advice. I wrote it all down.",exp:"'Advice' is uncountable: 'a lot of advice' (not 'many advices'). Pronoun: 'it' (not 'them' — uncountable is singular). Two connected errors."},
        {id:"cu006",type:"fill",q:"How much ___ do you need? I can lend you some if you're short.",a:"money",exp:"'Money' is uncountable. 'How much money' (not 'how many moneys'). Chinese 钱 doesn't distinguish countable/uncountable."},
        {id:"cu007",type:"mc",q:"Which noun IS countable?",options:["luggage","research","suggestion","traffic"],a:2,exp:"'Suggestion' is countable: 'a suggestion', 'several suggestions'. The others are all uncountable: 'some luggage', 'some research', 'heavy traffic'. No 'luggages', 'researches', or 'traffics'."},
        {id:"cu008",type:"error",q:"The traffics on the road were terrible. There were many car and the travel time was very long.",a:"The traffic on the road was terrible. There were many cars and the travel time was very long.",exp:"'Traffic' is uncountable ('was', not 'were'). 'Cars' is countable (needs plural 's'). 'Travel' as a noun is often uncountable too."},
        {id:"cu009",type:"fill",q:"She did a lot of ___ before writing the report. The ___ took her three days.",a:"research ... research",exp:"'Research' is uncountable in both uses. 'A lot of research'. You can say 'research studies' if you need to count them."},
        {id:"cu010",type:"mc",q:"'I need ___ for the classroom.' Which is correct?",options:["a new equipment","new equipments","some new equipment","many new equipment"],a:2,exp:"'Equipment' is uncountable: 'some new equipment'. Not 'a new equipment' (no article) or 'new equipments' (no plural). Use 'pieces of equipment' to count."},
        {id:"cu011",type:"error",q:"He has many experiences in teaching. His knowledge are very impressive.",a:"He has a lot of experience in teaching. His knowledge is very impressive.",exp:"'Experience' (uncountable when meaning expertise). Note: 'an experience' (countable) means a specific event. 'Knowledge IS' (uncountable, singular verb)."},
        {id:"cu012",type:"fill",q:"There is too much ___ in this room. We need to remove some ___ before the event.",a:"noise ... chairs",exp:"'Noise' is uncountable (too much noise). 'Chairs' is countable (some chairs). The difference determines quantifier choice."},
        {id:"cu013",type:"error",q:"I need to buy some breads and milks from the shop.",a:"I need to buy some bread and milk from the shop.",exp:"'Bread' and 'milk' are uncountable. 'Some bread' and 'some milk'. To count: 'two loaves of bread', 'two bottles/glasses of milk'."},
        {id:"cu014",type:"fill",q:"The school has made great ___ this year. The ___ speak for themselves.",a:"progress ... results",exp:"'Progress' is uncountable (great progress, not 'progresses'). 'Results' IS countable and can be plural."},
        {id:"cu015",type:"mc",q:"Which is the correct way to count 'luggage'?",options:["Two luggages","Two pieces of luggage","Two luggage","A couple of luggages"],a:1,exp:"'Pieces of luggage' is the counting structure for uncountable nouns. 'Items of clothing', 'pieces of advice', 'slices of bread'. This is the universal pattern."},
        {id:"cu016",type:"error",q:"She has a good news to share with us. The weather forecast also predicts a nice weather.",a:"She has good news to share with us. The weather forecast also predicts nice weather.",exp:"'News' and 'weather' are both uncountable. No 'a' before either. 'News' looks plural but is always singular: 'The news IS good.'"},
        {id:"cu017",type:"fill",q:"Could you give me a ___ of paper? I also need a ___ of tape.",a:"piece ... roll",exp:"Counting uncountable nouns: 'a piece of paper' (or 'sheet'), 'a roll of tape'. Learning common counting expressions is essential."},
        {id:"cu018",type:"error",q:"We need more staffs in the department. Can we hire two more peoples?",a:"We need more staff in the department. Can we hire two more people?",exp:"'Staff' is a collective noun (uncountable as a group — 'more staff'). 'People' is already plural (never 'peoples' unless referring to ethnic groups). Chinese 人们/员工们 adds plurals."},
        {id:"cu019",type:"fill",q:"How ___ students are in your class? I have too ___ work to mark this weekend.",a:"many ... much",exp:"'How many + countable plural' (students). 'Too much + uncountable' (work). The many/much distinction maps to countable/uncountable."},
        {id:"cu020",type:"mc",q:"Which word can be BOTH countable and uncountable with different meanings?",options:["furniture","information","paper","luggage"],a:2,exp:"'Paper' uncountable = material ('I need some paper'). 'Paper' countable = document ('I wrote three papers'). Some English nouns change meaning based on countability."},
        {id:"cu021",type:"error",q:"I have bought new softwares for the computer lab. The technology team will help with installation.",a:"I have bought new software for the computer lab. The technology team will help with the installation.",exp:"'Software' is uncountable (never 'softwares'). To count: 'two software programs/packages'. Chinese 软件 is countable."},
        {id:"cu022",type:"fill",q:"There was a lot of ___ about the decision. Many ___ were raised by staff.",a:"discussion ... concerns",exp:"'Discussion' (uncountable in this general sense). 'Concerns' (countable — specific worries). Both describe the same meeting but use different grammar."},
        {id:"cu023",type:"error",q:"The school has made a lot of improvements to its infrastructure. New furnitures and equipments have been ordered.",a:"The school has made a lot of improvements to its infrastructure. New furniture and equipment have been ordered.",exp:"'Furniture' and 'equipment' — both always uncountable. 'Improvements' IS countable. Three nouns in one passage — knowing which is countable matters."},
        {id:"cu024",type:"fill",q:"She received a lot of ___ on her assessment task. All the ___ was positive.",a:"feedback ... feedback",exp:"'Feedback' is uncountable. 'A lot of feedback', 'the feedback WAS'. Chinese 反馈 can be counted. To count: 'pieces of feedback' or 'several comments'."},
        {id:"cu025",type:"open",q:"Correct all countable/uncountable errors: 'I need some advices on my homeworks. Can you give me informations about the assessments? I have many works to do.'",a:"I need some advice on my homework. Can you give me some information about the assessments? I have a lot of work to do.",exp:"Advice (uncountable), homework (uncountable), information (uncountable), work (uncountable). 'Assessments' IS countable — correctly plural. The last sentence: 'a lot of work' not 'many works'."},
        {id:"cu026",type:"fill",q:"We had some trouble with ___ during the last exam. The ___ needs to be replaced.",a:"technology ... technology",exp:"'Technology' is generally uncountable in this sense. 'Some trouble with technology'. 'The technology' (specific). To count: 'technologies' (different types/fields)."},
        {id:"cu027",type:"mc",q:"'There ___ a lot of evidence to support this approach.'",options:["is","are","have","were"],a:0,exp:"'Evidence' is uncountable — always singular verb: 'There IS evidence.' Not 'evidences' or 'there are evidence'. Chinese 证据 can be counted."},
        {id:"cu028",type:"error",q:"The children need more spaces to play. Also, the school needs better transportations for excursions.",a:"The children need more space to play. Also, the school needs better transport for excursions.",exp:"'Space' (uncountable when meaning room/area). 'Transport' (uncountable in British/Australian English for general transportation). 'Spaces' can mean specific areas; 'transports' is never used."},
        {id:"cu029",type:"fill",q:"How much ___ does this project require? We also need more ___ to complete it.",a:"time ... resources",exp:"'Time' is uncountable (how much time). 'Resources' IS countable (more resources). Mixing countable and uncountable in one conversation is normal."},
        {id:"cu030",type:"fill",q:"I've done extensive ___ on this topic and collected a great deal of ___.",a:"research ... data",exp:"'Research' and 'data' are both uncountable in standard usage (though 'data' is debated — 'data is' is now accepted in Australian English)."},
        {id:"cu031",type:"error",q:"She gave me many good feedbacks on my lesson. I received several useful informations.",a:"She gave me a lot of good feedback on my lesson. I received a lot of useful information.",exp:"'Feedback' and 'information' are ALWAYS uncountable. Use 'a lot of' instead of 'many'. To count: 'several pieces of feedback', 'several pieces of information'."},
        {id:"cu032",type:"mc",q:"Which is correct: 'The ___ was helpful'?",options:["advice","advices","an advice","advise"],a:0,exp:"'The advice was helpful.' 'Advice' is uncountable. 'Advise' is the VERB. Chinese speakers confuse advice/advise because 建议 is both noun and verb."},
        {id:"cu033",type:"fill",q:"We need new ___ for the computer lab. The school has allocated ___ in the budget for this.",a:"equipment ... funds",exp:"'Equipment' (uncountable — no 'equipments'). 'Funds' IS countable (= money allocated). Knowing which financial terms are countable matters."},
        {id:"cu034",type:"fill",q:"She has a wealth of ___ in education. Her ___ of the curriculum is outstanding.",a:"experience ... knowledge",exp:"'Experience' (uncountable when meaning expertise) and 'knowledge' (uncountable). 'A wealth of' = a great amount of. Both use singular verbs."},
        {id:"cu035",type:"error",q:"I have a lot of work to do. I also need to finish marking all the student's homeworks before Friday.",a:"I have a lot of work to do. I also need to finish marking all the students' homework before Friday.",exp:"'Homework' is uncountable (no 'homeworks'). 'Students'' = plural possessive (many students). Two common errors in one sentence."}
      ]
    },
    {
      id: "verb-patterns-collocations",
      title: "Verb Patterns & Collocations",
      theory: "Many Chinese speakers use direct translations that produce unnatural English. For example, '开 (kāi) meeting' becomes 'open a meeting' instead of 'hold a meeting'. English collocations (words that naturally go together) must be learned as units. Verb patterns (verb + infinitive, verb + gerund, verb + object + infinitive) also differ between Chinese and English.",
      exercises: [
        {id:"vc001",type:"error",q:"We will open a meeting tomorrow to discuss the new policy.",a:"We will hold a meeting tomorrow to discuss the new policy.",exp:"'Hold a meeting' (not 'open'). Chinese 开会 (kāi huì) literally means 'open a meeting'. English collocations: hold/have a meeting, take/sit an exam, make a decision."},
        {id:"vc002",type:"fill",q:"She ___ a mistake in the report and had to ___ corrections.",a:"made ... make",exp:"'Make a mistake' and 'make corrections' — both use 'make'. Not 'do a mistake'. Chinese 犯错 (fàn cuò) doesn't help with the English collocation."},
        {id:"vc003",type:"mc",q:"Which collocation is correct?",options:["do a decision","take a decision","make a decision","create a decision"],a:2,exp:"'Make a decision' is the standard collocation. 'Take a decision' is also used in British English but less common. 'Do a decision' and 'create a decision' are incorrect."},
        {id:"vc004",type:"error",q:"I want to improve my English so I decided studying harder this term.",a:"I want to improve my English so I decided to study harder this term.",exp:"'Decide + to + infinitive' (not gerund). Some verbs take infinitive (decide, want, plan, hope), others take gerund (enjoy, avoid, suggest). This must be memorised."},
        {id:"vc005",type:"fill",q:"Could you ___ me a favour and ___ an eye on my class for five minutes?",a:"do ... keep",exp:"'Do me a favour' (not 'make me a favour'). 'Keep an eye on' = watch/monitor. Both are fixed collocations."},
        {id:"vc006",type:"mc",q:"Which verb pattern is correct?",options:["I enjoy to teach.","I enjoy teaching.","I enjoy teach.","I enjoy for teaching."],a:1,exp:"'Enjoy + gerund': 'enjoy teaching'. Never 'enjoy to teach'. Other gerund verbs: avoid, consider, finish, suggest, mind, practise."},
        {id:"vc007",type:"error",q:"She suggested me to change the seating plan. I agreed to do it.",a:"She suggested that I change the seating plan. I agreed to do it.",exp:"'Suggest that + subject + base verb' (subjunctive). NOT 'suggest me to change'. But 'agree TO do' is correct. Different verbs have different patterns."},
        {id:"vc008",type:"fill",q:"I ___ forward to hearing from you. Please ___ free to contact me anytime.",a:"look ... feel",exp:"'Look forward to + gerund' (hearing). 'Feel free to + infinitive' (contact). Two very common professional email phrases with different patterns."},
        {id:"vc009",type:"error",q:"He let me to use his computer. She made me to rewrite the report.",a:"He let me use his computer. She made me rewrite the report.",exp:"'Let + object + base verb' (no 'to'). 'Make + object + base verb' (no 'to'). Chinese speakers add 'to' because 让我用 feels like 'let me to use'."},
        {id:"vc010",type:"fill",q:"I ___ taking notes during the presentation so I could ___ the information with my team.",a:"kept ... share",exp:"'Kept taking' (keep + gerund = continue). 'Could share' (modal + base verb). The gerund/infinitive distinction is crucial."},
        {id:"vc011",type:"mc",q:"'The principal asked me ___ the report by Friday.'",options:["finish","to finish","finishing","for finish"],a:1,exp:"'Ask someone TO do something'. 'Ask + object + infinitive'. Also: 'tell someone to', 'want someone to', 'expect someone to'."},
        {id:"vc012",type:"error",q:"I am looking forward to see you at the conference next week.",a:"I am looking forward to seeing you at the conference next week.",exp:"'Look forward TO + gerund'. The 'to' here is a preposition (not part of the infinitive), so it takes a gerund. This is one of the most common errors at all levels."},
        {id:"vc013",type:"fill",q:"She ___ an apology to the student and promised to ___ more patient in the future.",a:"offered ... be",exp:"'Offered an apology' (not 'said sorry to' in formal contexts). 'Promised to be' (promise + infinitive). Professional language collocations."},
        {id:"vc014",type:"error",q:"Please help me to arrange the classroom. Can you assist me move these desks?",a:"Please help me arrange the classroom. Can you assist me in moving these desks?",exp:"'Help + object + base verb' (no 'to' — though both are acceptable). 'Assist + object + in + gerund'. Different verbs with similar meanings use different patterns."},
        {id:"vc015",type:"fill",q:"I need to ___ a phone call to a parent. Could you ___ a message if anyone calls for me?",a:"make ... take",exp:"'Make a phone call' (not 'do' or 'play'). 'Take a message' (not 'receive' or 'get'). Fixed collocations that must be memorised."},
        {id:"vc016",type:"mc",q:"Which collocation is correct?",options:["do homework","make homework","create homework","play homework"],a:0,exp:"'Do homework' (not 'make'). General pattern: 'do' for tasks/activities (do work, do exercise, do research). 'Make' for creating (make a cake, make a plan, make an effort)."},
        {id:"vc017",type:"error",q:"She is very concentrate on her work. The students are very interest in the topic.",a:"She is very concentrated on her work. The students are very interested in the topic.",exp:"'Concentrated' and 'interested' — past participle adjectives describe feelings/states. 'Concentrate' and 'interest' are verbs, not adjectives. Chinese 她很集中 uses the verb directly."},
        {id:"vc018",type:"fill",q:"I ___ a good impression on the interview panel. They ___ me the position on the spot.",a:"made ... offered",exp:"'Made a good impression' (not 'gave' or 'had'). 'Offered me the position' (not 'provided' or 'gave'). Job-related collocations."},
        {id:"vc019",type:"error",q:"Can you teach me how to operate this software? I want to learn using it properly.",a:"Can you teach me how to operate this software? I want to learn to use it properly.",exp:"'Learn TO do something' (infinitive for new skills). 'Learn doing' would mean 'learn by doing' (different meaning). 'Learn to use' = acquire the ability to use."},
        {id:"vc020",type:"fill",q:"The teacher ___ the students to work independently and ___ responsible for their own learning.",a:"encouraged ... be",exp:"'Encourage someone TO do something'. 'Be responsible for' — a key professional phrase. These verb + object + infinitive patterns are very common."},
        {id:"vc021",type:"mc",q:"Which is the correct collocation?",options:["take a shower","make a shower","do a shower","have a shower"],a:3,exp:"In Australian/British English: 'HAVE a shower'. Americans say 'TAKE a shower'. Also: 'have a bath', 'have a rest', 'have a go', 'have a chat'. 'Have' is extremely versatile."},
        {id:"vc022",type:"error",q:"I played piano for two hours yesterday. I also played exercise at the gym.",a:"I played the piano for two hours yesterday. I also did exercise at the gym.",exp:"'Play THE piano' (instruments need 'the'). 'Do exercise' (not 'play exercise'). Chinese 做运动 literally translates as 'do exercise', which is actually correct — the error is 'play exercise'."},
        {id:"vc023",type:"fill",q:"We need to ___ attention to student wellbeing. It's important to ___ the time to check in with each student.",a:"pay ... take",exp:"'Pay attention to' (not 'give attention'). 'Take the time to' (not 'spend the time to'). Both are high-frequency professional collocations."},
        {id:"vc024",type:"error",q:"She avoided to discuss the topic because she didn't know enough about it.",a:"She avoided discussing the topic because she didn't know enough about it.",exp:"'Avoid + gerund' (never infinitive). 'Avoid discussing' (not 'avoid to discuss'). Chinese 避免 doesn't indicate whether a gerund or infinitive follows."},
        {id:"vc025",type:"fill",q:"I ___ my best to finish the report on time, but I couldn't ___ the deadline.",a:"did ... meet",exp:"'Did my best' (not 'tried my best' — though both are acceptable). 'Meet the deadline' (not 'reach' or 'catch'). Common work collocations."},
        {id:"vc026",type:"mc",q:"Which verb takes both gerund AND infinitive with different meanings?",options:["enjoy","avoid","stop","suggest"],a:2,exp:"'Stop doing' = cease an activity. 'Stop to do' = pause in order to do something else. 'I stopped smoking' vs 'I stopped to smoke'. These dual-pattern verbs are tricky."},
        {id:"vc027",type:"error",q:"The student refused following the instructions and kept to argue with me.",a:"The student refused to follow the instructions and kept arguing with me.",exp:"'Refuse TO + infinitive'. 'Keep + gerund'. These patterns are fixed and must be memorised. Chinese doesn't distinguish between the two."},
        {id:"vc028",type:"fill",q:"She ___ me that she would be late and asked me to ___ on without her.",a:"told ... carry",exp:"'Told me that' (not 'said me'). 'Carry on' = continue. 'Say' doesn't take an indirect object — 'She said TO me' or 'She told me'."},
        {id:"vc029",type:"open",q:"Correct all collocation errors: 'We opened a meeting to do a decision about the exam. The principal told us to make our best and said she expected us to reach the deadline.'",a:"We held a meeting to make a decision about the exam. The principal told us to do our best and said she expected us to meet the deadline.",exp:"Hold a meeting (not open). Make a decision (not do). Do our best (not make). Meet the deadline (not reach). Four collocation corrections — all common Chinglish patterns."},
        {id:"vc030",type:"fill",q:"I'd like to ___ a complaint about the noise level. It's ___ it difficult to teach.",a:"make ... making",exp:"'Make a complaint' (not 'do' or 'say'). 'Making it difficult' — present continuous describing an ongoing problem. 'It' is a dummy object before the adjective."},
        {id:"vc031",type:"error",q:"She said me that the meeting was cancelled. I told that I would come tomorrow.",a:"She told me that the meeting was cancelled. I said that I would come tomorrow.",exp:"'Tell someone' (needs an object: told me). 'Say something' (no person object: said that). Chinese 说 and 告诉 are less rigid. Mixing say/tell is extremely common."},
        {id:"vc032",type:"fill",q:"Can you ___ the difference between formative and summative assessment? Let me ___ it to you.",a:"tell ... explain",exp:"'Tell the difference' = distinguish. 'Explain it to you' = make it clear. 'Tell' takes a direct object, 'explain' takes 'to + person'."},
        {id:"vc033",type:"mc",q:"Which collocation is correct?",options:["catch the bus","take the bus","ride the bus","All are acceptable"],a:3,exp:"'Catch the bus', 'take the bus', and 'ride the bus' are all used in Australian English. 'Catch' implies arriving just in time, 'take' is neutral, 'ride' focuses on the journey."},
        {id:"vc034",type:"fill",q:"The principal ___ a speech at assembly. The deputy ___ the announcements afterwards.",a:"gave ... read",exp:"'Give a speech' (not 'do a speech' or 'say a speech'). 'Read the announcements' (from a prepared list). Common school event collocations."},
        {id:"vc035",type:"error",q:"I want to rise a concern about the workload. Also I want to raise my hand to ask a question.",a:"I want to raise a concern about the workload. Also I want to raise my hand to ask a question.",exp:"'Raise a concern' (not 'rise'). 'Raise' = lift something up / bring something to attention (transitive). 'Rise' = go upward by itself (intransitive). 'The sun rises' but 'I raise my hand'."}
      ]
    }
  ]
}

};
// End of WORKPLACE_ENGLISH data